// RESOLUTION OUTPUT

.debugResolution
{
	.debugResolution-output:before
	{
		content: "Full @{xf-responsiveWide} - @{xf-pageWidthMax}";
		@media (min-width: @xf-pageWidthMax) { content: "Max > @{xf-pageWidthMax}"; }
		@media (max-width: @xf-responsiveWide) { content: "Wide < @{xf-responsiveWide}"; }
		@media (max-width: @xf-responsiveMedium) { content: "Medium < @{xf-responsiveMedium}"; }
		@media (max-width: @xf-responsiveNarrow) { content: "Narrow < @{xf-responsiveNarrow}"; }
	}
}

{{ include('nl_core.less') }}

.bbWrapper
{
	// This approach is needed to normalize browser differences that normalize.css won't handle within BB code/rich text
	// sections. You may need higher specificity to override some situations because of this.

	ol:not(.is-structureList),
	ul:not(.is-structureList)
	{
		margin-top: 1em;
		margin-bottom: 1em;
		overflow: hidden;
	}

	ol:not(.is-structureList) ol:not(.is-structureList),
	ol:not(.is-structureList) ul:not(.is-structureList),
	ul:not(.is-structureList) ol:not(.is-structureList),
	ul:not(.is-structureList) ul:not(.is-structureList)
	{
		margin-top: 0;
		margin-bottom: 0;
	}

	// note that changes to these rules will likely need to be replicated into editor.less
	h2,
	h3,
	h4
	{
		margin: .5em 0;
		clear: both;
	}

	h2 { font-size: @xf-fontSizeLargest; }
	h3 { font-size: @xf-fontSizeLarger; }
	h4 { font-size: @xf-fontSizeLarge; }

	hr
	{
		border: none;
		border-top: @xf-borderSize solid @xf-borderColorHeavy;
		clear: both;
	}

	> :first-child
	{
		margin-top: 0;
	}
}

.bbImage
{
	width: auto;
	height: auto;
	max-width: 100%;
}

.bbImageWrapper
{
	display: inline-block;
	max-width: 100%;
}

// classes to handle images being floated left and right via BB code attributes
.bbImage,
.bbImageWrapper
{
	&.bbImageAligned--left
	{
		float: left;
		margin: @xf-bbCodeImgFloatMargin @xf-bbCodeImgFloatMarginAfter @xf-bbCodeImgFloatMarginAfter 0;
	}

	&.bbImageAligned--right
	{
		float: right;
		margin: @xf-bbCodeImgFloatMargin 0 @xf-bbCodeImgFloatMarginAfter @xf-bbCodeImgFloatMarginAfter;
	}
}

.bbMediaWrapper,
.bbMediaJustifier,
.bbOembed
{
	width: 560px;
	max-width: 100%;
	margin: 0;

	&.fb_iframe_widget
	{
		display: block;
	}

	.m-blockAligner();

	&.bbImageAligned--left
	{
		float: left;
		margin: @xf-bbCodeImgFloatMargin @xf-bbCodeImgFloatMarginAfter @xf-bbCodeImgFloatMarginAfter 0;
	}

	&.bbImageAligned--right
	{
		float: right;
		margin: @xf-bbCodeImgFloatMargin 0 @xf-bbCodeImgFloatMarginAfter @xf-bbCodeImgFloatMarginAfter;
	}
}

.fb_iframe_widget
{
	> span,
	iframe
	{
		max-width: 100%;
	}
}

.bbMediaWrapper.bbMediaWrapper--inline
{
	display: inline-block;
}

.bbMediaWrapper-inner
{
	position: relative;
	padding-bottom: 56.25%; /* 16:9 ratio */
	height: 0;

	&.bbMediaWrapper-inner--4to3
	{
		padding-bottom: 75%; /* 4:3 ratio */
	}

	&.bbMediaWrapper-inner--104px
	{
		padding-bottom: 104px;
	}

	&.bbMediaWrapper-inner--110px
	{
		padding-bottom: 110px;
	}

	&.bbMediaWrapper-inner--150px
	{
		padding-bottom: 150px;
	}

	&.bbMediaWrapper-inner--500px
	{
		padding-bottom: 500px;
	}

	&.bbMediaWrapper-inner--audio
	{
		padding-bottom: 60px;

		audio
		{
			outline: none;
		}
	}

	iframe,
	object,
	embed,
	video,
	audio,
	.bbMediaWrapper-fallback
	{
		position: absolute;
		top: 0;
		left: 0;
		width: 100%;
		height: 100%;
	}
}

.bbMediaWrapper-fallback
{
	display: flex;
	justify-content: center;
	align-items: center;
	max-width: 100%;
	.xf-minorBlockContent();
}

.bbOembed
{
	&.bbOembed--loaded
	{
		display: block;
	}

	iframe,
	object,
	embed,
	video,
	audio
	{
		max-width: 100%;
	}

	.embedly-card
	{
		margin: 0;
		background: white;
	}
}

.bbTable
{
	max-width: 100%;
	overflow: auto;

	.m-tableBase();
}

.bbCodePlainUnfurl
{
	&.link
	{
		display: block;
	}
}

{{ include('nl_custom_bbcodes.less') }}

// ################################# BLOCKS ##################

.blocks
{
	margin-bottom: @xf-elementSpacer;

	&:last-child
	{
		margin-bottom: 0;
	}

	.block
	{
		margin-bottom: (@xf-elementSpacer / 2);

		&:last-child
		{
			margin-bottom: 0;
		}
	}

	&.blocks--close .block
	{
		margin-bottom: (@xf-elementSpacer / 4);
	}

	&.blocks--separated
	{
		+ .blocks
		{
			padding-top: @xf-elementSpacer;
			border-top: @xf-borderSize solid @xf-borderColor;
		}
	}
}

.blocks-header
{
	font-size: @xf-fontSizeLarger;
	font-weight: @xf-fontWeightNormal;
	color: @xf-textColorMuted;

	margin: 0;
	padding: 0;
	margin-bottom: 5px;

	&.blocks-header--strong
	{
		color: @xf-textColorDimmed;

		.blocks-desc
		{
			color: @xf-textColorMuted;
		}
	}
}

.blocks-textJoiner
{
	display: table;
	width: 100%;
	margin-bottom: (@xf-elementSpacer / 2);
	padding: 0 @xf-paddingMedium;

	> span
	{
		display: table-cell;
		position: relative;

		&:before
		{
			content: '';
			position: absolute;
			left: 0;
			right: 0;
			top: 50%;
			border-top: @xf-borderSize solid @xf-borderColor;
		}
	}

	> em
	{
		display: table-cell;
		padding: 0 @xf-paddingLarge;
		width: 1%;
		white-space: nowrap;
		font-size: @xf-fontSizeLargest;
		line-height: 1;
		font-style: normal;
		text-align: center;
	}
}

.block
{
	margin-bottom: @xf-elementSpacer;
	.xf-nlBlockWrapper();

	&.block--close
	{
		margin-bottom: 5px;
	}

	&.block--treeEntryChooser
	{
		.block-header
		{
			font-size: @xf-fontSizeLarge;

			.block-desc
			{
				font-size: @xf-fontSizeSmallest;
			}
		}

		.block-row
		{
			padding-top: 6px;
			padding-bottom: 6px;
		}

		.contentRow
		{
			&.is-disabled
			{
				opacity: 0.5;
			}
		}

		.contentRow-title
		{
			font-size: @xf-fontSizeNormal;
		}

		.contentRow-minor
		{
			font-size: @xf-fontSizeSmaller;
		}

		.contentRow-suffix
		{
			font-size: @xf-fontSizeSmall;
		}
	}
}

.block-outer
{
	padding-bottom: @xf-blockPaddingV;
	.m-clearFix();

	&:empty
	{
		display: none;
	}

	&.block-outer--after
	{
		padding-top: @xf-blockPaddingV;
		padding-bottom: 0;
	}

	&.block-outer--padded
	{
		padding-left: @xf-blockPaddingH;
		padding-right: @xf-blockPaddingH;
	}

	.block-outer-hint
	{
		font-size: @xf-fontSizeSmall;
		color: @xf-textColorMuted;
	}
}
.block-outer-main, .block-row-main { float: left; }
.block-outer-opposite, .block-row-opposite { float: right; }
.block-outer-middle, .block-row-middle { text-align: center; }

.block-container
{
	.xf-contentBase();
	.xf-blockBorder();
	border-radius: @xf-blockBorderRadius;

	&.block-container--none
	{
		background: none;
		border: none;
		color: @xf-textColor;
		padding: 0;
	}
}

@media (min-width: @xf-responsiveEdgeSpacerRemoval)
{
	@{block-noStripSel} > :first-child,
	.block-topRadiusContent,
	@{block-noStripSel} > .block-body:first-child > .blockLink:first-child
	{
		border-top-left-radius: @block-borderRadius-inner;
		border-top-right-radius: @block-borderRadius-inner;
	}

	@{block-noStripSel} > :last-child,
	.block-bottomRadiusContent,
	@{block-noStripSel} > .block-body:last-child > .blockLink:last-child,
	@{block-noStripSel} > .tabPanes:last-child > [role=tabpanel] > :last-child,
	@{block-noStripSel} > .tabPanes:last-child > [role=tabpanel] > .block-body > :last-child
	{
		border-bottom-left-radius: @block-borderRadius-inner;
		border-bottom-right-radius: @block-borderRadius-inner;
	}

	@{block-noStripSel} > .block-body:first-child > .dataList:first-child,
	.block-topRadiusContent.dataList,
	.block-topRadiusContent > .dataList:first-child
	{
		tbody:first-child .dataList-row:first-child,
		thead:first-child .dataList-row:first-child
		{
			> .dataList-cell:first-child { border-top-left-radius: @block-borderRadius-inner; }
			> .dataList-cell:last-child { border-top-right-radius: @block-borderRadius-inner; }
		}
	}

	@{block-noStripSel} > .block-body:first-child > .formRow:first-child,
	.block-topRadiusContent.formRow,
	.block-topRadiusContent > .formRow:first-child
	{
		> dt { border-top-left-radius: @block-borderRadius-inner; }
		> dd { border-top-right-radius: @block-borderRadius-inner; }
	}

	@{block-noStripSel} > .block-body:last-child > .dataList:last-child,
	.block-bottomRadiusContent.dataList,
	.block-bottomRadiusContent > .dataList:last-child
	{
		tbody:last-child .dataList-row:last-child
		{
			> .dataList-cell:first-child { border-bottom-left-radius: @block-borderRadius-inner; }
			> .dataList-cell:last-child { border-bottom-right-radius: @block-borderRadius-inner; }
		}
	}

	@{block-noStripSel} > .block-body:last-child > .formRow:last-child,
	.block-bottomRadiusContent.formRow,
	.block-bottomRadiusContent > .formRow:last-child
	{
		> dt { border-bottom-left-radius: @block-borderRadius-inner; }
		> dd { border-bottom-right-radius: @block-borderRadius-inner; }
	}

	@{block-noStripSel} > .block-body:last-child .formSubmitRow:not(.is-sticky),
	@{block-noStripSel} > .formSubmitRow:not(.is-sticky):last-child,
	.block-bottomRadiusContent > .formSubmitRow:not(.is-sticky)
	{
		> dt { border-bottom-left-radius: @block-borderRadius-inner; }
		> dd { border-bottom-right-radius: @block-borderRadius-inner; }

		.formSubmitRow-bar
		{
			border-bottom-left-radius: @block-borderRadius-inner;
			border-bottom-right-radius: @block-borderRadius-inner;
		}
	}
}

.block-header
{
	padding: @xf-blockHeadPaddingV @xf-blockHeadPaddingH;
	margin: 0;
	font-weight: @xf-fontWeightNormal;
	text-decoration: none;
	<xf:if is="property('nlBlockHeadStyle') == 'blockMinorHeader'">
	.xf-blockMinorHeader();
	<xf:else />
	.xf-blockHeader();
	</xf:if>

	.m-clearFix();
	/* .m-hiddenLinks(); */

	&.block-header--separated
	{
		border-top: @xf-borderSize solid @xf-borderColorLight;
	}

	.block-desc
	{
		<xf:if is="property('nlBlockHeadStyle') == 'blockHeader'">
		color: fade(@xf-blockHeader--color, 70);
		<xf:else />
		color: fade(@xf-blockMinorHeader--color, 70);
		</xf:if>
		.m-textColoredLinks();
	}
}

.block-minorHeader
{
	padding: @xf-blockHeadPaddingV  @xf-blockHeadPaddingH;
	margin: 0;
	font-weight: @xf-fontWeightNormal;
	text-decoration: none;
	.m-lineHeightDefault();
	<xf:if is="property('nlBlockHeadStyle') == 'blockHeader'">
	.xf-blockHeader();
	<xf:else />
	.xf-blockMinorHeader();
	</xf:if>

	.m-clearFix();
	.m-hiddenLinks();

	.block-body + &
	{
		border-top: @xf-borderSize solid @xf-borderColorLight;
	}

	.block-desc
	{
		.m-textColoredLinks();
	}

	&--spaced
	{
		margin-top: @xf-paddingSmall;
	}

	&--small
	{
		font-size: @xf-fontSizeSmall;
	}
}

.block-tabHeader
{
	padding: 0;
	margin: 0;
	font-weight: @xf-fontWeightNormal;
	.xf-blockTabHeader();
	.m-tabsTogether(xf-default(@xf-blockTabHeader--font-size, @xf-fontSizeNormal));

	.tabs-tab
	{
		padding: @xf-blockPaddingV @xf-blockPaddingH;
		border-bottom: @xf-borderSizeFeature solid transparent;
		.xf-nlBlockTabHeaderTab();

		&:hover
		{
			// color: @xf-blockTabHeaderSelected--color;
			// background: fade(@xf-blockTabHeaderSelected--color, 10%);
			.xf-nlBlockTabHeaderHover();
		}

		&.is-active
		{
			background: none;
			.xf-blockTabHeaderSelected();
		}
	}

	.tabs-text
	{
		padding: @xf-blockPaddingV @xf-blockPaddingH;
		border-bottom: @xf-borderSizeFeature solid transparent;
	}

	.block-tabHeader-extra
	{
		float: right;
		color: inherit;
		font-size: @xf-blockTabHeader--font-size;
		padding: @xf-blockPaddingV @xf-blockPaddingH;
	}

	.hScroller-action
	{
		.m-hScrollerActionColorVariation(
			xf-default(@xf-blockTabHeader--background-color, transparent),
			xf-default(@xf-blockTabHeader--color, ~""),
			xf-default(@xf-blockTabHeaderSelected--color, ~"")
		);
	}
}

.block-minorTabHeader
{
	padding: 0;
	margin: 0;
	font-weight: @xf-fontWeightNormal;
	.xf-blockMinorTabHeader();
	.m-tabsTogether(xf-default(@xf-blockMinorTabHeader--font-size, @xf-fontSizeNormal));

	.tabs-tab
	{
		padding: @xf-blockPaddingV @xf-blockPaddingH max(0px, @xf-blockPaddingV - @xf-borderSizeFeature);
		border-bottom: @xf-borderSizeFeature solid transparent;
		.xf-nlBlockMinorTabHeaderTab();

		&:hover
		{
			.xf-nlBlockMinorTabHeaderHover();
		}

		&.is-active
		{
			.xf-blockMinorTabHeaderSelected();
		}
	}

	.tabs-text
	{
		padding: @xf-blockPaddingV @xf-blockPaddingH max(0px, @xf-blockPaddingV - @xf-borderSizeFeature);
		border-bottom: @xf-borderSizeFeature solid transparent;
	}

	.hScroller-action
	{
		.m-hScrollerActionColorVariation(
			xf-default(@xf-blockMinorTabHeader--background-color, transparent),
			xf-default(@xf-blockMinorTabHeader--color, ~""),
			xf-default(@xf-blockMinorTabHeaderSelected--color, ~"")
		);
	}
}

.block-filterBar
{
	padding: @xf-blockHeadPaddingV @xf-blockHeadPaddingH;
	.m-lineHeightDefault();
	.xf-blockFilterBar();

	&.block-filterBar--standalone
	{
		padding: @xf-blockHeadPaddingV @xf-blockHeadPaddingH;
		border: @xf-borderSize solid @xf-borderColor;
		border-radius: @block-borderRadius-inner;

		@media (max-width: @xf-responsiveEdgeSpacerRemoval)
		{
			border-radius: 0;
			border-left: none;
			border-right: none;
		}
	}

	.filterBar-filterToggle
	{
		background: mix(
			xf-default(@xf-blockFilterBar--color, @xf-linkColor),
			xf-default(@xf-blockFilterBar--background-color, transparent),
			8%
		);
	}

	.filterBar-listToggle, // Discussion grid
	.filterBar-filterToggle,
	.filterBar-menuTrigger
	{
		flex: 0 0 auto;
		white-space: nowrap;
		border-radius: @xf-borderRadiusMedium;
		text-decoration: none;
		padding: 1px  5px;
		transition: .2s all !important;
		.xf-nlBlockMenuTrigger();
		&:hover
		{
			text-decoration: none;
			background: mix(
				xf-default(@xf-blockFilterBar--color, @xf-linkColor),
				xf-default(@xf-blockFilterBar--background-color, transparent),
				16%
			);
			.xf-nlBlockMenuTriggerHover();
		}
	}

	.filterBar-menuTrigger
	{
		margin-right: 0;
	}
}

.block-textHeader
{
	margin: @xf-blockPaddingV/2 0;
	padding: 0;
	font-weight: @xf-fontWeightNormal;
	.xf-blockTextHeader();

	.m-clearFix();
	.m-hiddenLinks();

	&.block-textHeader--scaled
	{
		font-size: inherit;
	}

	.block-textHeader-highlight
	{
		color: @xf-textColor;
	}

	.block-desc
	{
		.m-textColoredLinks();
	}

	&:first-child
	{
		margin-top: 0;
	}
}

.block-formSectionHeader
{
	padding: @xf-blockPaddingV @xf-blockPaddingH;
	margin: 0;
	font-weight: @xf-fontWeightNormal;
	text-decoration: none;
	.xf-formSectionHeader();

	.m-clearFix();
	.m-hiddenLinks();

	.block-desc
	{
		.m-textColoredLinks();
	}

	.block-container > &:first-child,
	.block-body--collapsible &:first-child,
	.block-header + &
	{
		border-top: none;
	}

	.block-formSectionHeader-aligner
	{
		@_blockPaddingShift: (unit(@xf-formLabelWidth) / 100) * (@xf-blockPaddingH);

		display: inline-block;
		text-align: right;
		min-width: @xf-formLabelWidth;
		min-width: ~"calc((@{xf-formLabelWidth}) - (@{_blockPaddingShift}) - (@{xf-formRowPaddingHInner}) - (@{xf-borderSize}))";
		max-width: 100%;

		@media (max-width: @xf-formResponsive)
		{
			display: inline;
			text-align: left;
			min-width: 0;
			padding-left: 0;
		}
	}

	@media (max-width: @xf-formResponsive)
	{
		padding-left: @xf-formRowPaddingHOuter;
	}

	.block-formSectionHeader-multiChecker
	{
		float: right;
	}

	&--small
	{
		font-size: @xf-fontSizeNormal;
	}
}

.block-desc,
.blocks-desc
{
	display: block;
	font-size: @xf-fontSizeSmaller;
	font-weight: @xf-fontWeightNormal;
}

.block-body
{
	.m-listPlain();

	&.block-body--collapsible
	{
		.has-no-js & { display: block; }

		.m-transitionFadeDown();
	}

	&.block-body--contained
	{
		overflow: auto;
		max-height: 300px;
		max-height: 70vh;
	}

	&.block-body--containedFixed
	{
		overflow-x: auto;
		max-height: 300px;
	}
}

.block-row
{
	margin: 0;
	padding: @xf-blockPaddingV @xf-blockPaddingH;
	.m-clearFix();

	&.block-row--toEdge
	{
		padding-left: 0;
		padding-right: 0;
	}
	.xf-nlBlockRow();

	&.block-row--alt
	{
		.xf-contentAltBase();
	}

	&.block-row--minor
	{
		font-size: @xf-fontSizeSmall;
	}

	&.block-row--separated
	{
		/* padding-top: (@xf-blockPaddingV) * 2; */
		/* padding-bottom: (@xf-blockPaddingV) * 2; */
		.xf-nlBlockRowSeparate();

		+ .block-row
		{
			// border-top: @xf-borderSize solid @xf-borderColorLight;
		}
		.block-container > .block-body > & {
			&:hover {
				.xf-nlBlockRowSeparateHover();
			}
		}
	}

	&.block-row--connectAbove
	{
		padding-bottom: (@xf-blockPaddingV) * 2;

		.block-body > &:last-child
		{
			padding-bottom: @xf-blockPaddingV;
		}
	}

	&.block-row--highlighted
	{
		.xf-contentHighlightBase();
	}

	&.block-row--clickable:hover
	{
		.xf-contentHighlightBase();
	}

	&.is-mod-selected
	{
		background: @xf-inlineModHighlightColor;
	}

	> pre
	{
		&:first-child { margin-top: 0; }
		&:last-child { margin-bottom: 0; }
	}
}

.block-separator
{
	margin: 0;
	padding: 0;
	border: none;
	border-top: @xf-borderSize solid @xf-borderColorLight;
}

.block-footer
{
	.xf-blockFooter();
	.m-clearFix();

	&:first-child
	{
		border: none;
	}

	[data-app=admin] &
	{
		.block-footer-counter,
		.block-footer-select
		{
			line-height: 30px;
		}
	}

	&:not(.block-footer--split)
	{
		.block-footer-counter
		{
			float: left;
		}

		.block-footer-controls
		{
			float: right;
		}
	}

	&.block-footer--split
	{
		display: flex;
		align-items: center;

		.block-footer-main,
		.block-footer-counter
		{
			flex-grow: 1;
		}

		.block-footer-select:not(:last-child)
		{
			margin: 0 1em;
		}

		.block-footer-opposite,
		.block-footer-controls
		{
			margin-left: auto;
		}
	}
}

@media (max-width: @xf-responsiveNarrow)
{
	.block-outer
	{
		text-align: center;
	}

	.block-outer-main,
	.block-outer-opposite
	{
		float: none;
		text-align: center;
	}

	.block-outer-main + .block-outer-opposite
	{
		margin-top: @xf-paddingMedium;
	}
}

// ############################ BLOCK LINKS ##################

@_blockLinkPaddingV: @xf-nlBlockLinkPaddingV;

.blockLink
{
	display: block;
	padding: @_blockLinkPaddingV @xf-blockPaddingH;
	.xf-blockLink();

	&.is-selected
	{
		.xf-blockLinkSelected(no-border);
		border-left: @xf-blockLinkSelected--border-width solid @xf-blockLinkSelected--border-color;
		padding-left: (@xf-blockPaddingH - xf-default(@xf-blockLinkSelected--border-width, 0));
	}

	&:hover
	{
		.xf-blockLinkSelected(background);
		text-decoration: inherit;
	}
}

.blockLink-desc
{
	display: block;
	color: @xf-textColorMuted;
	font-size: @xf-fontSizeSmaller;
	font-weight: @xf-fontWeightNormal;
}

.blockLinkSplitToggle
{
	display: flex;
	padding: 0;
	text-decoration: none;
	cursor: pointer;

	&.is-selected
	{
		.xf-blockLinkSelected(no-border);
	}

	&:hover
	{
		.xf-blockLinkSelected(background);
		text-decoration: inherit;
	}
}

.blockLinkSplitToggle-link
{
	display: block;
	padding: @_blockLinkPaddingV @xf-blockPaddingH;
	text-decoration: none;
	flex-grow: 1;

	&:hover
	{
		text-decoration: none;
	}

	.blockLinkSplitToggle.is-selected &
	{
		border-left: @xf-blockLinkSelected--border-width solid @xf-blockLinkSelected--border-color;
		padding-left: (@xf-blockPaddingH - xf-default(@xf-blockLinkSelected--border-width, 0));
	}
}

.blockLinkSplitToggle-toggle
{
	display: inline-block;
	padding: @_blockLinkPaddingV @xf-blockPaddingH;
	text-decoration: none;
	flex-grow: 0;
	line-height: 1;

	&:hover
	{
		text-decoration: none;
	}

	&:after
	{
		.m-faBase();
		font-size: 80%;
		.m-faContent(@fa-var-chevron-down);
	}

	&.is-active:after
	{
		.m-faContent(@fa-var-chevron-up);
	}
}

.blockLink--iconic
{
	i:after
	{
		.m-faBase();
		display: inline-block;
		min-width: 1em;
		position: absolute;
		left: @xf-blockPaddingH;
		top: 8px;
		display: none !important;
	}

	&--started i:after
	{
		.m-faContent(@fa-var-file-alt);
	}
	&--contributed i:after
	{
		.m-faContent(@fa-var-comments);
	}
	&--watched i:after
	{
		.m-faContent(@fa-var-bookmark);
	}
	&--unanswered i:after
	{
		.m-faContent(@fa-var-question-circle);
	}
}

// ################################ FAUX BLOCK LINKS #######################
// concept from https://codepen.io/BPScott/pen/Erwan and http://codepen.io/IschaGast/pen/Qjxpxo
// z-indexes are bumped to have the link sit on top of positioned elements (without z-index)

.fauxBlockLink
{
	position: relative;

	a,
	.fauxBlockLink-link
	{
		position: relative;
		z-index: 2;
	}

	.fauxBlockLink-blockLink
	{
		position: static;

		&:before
		{
			content: '';
			position: absolute;
			top: 0;
			left: 0;
			right: 0;
			bottom: 0;
			z-index: 1;
		}
	}

	&.fauxBlockLink--noHover
	{
		.fauxBlockLink-blockLink:hover
		{
			text-decoration: none;
		}
	}
}

// ############################ BUTTONS #################

.button,
a.button // needed for specificity over a:link
{
	.m-buttonBase();

	a
	{
		color: inherit;
		text-decoration: none;
	}

	.xf-buttonDefault();
	// .m-buttonBlockColorVariationSimple(xf-default(@xf-buttonDefault--background-color, transparent));

	&.button--primary
	{
		.xf-buttonPrimary();
		// .m-buttonBlockColorVariationSimple(xf-default(@xf-buttonPrimary--background-color, transparent));
	}

	&.button--cta
	{
		.xf-buttonCta();
		// .m-buttonBlockColorVariationSimple(xf-default(@xf-buttonCta--background-color, transparent));
	}

	&.button--link
	{
		// block colors
		background: @xf-contentBg;
		color: @xf-linkColor;
		.m-buttonBorderColorVariation(@xf-borderColor);

		&:hover,
		&:active,
		&:focus
		{
			text-decoration: none;
			background: @xf-contentHighlightBg;
		}
	}

	&.button--plain
	{
		background: none;
		color: @xf-linkColor;
		border: none;

		&:hover,
		&:active,
		&:focus
		{
			text-decoration: none;
			background: none;
		}
	}

	&.button--alt
	{
		// block colors
		background-color: @xf-paletteColor1;
		color: @xf-linkColor;
		.m-buttonBorderColorVariation(@xf-paletteColor2);

		&:hover,
		&:active,
		&:focus
		{
			background-color: @xf-paletteColor1;
			color: @xf-linkColor;
		}
	}

	&.button--longText
	{
		.m-overflowEllipsis();
		max-width: 100%;
		display: inline-block;
	}

	&.is-disabled
	{
		.xf-buttonDisabled();
		// .m-buttonBorderColorVariation(xf-default(@xf-buttonDisabled--background-color, transparent));

		&:hover,
		&:active,
		&:focus
		{
			background: xf-default(@xf-buttonDisabled--background-color, transparent) !important;
		}
	}

	&.is-hidden
	{
		display: none;
	}

	&.button--scroll
	{
		background: fade(xf-default(@xf-buttonDefault--background-color, transparent), 75%);
		padding: 5px 8px;

		.m-dropShadow();
	}

	&.button--normal
	{
		font-size: @xf-fontSizeNormal;
	}

	&.button--small
	{
		font-size: @xf-fontSizeSmall;
		padding: 3px 6px;
	}

	&.button--smaller
	{
		font-size: @xf-fontSizeSmaller;
		padding: 2px 5px;
	}

	&.button--fullWidth
	{
		display: block;
		width: 100%;
	}

	&.button--adminStyleAsset
	{
		&.is-disabled
		{
			visibility: hidden;
		}

		&.is-modify
		{
			.m-buttonIcon(@fa-var-pencil);
		}

		&.is-revert
		{
			.m-buttonIcon(@fa-var-history);
		}
	}

	&.button--wrap
	{
		white-space: normal;
	}

	&.button--icon
	{
		> .button-text:before,
		.button-icon
		{
			.m-faBase();
		}

		> .button-text:before,
		> .fa--xf:before,
		.button-icon
		{
			font-size: 120%;
			vertical-align: -.1em;
			display: inline-block;
			margin: -.255em 6px -.255em 0;
		}

		> .fa--xf
		{
			// helps fix a button alignment issue (Chrome only)
			line-height: inherit;
		}

		.button-icon
		{
			height: 1em;
			vertical-align: 0;
		}

		&.button--iconOnly
		{
			> .button-text:before,
			> i.fa--xf:before,
			.button-icon
			{
				margin-left: 0;
				margin-right: 0;
			}
		}

		&.button--padded
		{
			> .button-text:before,
			> i.fa--xf:before,
			.button-icon
			{
				margin-top: 0;
				margin-bottom: 0;
			}
		}

		&--add          { .m-buttonIcon(@fa-var-plus-square, .88em); }
		&--confirm      { .m-buttonIcon(@fa-var-check, 1em); }
		&--write	    { .m-buttonIcon(@fa-var-edit, 1.13em); }
		&--import  	    { .m-buttonIcon(@fa-var-upload, 1.13em); }
		&--export  	    { .m-buttonIcon(@fa-var-download,  1.13em); }
		&--download	    { .m-buttonIcon(@fa-var-download, 1.13em); }
		&--redirect	    { .m-buttonIcon(@fa-var-external-link, 1em); }
		&--disable      { .m-buttonIcon(@fa-var-power-off, 1em); }
		&--edit         { .m-buttonIcon(@fa-var-edit, 1.13em); }
		&--save         { .m-buttonIcon(@fa-var-save, .88em); }
		&--reply	    { .m-buttonIcon(@fa-var-reply, 1.13em); }
		&--quote	    { .m-buttonIcon(@fa-var-quote-left, 1.13em); }
		&--purchase	    { .m-buttonIcon(@fa-var-credit-card, 1.13em); }
		&--payment	    { .m-buttonIcon(@fa-var-credit-card, 1.13em); }
		&--convert	    { .m-buttonIcon(@fa-var-bolt, .75em); }
		&--search	    { .m-buttonIcon(@fa-var-search, 1em); }
		&--sort         { .m-buttonIcon(@fa-var-sort, .63em); }
		&--upload	    { .m-buttonIcon(@fa-var-upload, 1.13em); }
		&--attach	    { .m-buttonIcon(@fa-var-paperclip, 1em); }
		&--login {
			.m-buttonIcon(@fa-var-lock, .88em);
		}
		&--rate         { .m-buttonIcon(@fa-var-star, 1.13em); }
		&--config       { .m-buttonIcon(@fa-var-cog, 1em); }
		&--refresh      { .m-buttonIcon(@fa-var-sync-alt, 1em); }
		&--translate    { .m-buttonIcon(@fa-var-globe, .97em); }
		&--vote         { .m-buttonIcon(@fa-var-check-circle, 1em); }
		&--result       { .m-buttonIcon(@fa-var-chart-bar, 1em); }
		&--history	    { .m-buttonIcon(@fa-var-history, 1em); }
		&--cancel       { .m-buttonIcon(@fa-var-ban, 1em); }
		&--close        { .m-buttonIcon(@fa-var-times, .69em); }
		&--preview      { .m-buttonIcon(@fa-var-eye, 1.13em); }
		&--conversation { .m-buttonIcon(@fa-var-comments, 1.13em); }
		&--bolt         { .m-buttonIcon(@fa-var-bolt, .75em); }
		&--list         { .m-buttonIcon(@fa-var-list, 1em); }
		&--prev			{ .m-buttonIcon(@fa-var-chevron-left, .63em); }
		&--next			{ .m-buttonIcon(@fa-var-chevron-right, .63em); }
		&--markRead     { .m-buttonIcon(@fa-var-check-square, .88em); }
		&--user         { .m-buttonIcon(@fa-var-user, .88em); }
		&--userCircle   { .m-buttonIcon(@fa-var-user-circle, .97em); }

		&--notificationsOn  { .m-buttonIcon(@fa-var-bell, 1.25em); } // actually only .88em, but as we use this as a toggle, make it the same width as bell-slash
		&--notificationsOff { .m-buttonIcon(@fa-var-bell-slash, 1.25em); }

		&--show			{ .m-buttonIcon(@fa-var-eye, 1.25em) } // actually only 1.13em, but it's a toggle
		&--hide			{ .m-buttonIcon(@fa-var-eye-slash, 1.25em) }

		// for inline mod confirmations
		&--merge { .m-buttonIcon(@fa-var-compress, .88em); }
		&--move { .m-buttonIcon(@fa-var-share, 1.13em); }
		&--copy { .m-buttonIcon(@fa-var-copy, .88em); }
		&--approve, &--unapprove { .m-buttonIcon(@fa-var-shield, 1em); }
		&--delete, &--undelete { .m-buttonIcon(@fa-var-trash-alt, .88em); }
		&--stick, &--unstick { .m-buttonIcon(@fa-var-thumbtack, .75em); }
		&--lock { .m-buttonIcon(@fa-var-lock, .88em); }
		&--unlock { .m-buttonIcon(@fa-var-unlock, .88em); }

		&--bookmark
		{
			.m-buttonIcon(@fa-var-bookmark);

			&.is-bookmarked .button-text:before
			{
				font-weight: @faWeight-solid;
				color: @xf-textColorAttention;
			}
		}
	}

	&.button--provider
	{
		> .button-text:before,
		.button-icon
		{
			.m-faBase('Brands');
			font-size: 120%;
			vertical-align: middle;
			display: inline-block;
			margin: -4px 6px -4px 0;
		}

		.button-icon
		{
			height: 1em;
			vertical-align: 0;
		}

		&--facebook
		{
			.m-buttonColorVariation(#3B5998, white);
			.m-buttonIcon(@fa-var-facebook, 1em);
		}

		&--twitter
		{
			.m-buttonColorVariation(#1DA1F3, white);
			.m-buttonIcon(@fa-var-twitter, 1em);
		}

		&--google
		{
			.m-buttonColorVariation(white, #444);
			border-color: #e9e9e9;

			> .button-text:before
			{
				display: none;
			}
		}

		&--github
		{
			.m-buttonColorVariation(#666666, white);
			.m-buttonIcon(@fa-var-github, .97em);
		}

		&--linkedin
		{
			.m-buttonColorVariation(#0077b5, white);
			.m-buttonIcon(@fa-var-linkedin, .88em);
		}

		&--microsoft
		{
			.m-buttonColorVariation(#00bcf2, white);
			.m-buttonIcon(@fa-var-windows, .88em);
		}

		&--yahoo
		{
			.m-buttonColorVariation(#410093, white);
			.m-buttonIcon(@fa-var-yahoo, .88em);
		}
	}

	&.button--splitTrigger
	{
		// button-text and button-menu are always children of button--splitTrigger
		// but are defined here for reasons of specificity, as these border colors
		// are overwritten by .m-buttonBorderColorVariation()
		> .button-text { border-right: @xf-borderSize solid transparent; }
		> .button-menu { border-left: @xf-borderSize solid transparent; }

		.m-clearFix();
		padding: 0;
		font-size: 0;
		display: inline-block;

		button.button-text
		{
			background: transparent;
			border: none;
			border-right: @xf-borderSize solid transparent;
			color: inherit;
		}

		> .button-text,
		> .button-menu
		{
			.xf-buttonBase();
			display: inline-block;

			&:hover
			{
				&:after
				{
					opacity: 1;
				}
			}
		}

		> .button-text
		{
			.m-borderRightRadius(0);
		}

		> .button-menu
		{
			.m-borderLeftRadius(0);
			padding-right: xf-default(@xf-buttonBase--padding-right, 0);// * (2/3);
			padding-left: xf-default(@xf-buttonBase--padding-left, 0);// * (2/3);

			&:after
			{
				.m-menuGadget(); // .58em
				opacity: .5;
			}
		}
	}
}

.buttonGroup
{
	display: inline-block;
	vertical-align: top;
	.m-clearFix();

	&.buttonGroup--aligned
	{
		vertical-align: middle;
	}

	> .button
	{
		float: left;

		&:not(:first-child)
		{
			border-left: none;
		}

		&:not(:first-child):not(:last-child)
		{
			border-radius: 0;
		}

		&:first-child:not(:last-child)
		{
			.m-borderRightRadius(0);
		}

		&:last-child:not(:first-child)
		{
			.m-borderLeftRadius(0);
		}
	}

	> .buttonGroup-buttonWrapper
	{
		float: left;

		&:not(:first-child) > .button
		{
			border-left: none;
		}

		&:not(:first-child):not(:last-child) > .button
		{
			border-radius: 0;
		}

		&:first-child:not(:last-child) > .button
		{
			.m-borderRightRadius(0);
		}

		&:last-child:not(:first-child) > .button
		{
			.m-borderLeftRadius(0);
		}
	}
}

.toggleButton
{
	> input
	{
		display: none;
	}

	> span
	{
		.xf-buttonDisabled();
		.m-buttonBorderColorVariation(xf-default(@xf-buttonDisabled--background-color, transparent));
	}

	&.toggleButton--small > span
	{
		font-size: @xf-fontSizeSmaller;
		padding: @xf-paddingSmall;
	}

	> input:checked + span
	{
		.xf-buttonDefault();
		.m-buttonBlockColorVariationSimple(xf-default(@xf-buttonDefault--background-color, transparent));
	}
}

.u-scrollButtons
{
	position: fixed;
	bottom: 30px;
	right: (@xf-pageEdgeSpacer) / 2;

	.has-hiddenscroll &
	{
		right: 20px;
	}

	z-index: @zIndex-9;

	.m-transition(opacity; @xf-animationSpeed);
	opacity: 0;
	display: none;

	&.is-transitioning
	{
		display: block;
	}

	&.is-active
	{
		display: block;
		opacity: 1;
	}

	.button
	{
		display: block;

		+ .button
		{
			margin-top: (@xf-pageEdgeSpacer) / 2;
		}
	}
}

// ################################ CATEGORY LIST #######################

@_categoryListTogglerWidth: 1em;
@_categoryListTogglerPaddingH: @xf-paddingMedium;
@_categoryListItemPaddingV: @xf-nlBlockLinkPaddingV;

.categoryList
{
	display: none;
	.m-listPlain();

	&.is-active
	{
		display: block;
	}
}

.categoryList-item
{
	padding: 0;
	text-decoration: none;
	font-size: @xf-fontSizeNormal;

	&.categoryList-item--small
	{
		font-size: @xf-fontSizeSmall;
	}

	.categoryList
	{
		padding-left: @xf-paddingLarge;
	}
}

.categoryList-itemDesc
{
	display: block;
	font-size: @xf-fontSizeSmaller;
	font-weight: @xf-fontWeightNormal;
	color: @xf-textColorMuted;
	margin-top: -@xf-blockPaddingV;

	.m-overflowEllipsis();
}

.categoryList-header
{
	padding: @xf-blockPaddingV 0;
	margin: 0;
	color: @xf-textColorFeature;
	text-decoration: none;
	font-weight: @xf-fontWeightHeavy;

	&.categoryList-header--muted
	{
		color: @xf-textColorMuted;
	}

	.m-clearFix();
	.m-hiddenLinks();
}

.categoryList-itemRow
{
	display: flex;
	min-width: 0;
}

.categoryList-link
{
	display: block;
	flex-grow: 1;
	padding: @_categoryListItemPaddingV @_categoryListTogglerPaddingH;
	text-decoration: none;

	.m-overflowEllipsis();

	&:hover
	{
		text-decoration: none;
	}

	&.is-selected
	{
		font-weight: @xf-fontWeightHeavy;
	}

	.categoryList-toggler + &,
	.categoryList-togglerSpacer + &
	{
		padding-left: 0;
	}
}

.categoryList-label
{
	margin-left: auto;
	align-self: center;
	padding-right: @_categoryListTogglerPaddingH;
}

.categoryList-toggler
{
	display: inline-block;
	padding: @_categoryListItemPaddingV @_categoryListTogglerPaddingH;
	text-decoration: none;
	flex-grow: 0;
	line-height: normal;

	&:hover
	{
		text-decoration: none;
	}

	&:after
	{
		.m-faBase();
		font-size: 80%;
		.m-faContent(@fa-var-chevron-down, @_categoryListTogglerWidth);
	}

	&.is-active:after
	{
		.m-faContent(@fa-var-chevron-up, @_categoryListTogglerWidth);
	}
}

.categoryList-togglerSpacer
{
	display: inline-block;
	visibility: hidden;
	padding: @_categoryListItemPaddingV @_categoryListTogglerPaddingH;

	&:after
	{
		.m-faBase();
		font-size: 80%;
		.m-faContent(@fa-var-chevron-down, @_categoryListTogglerWidth);
	}
}

<xf:if is="property('nlBlockLinkType') == 'lineHeight'">
.categoryList-link
{
	padding: 0;
	color: inherit;
}
.categoryList-toggler
{
	padding: 0 @_categoryListTogglerPaddingH 0 0 ;
    height: @xf-nlBlockLinkHeight;
    line-height: (@xf-nlBlockLinkHeight - 2);
	color: inherit;
}
.categoryList-togglerSpacer
{
	padding: @_categoryListItemPaddingV @_categoryListTogglerPaddingH 0 0;

	.toggleTarget .toggleTarget & {
		padding-left: @_categoryListTogglerPaddingH;
	}
}
</xf:if>

// ########################################## COLLAPSE / TOGGLERS ##############################

.toggleTarget
{
	display: none;
	.m-transition(all, -xf-height;);
	overflow: hidden;
	height: 0;
	opacity: 0;

	&.is-transitioning
	{
		display: block;
	}

	&.is-active
	{
		display: block;
		height: auto;
		opacity: 1;
	}
}

.collapseTrigger:not(.button)
{
	cursor: pointer;

	&:before
	{
		.m-faBase('Pro', @faWeight-solid);
		//.m-faContent(@fa-var-caret-right); //, .63em
		display: inline-block;
		content: "@xf-nlCollapseTriggerIcon";
		width: .63em;
		font-size: 80%;
		margin-right: .2em;
		// Prevent transitioned flipping
		<xf:if is="property('nlCollapseTriggerIconActiveMode') == 'rotate' || property('nlCollapseTriggerIconActiveMode') == 'icon'">
		transition: .2s all;
		<xf:else />
		transition: .2s background, .2s border, .2s color;
		</xf:if>
	}

	&.is-active:before
	{
		//.m-faContent(@fa-var-caret-down); //, .63em
		<xf:if is="property('nlCollapseTriggerIconActiveMode') == 'rotate'">
			transform: rotate(180deg);
		<xf:elseif is="property('nlCollapseTriggerIconActiveMode') == 'flipX'" />
			transform: rotateX(180deg);
		<xf:elseif is="property('nlCollapseTriggerIconActiveMode') == 'flipY'" />
			transform: rotateY(180deg);
		<xf:elseif is="property('nlCollapseTriggerIconActiveMode') == 'icon'" />
			content: "@xf-nlCollapseTriggerActiveIcon";
		</xf:if>
	}

	&.collapseTrigger--block
	{
		display: block;

		&:before
		{
			float: right;
			margin-right: 0;
			margin-left: 5px;
			font-size: 100%;
			line-height: inherit;
		}
	}
}

.collapseTrigger.button--icon
{
	.m-buttonIcon(@fa-var-angle-right, .63em); // only .5em but it's a toggle

	&.is-active
	{
		.m-buttonIcon(@fa-var-angle-down, .63em);
	}
}

// ##################### FILTERING #####################

.filterBlock
{
	padding: @xf-paddingMedium;
	font-size: @xf-fontSizeSmaller;
	float: right;
	.xf-contentBase();
	.xf-blockBorder();
	border-radius: @xf-blockBorderRadius;
	.m-clearFix();

	.filterBlock-input
	{
		width: 150px;
		display: inline;
		font-size: @xf-fontSizeSmaller;

		&.filterBlock-input--small
		{
			width: 100px;
		}
	}

	select.filterBlock-input
	{
		width: auto;
	}
}

.quickFilter
{
	position: relative;

	.input
	{
		width: 180px;
		font-size: @xf-fontSizeSmaller;
	}

	label
	{
		font-size: @xf-fontSizeSmaller;
	}

	input[type=checkbox]
	{
		.m-checkboxAligner();
	}

	.js-filterClear
	{
		color: @controlColor;

		&:hover
		{
			color: @controlColor--hover;
		}

		&:before
		{
			.m-faBase();
			.m-faContent(@fa-var-times);
		}
	}
}

.filterBar
{
	display: flex;
	align-items: center; // Try this patch, depricate if needed
}

.filterBar-filters
{
	flex: 1 1 auto;

	display: flex;
	flex-wrap: wrap;
	row-gap: @xf-blockPaddingV;
	// column-gap: @xf-blockPaddingV;

	.m-listPlain();
}

.filterBar-filterToggle
{
	display: flex;
	text-decoration: none;
	color: inherit;
	padding: 1px 8px;
	border-radius: @xf-borderRadiusMedium;
	.m-transition();

	column-gap: 2px;
	margin-right: @xf-blockPaddingV;

	i.fa--xf
	{
		align-self: center;
	}

	&:after
	{
		.m-faBase();
		font-size: 80%;
		vertical-align: bottom;
		.m-faContent(" @{fa-var-times}");
		opacity: .5;
		.m-transition(opacity);
		position: relative;
		bottom: -2px;
	}

	&:hover
	{
		text-decoration: none;

		&:after
		{
			opacity: 1;
		}
	}
}

.filterBar-filterToggle-label
{
	opacity: .75;
	margin-right: 2px;
}

.filterBar-filterToggle-value
{
	max-width: 120px;
	overflow: hidden;
	white-space: nowrap;
	text-overflow: ellipsis;

	&:not(:last-of-type):after
	{
		content: "{$xf.language.comma_separator}";
	}
}

.filterBar-menuTrigger
{
	flex: 0 0 auto;
	margin-left: auto;
	white-space: nowrap;
	border-radius: @xf-borderRadiusMedium;
	text-decoration: none;
	padding: 1px  5px;

	&:after
	{
		.m-menuGadget();
	}
}

@media (max-width: @xf-responsiveMedium)
{
	.filterBar-filterToggle-label
	{
		display: none;
	}
}

// ####################################### PAGE NAVIGATION ########################

@_page-paddingV: xf-default(@xf-buttonBase--padding-top, 6px);
@_page-paddingH: 8px;
@_page-paddingHSimple: 10px;

.pageNavWrapper {}

.m-pageNavElCore()
{
	background: linear-gradient(0deg, @xf-contentHighlightBg, mix(@xf-contentHighlightBg, @xf-contentBg, 25%));
	color: @xf-linkColor;
	.xf-blockBorder();
	font-size: @xf-fontSizeSmall;
	white-space: nowrap;
	.xf-nlPageNavItem();

	&:hover,
	&:active
	{
		/*
		background: xf-intensify(@xf-contentHighlightBg, 3%);
		*/
		text-decoration: none;
		.xf-nlPageNavItemHover();
	}
}

.pageNav-jump
{
	display: inline-block;
	.m-pageNavElCore();
	border-radius: @xf-borderRadiusSmall;
	padding: @_page-paddingV @_page-paddingH;

	&.pageNav-jump--prev:before,
	&.pageNav-jump--next:after
	{
		.m-faBase('Pro', @faWeight-solid);
		font-size: 80%;
		unicode-bidi: isolate; // maintain position in RTL with LTR text
	}

	&.pageNav-jump--prev:before
	{
		.m-faContent("@{fa-var-caret-left}\00a0", false, ltr); // .61em
		.m-faContent("@{fa-var-caret-right}\00a0", false, rtl); // .61em
	}

	&.pageNav-jump--next:after
	{
		.m-faContent("\00a0@{fa-var-caret-right}", false, ltr); // .61em
		.m-faContent("\00a0@{fa-var-caret-left}", false, rtl); // .61em
	}
}

.pageNav-main
{
	.m-listPlain();
	display: inline-table;
}

.pageNav-page
{
	display: table-cell;
	.m-pageNavElCore();
	/*
	&:not(:last-child)
	{
		border-right: none;
	}

	&:not(:first-child)
	{
		border-left-color: @xf-borderColorLight;
	}

	&:first-child
	{
		.m-borderLeftRadius(@xf-borderRadiusSmall);
	}

	&:last-child
	{
		.m-borderRightRadius(@xf-borderRadiusSmall);
	}
	*/
	> a
	{
		display: block;
		padding: @_page-paddingV @_page-paddingH;
		text-decoration: none;
		color: inherit;
	}

	&.pageNav-page--current
	{
		/*
		background: @xf-contentAccentBg;
		color: @xf-textColorAccentContent;

		border: @xf-borderSize solid @xf-borderColorAccentContent;
		*/
		cursor: pointer;
		.xf-nlPageNavItemHover();

		&:hover,
		&:active
		{
			/*
			background: xf-intensify(@xf-contentAccentBg, 3%);
			*/
		}

		+ .pageNav-page
		{
			/*
			border-left: none;
			*/
		}
	}
}

// Hide relative page numbers on narrow devices when we have a skip entry as we don't necessarily have space.
@media (max-width: @xf-responsiveNarrow)
{
	.pageNav--skipStart
	{
		.pageNav-page.pageNav-page--earlier
		{
			display: none;
		}
	}

	.pageNav--skipEnd
	{
		.pageNav-page.pageNav-page--later
		{
			display: none;
		}

		.pageNav-page.pageNav-page--skipEnd
		{
			border-left: none;
		}
	}
}

// ########################### SIMPLE PAGE NAV VARIANT ########################

.pageNavSimple
{
	display: inline-flex;
}

.pageNavSimple-el
{
	display: inline-block;
	.xf-blockBorder();
	border-radius: @xf-borderRadiusSmall;
	padding: @_page-paddingV @_page-paddingHSimple;
	font-size: @xf-fontSizeSmall;
	text-align: center;
	white-space: nowrap;
	margin-right: 4px;

	&:last-child
	{
		margin-right: 0;
	}

	&.pageNavSimple-el--current
	{
		.xf-contentAccentBase();

		&:hover,
		&:active
		{
			background: xf-intensify(@xf-contentAccentBg, 3%);
			text-decoration: none;
		}
	}

	&.pageNavSimple-el--prev,
	&.pageNavSimple-el--next
	{
		background: linear-gradient(0deg, @xf-contentHighlightBg, mix(@xf-contentHighlightBg, @xf-contentBg, 25%));
		color: @xf-linkColor;
		min-width: 75px;

		@media (max-width: 350px)
		{
			min-width: 0;
		}

		&:hover,
		&:active
		{
			background: xf-intensify(@xf-contentHighlightBg, 3%);
			text-decoration: none;
		}

		i:before
		{
			.m-faBase('Pro', @faWeight-solid);
		}
	}

	&.pageNavSimple-el--prev i:before
	{
		.m-faContent(@fa-var-caret-left, false, ltr); // , .44em
		.m-faContent(@fa-var-caret-right, false, rtl); // , .44em
	}

	&.pageNavSimple-el--next i:before
	{
		.m-faContent(@fa-var-caret-right, false, ltr); // , .44em
		.m-faContent(@fa-var-caret-left, false, rtl); // , .44em
	}

	&.pageNavSimple-el--first,
	&.pageNavSimple-el--last
	{
		border-color: transparent;
		padding-left: (@_page-paddingHSimple / 2);
		padding-right: (@_page-paddingHSimple / 2);
		color: fade(@xf-linkColor, 60%);

		&:hover,
		&:active
		{
			.xf-blockBorder();
			background: xf-intensify(@xf-contentHighlightBg, 3%);
			color: @xf-linkColor;
			text-decoration: none;
		}

		i:before
		{
			.m-faBase('Pro', @faWeight-solid);
		}
	}

	&.pageNavSimple-el--first i:before
	{
		.m-faContent(@fa-var-backward, false, ltr); // 1em
		.m-faContent(@fa-var-forward, false, rtl); // 1em
	}

	&.pageNavSimple-el--last i:before
	{
		.m-faContent(@fa-var-forward, false, ltr); // 1em
		.m-faContent(@fa-var-backward, false, rtl); // 1em
	}

	&.is-disabled
	{
		border-color: transparent;
		background: none;
		color: @xf-textColorMuted;
		text-decoration: none;
		pointer-events: none;

		&:hover
		{
			background: none;
			color: @xf-textColorMuted;
		}
	}
}

// #################### DISPLAY VARIANTS #########################

.pageNavWrapper--simple
{
	.pageNav
	{
		display: none;
	}
}

.pageNavWrapper--full
{
	.pageNavSimple
	{
		display: none;
	}
}

.pageNavWrapper--mixed
{
	.pageNavSimple
	{
		display: none;
	}

	@media (max-width: @xf-responsiveMedium)
	{
		.pageNav
		{
			display: none;
		}

		.pageNavSimple
		{
			display: inline-flex;
		}
	}
}

// Hide any block page nav that goes before the block as we will be wasting vertical space.
@media (max-width: @xf-responsiveNarrow)
{
	.block-outer:not(.block-outer--after) .pageNavWrapper:not(.pageNavWrapper--forceShow)
	{
		display: none;
	}

	// this is a sanity check in case .block-outer--after is forgotten
	.block-container + .block-outer .pageNavWrapper
	{
		display: block;
	}
}

/* XF-RTL:disable */
{{ include('editor_base.less') }}
/* XF-RTL:enable */

@_editorBorderRadius: xf-default(@xf-input--border-radius, @xf-borderRadiusMedium);
@_editorBorderColor: var(--input-border-heavy) var(--input-border-light) var(--input-border-light) var(--input-border-heavy);
//@_editorFocusBorderColor: xf-default(@xf-inputFocus--border-top-color, @xf-borderColorHeavy) xf-default(@xf-inputFocus--border-right-color, @xf-borderColorLight) xf-default(@xf-inputFocus--border-bottom-color, @xf-borderColorLight) xf-default(@xf-inputFocus--border-left-color, @xf-borderColorHeavy);
@_editorButtonGroupHPadding: 12px;
@_editorButtonGroupHPaddingSmall: 6px;

.fr-box.fr-basic
{
	background: @xf-editorBg;
	border: solid 1px @xf-borderColor;
	border-color: @_editorBorderColor;
	.border-radius(@_editorBorderRadius);

	.fr-toolbar.fr-top
	{
		background: @xf-editorToolsBg;
	}

	&.is-focused
	{
		background: @xf-editorFocusBg;
		//border-color: @_editorFocusBorderColor;

		.fr-element
		{
			color: @xf-editorFocusColor;
		}

		.fr-toolbar.fr-top
		{
			background: @xf-editorToolsFocusBg;
		}
	}

	// regular border instead of an 'input' border
	&.is-preview,
	&.is-preview .fr-toolbar .fr-btn-grp.rte-tab--preview
	{
		background: @xf-contentBg;
		border-color: @xf-borderColor;
	}

	.fr-wrapper
	{
		border: none;
	}

	.fr-element
	{
		.m-inputZoomFix();
		padding-top: @editor-padding / 2;
	}
}

.fr-toolbar
{
	@_more-spacer: 4px;

	display: flex;
	flex-wrap:  wrap;
	border: none;
	background: transparent;
	.border-radius(@_editorBorderRadius @_editorBorderRadius 0 0);

	.fr-command.fr-btn
	{
		display: inline-flex;
		align-items: center;
		justify-content: center;

		// context sensitivity for toolbar buttons (highlight [B] when cursor is on bold text etc.)
		&.fr-active:not(.fr-disabled)
		{
			color: @xf-editorButtonActiveColor;
			background: @xf-editorButtonSelectedBg;
		}

		// de-emphasize the 'more' buttons slightly
		&[data-cmd^="more"]
		{
			opacity: 0.5;

			&.fr-open
			{
				opacity: 1
			}

			i
			{
				width: 16px;
			}
		}

		&.fr-dropdown
		{
			margin-right: 8px;

			&:last-of-type
			{
				margin-right: 2px;
			}
		}
	}

	// BUTTON GROUP HANDLING
	.fr-btn-grp
	{
		// using CSS variables here but we have a fallback for older browsers (for now)
		--hpadding: @_editorButtonGroupHPadding;

		display: inline-flex;

		border-style: solid;
		border-width: 0px;
		border-color: @_editorBorderColor;

		margin: 0;
		padding: @_more-spacer 0 0 @_editorButtonGroupHPadding; // basic padding for older browsers
		padding: @_more-spacer 0 0 var(--hpadding);

		// hide empty groups completely, just in case we have alternative padding specified later on
		&:empty
		{
			padding: 0 !important;
		}

		//&:nth-child(even)
		//{
		//	background: rgba(0,0,0,.05);
		//}

		&.fr-float-left
		{
			+ .fr-btn-grp.fr-float-right:not(.rte-tab--preview)
			{
				flex: 1 1 0;
				justify-content: flex-end;
			}
		}

		&.rte-tab--beforePreview
		{
			padding-right: @_editorButtonGroupHPadding;
			padding-right: var(--hpadding);

			&.fr-float-left
			{
				// make sure this expands to fill the space so the preview border is correct
				flex-grow: 1;
			}
		}

		// tabify inactive groups
		&.rte-tab--inactive
		{
			border-bottom-width: 1px;
		}

		&.rte-tab--preview
		{
			border-left-width: 1px;
			.border-radius(0 @_editorBorderRadius 0 0);

			// pad the button to make it fill the tab
			// normally padding: 4px, 17px, 0, 22px; margin: 0;
			padding: 0 !important;

			.fr-command.fr-btn
			{
				padding: 4px (@_editorButtonGroupHPadding + 5px) 0px (@_editorButtonGroupHPadding + 5px);
				padding: 4px ~'calc(var(--hpadding) + 5px)' 0px ~'calc(var(--hpadding) + 5px)';
				height: 36px;
				.border-radius(0 @_editorBorderRadius 0 0);

				&:hover
				{
					background: transparent;
				}
			}
		}
	}

	.fr-newline
	{
		margin: 0;
	}

	// 'more' toolbar stuff
	.fr-command.fr-btn.fr-open
	{
		margin-top: @btn-margin;
		padding-bottom: @_more-spacer;
		height: (@btn-height + @_more-spacer);
	}

	.fr-more-toolbar
	{
		position: absolute;
		bottom: 0;

		&[style*="padding-left: 0px"]
		{
			// Padding is used on the more toolbar for button alignment. If it's 0 then we don't want
			// the buttons to be jammed up against the edge.
			padding-left: @_editorButtonGroupHPaddingSmall !important;
		}
	}
}

.fr-separator
{
	float: none;
	display: inline-flex;
	align-items: center;
	justify-content: center;
	background-color: @xf-editorButtonDisabledColor;

	&.fr-vs
	{
		height: @btn-height - @btn-margin * 2;
		margin: 4px;
	}

	.fr-toolbar > &
	{
		// hide separators directly under the toolbar rather in groups - this only happens as
		// a resize quirk
		display: none;
	}
}

// RTE disabled (BB code mode) styling
.fr-box textarea.input
{
	border: none;
	background: none;
}

// some adjustments for different screen resolutions
.fr-box.fr-basic
{
	&[data-size="XL"],
	&[data-size="LG"],
	&[data-size="MD"]
	{
		.fr-btn-grp
		{
			padding-right: @_editorButtonGroupHPadding;
		}
	}

	// shrink the 'Preview' padding at smaller resolutions
	&[data-size="SM"],
	&[data-size="XS"]
	{
		.fr-btn-grp
		{
			--hpadding: @_editorButtonGroupHPaddingSmall;
		}
	}

	// show the 'Preview' text on the preview tab at larger resolutions
	// this width is defined by the width of the page 50px larger than the size at which quick reply turns on the full-size toolbar
	@media (min-width: 1132px)
	{
		&[data-size="XL"] .rte-tab--preview span.fr-sr-only
		{
			font-size: 13px;

			// undo the original class
			position: static;
			width: auto;
			height: auto;
			clip: auto;
			overflow: visible;
			margin: 0;
		}
	}
}



.fr-toolbar,
.fr-popup,
.fr-modal
{
	// make FontAwesome iconography respect btn-font-size
	.fr-command.fr-btn i
	{
		font-size: @xf-editorButtonSize;
	}

	// improve positioning of FA buttons
	.fr-tabs .fr-command.fr-btn i
	{
		margin: ((@popup-tab-button-height - @popup-btn-svg-size) / 2) ((@popup-tab-button-width - @popup-btn-svg-size) / 2);
	}

	.fr-command.fr-btn svg path
	{
		fill: currentColor;
		.m-transition(none);
	}

	// adjust separator height in this scenario to match button height
	.fr-tabs .fr-separator.fr-vs
	{
		margin-top: 2px;
		margin-bottom: 2px;
	}

	// some elements briefly flash through dropdowns on transition
	z-index: 3;
}

.fr-command.fr-btn + .fr-dropdown-menu .fr-dropdown-wrapper .fr-dropdown-content
{
	ul.fr-dropdown-list li a i
	{
		font-size: @xf-editorButtonSize;
		margin: 8px 7px;
	}
}

// setup visuals in the editor match visuals in messages
.fr-view
{
	img.fr-draggable:not(.smilie),
	.bbImage
	{
		max-width: 100%;
		height: auto;
	}

	.fr-video
	{
		position: relative;

		video
		{
			width: 560px;
			max-width: 100%;
		}
	}

	.fr-audio
	{
		-webkit-user-select: none;
		-moz-user-select: none;
		-ms-user-select: none;
		user-select: none;

		audio
		{
			width: 560px;
			max-width: 100%;
		}
	}

	p
	{
		margin-bottom: 0;
		margin-top: 0;
	}

	&.fr-element
	{
		.fr-disabled
		{
			.xf-inputDisabled() !important;
		}

		@attach-margin: @xf-bbCodeImgFloatMargin;
		@attach-margin-after: @xf-bbCodeImgFloatMarginAfter;

		img.fr-dii
		{
			display: inline-block;
			float: none;
			margin: 0;
			max-width: 100%;

			&.fr-fil
			{
				float: left;
				margin: @attach-margin @attach-margin-after @attach-margin-after 0;
				max-width: calc(~'100% - @{attach-margin}');
			}

			&.fr-fir
			{
				float: right;
				margin: @attach-margin 0 @attach-margin-after @attach-margin-after;
				max-width: calc(~'100% - @{attach-margin}');
			}
		}

		.fr-video.fr-dvi
		{
			display: inline-block;
			float: none;
			margin-left: @attach-margin;
			margin-right: @attach-margin;
			max-width: calc(~'100% - (2 * @{attach-margin})');
			outline: @xf-borderSize solid @xf-borderColorLight;

			&.fr-fvl
			{
				float: left;
				margin: @attach-margin @attach-margin-after @attach-margin-after 0;
				max-width: calc(~'100% - @{attach-margin}');
			}

			&.fr-fvr
			{
				float: right;
				margin: @attach-margin 0 @attach-margin-after @attach-margin-after;
				max-width: calc(~'100% - @{attach-margin}');
			}
		}
	}

	.m-tableBase();

	h2,
	h3,
	h4
	{
		margin: .5em 0;
		clear: both;
	}

	h2 { font-size: @xf-fontSizeLargest; }
	h3 { font-size: @xf-fontSizeLarger; }
	h4 { font-size: @xf-fontSizeLarge; }

	hr
	{
		border: none;
		border-top: @xf-borderSize solid @xf-borderColorHeavy;
		clear: both;
	}

	// quote tag emulation
	blockquote
	{
		.xf-bbCodeBlock();
		margin: .5em 0;
		padding: @xf-paddingMedium @xf-paddingLarge;
		font-size: @xf-fontSizeSmall;
		display: flow-root;

		.m-tableBase();

		&:first-child
		{
			margin-top: 0;
		}

		&:last-child
		{
			margin-bottom: 0;
		}

		&[data-quote]
		{
			&:before
			{
				display: block;
				content: attr(data-quote) "{$xf.language.label_separator}";
				.xf-bbCodeBlockTitle();
				padding: @xf-paddingMedium @xf-paddingLarge;
				margin: -@xf-paddingMedium -@xf-paddingLarge @xf-paddingMedium -@xf-paddingLarge;
				// this margin combination makes the attribution take the full width and have bottom padding
			}
		}
	}
}

// try to make Froala inputs look like ours
.fr-popup
{
	.fr-input-line
	{
		padding: 18px 0 8px;

		input[type="text"],
		textarea
		{
			.xf-input();
			margin: 0;
			line-height: @xf-lineHeightDefault;
			.m-transition(background, color;);
			height: auto;

			&:hover
			{
				.xf-input(border);
			}

			&:focus
			{
				.xf-input(border);
				.xf-input(padding);
				.xf-inputFocus();
			}

			.m-inputZoomFix();
		}

		input + label,
		textarea + label
		{
			line-height: 1.2;
			font-size: 12px;
			color: fade(xf-default(@xf-input--color, @xf-textColor), 40%);
			background: transparent;
			top: 28px;
		}

		input.fr-not-empty + label,
		textarea.fr-not-empty + label
		{
			color: @xf-textColorMuted;
			top: 2px;
		}
	}

	.fr-action-buttons
	{
		height: auto;
		.m-frCommandStyle();
	}

	// fix FA selected color indicator
	.fr-color-set > span .fr-selected-color
	{
		.m-faBase();
	}
}

.fr-quick-insert
{
	padding-right: 0;
	margin-left: (@editor-padding / 2);

	// bring this into our z-index levels
	z-index: @zIndex-2;
}

// this toolbar is redundant and annoying
.fr-second-toolbar
{
	display: none;
}

.m-frCommandStyle()
{
	button.fr-command
	{
		.m-buttonBase();
		.xf-buttonPrimary();
		.m-buttonBlockColorVariationSimple(xf-default(@xf-buttonPrimary--background-color, transparent));

		height: auto;
		min-width: 0;
		line-height: @xf-lineHeightDefault;

		&:hover,
		&:active,
		&:focus
		{
			// overriding Froala's hover
			color: @xf-buttonPrimary--color;
		}
	}
}

// Fix for broken CSS in ui/popup.scss, plugin/image.scss, plugin/video.scss
// See: https://github.com/froala/wysiwyg-editor/issues/3878
.fr-popup textarea { resize: none; }

.fr-image-resizer
{
	&.fr-active { display: block; }

	.fr-handler
	{
		&.fr-hnw { cursor: nw-resize; }
		&.fr-hne { cursor: ne-resize; }
		&.fr-hsw { cursor: sw-resize; }
		&.fr-hse { cursor: se-resize; }
	}
}

.fr-box .fr-video-resizer
{
	&.fr-active { display: block; }

	.fr-handler
	{
		&.fr-hnw { cursor: nw-resize; }
		&.fr-hne { cursor: ne-resize; }
		&.fr-hsw { cursor: sw-resize; }
		&.fr-hse { cursor: se-resize; }
	}
}

// #### Smilies, emoji and GIF popup

@_menu-padding: @xf-paddingMedium;
@_menu-padding-large: @xf-paddingLarge;

.menu--emoji
{
	width: 412px;
}

.menu--gif
{
	width: 500px;
}

.menu--emoji,
.menu--gif
{
	max-width: calc(~'100% - @{xf-pageEdgeSpacer}');

	.menu-content
	{
		position: relative;
	}

	.menu-scroller
	{
		max-height: 250px;
		border-top: 0;
	}

	.menu-row
	{
		padding: @_menu-padding @_menu-padding;

		&.menu-row--insertedMessage
		{
			.m-hiddenEl(true);
			position: absolute;
			top: 0;
			left: 0;
			right: 0;
			border-bottom: @xf-borderSize solid @xf-borderColorLight;
		}

		&.menu-row--search
		{
			border-bottom: @xf-borderSize solid @xf-borderColor;
		}
	}

	.menu-emojiInsertedMessage
	{
		display: flex;
		align-items: center;
		justify-content: center;
		min-height: 35px;
		font-size: @xf-fontSizeNormal;

		img { max-height: 32px; }
		span { margin-left: .5em }
	}

	.menu-header
	{
		background: none;
		.xf-formSectionHeader();
		background-color: @xf-contentBg;
		z-index: @zIndex-1;
		font-size: @xf-fontSizeNormal;
		position: -webkit-sticky;
		position: sticky;
		padding: @_menu-padding @_menu-padding-large;
		top: 0;
	}

	.block-body--emoji
	{
		border-top: @xf-borderSize solid @xf-borderColorLight;
	}

	.is-hidden
	{
		display: none;
	}
}

.emojiList
{
	.m-listPlain();

	display: flex;
	flex-wrap: wrap;
	justify-content: flex-start;

	margin-right: -3px;
	margin-bottom: -3px;

	> li
	{
		min-width: 32px;
		margin-right: 3px;
		margin-bottom: 3px;

		.border-radius(@xf-borderRadiusMedium);
		cursor: pointer;

		&:hover,
		&:focus
		{
			background-color: @xf-paletteColor2;
		}

		a
		{
			min-width: 32px;
			height: 32px;
			font-size: 24px;

			display: flex;
			justify-content: center;
			align-items: center;
			cursor: pointer;
			overflow: hidden;

			&:hover,
			&:focus
			{
				text-decoration: none;
			}

			img
			{
				max-height: 32px;
			}

			.smilie.smilie--emoji
			{
				width: 22px;
			}

			.smilie--lazyLoad
			{
				visibility: hidden;
			}
		}
	}
}

// ### Editor placeholder system (where the editor is hidden until clicked)

.editorPlaceholder
{
	.is-hidden
	{
		display: none;
	}

	cursor: text;

	.editorPlaceholder-placeholder
	{
		.input
		{
			padding: @xf-paddingLarge;

			span
			{
				&:before
				{
					.m-faBase();
					.m-faContent(@fa-var-pen);
				}
			}
		}
	}
}

// ### Editor draft saving indicator

.editorDraftIndicator
{
	.m-transition();
	opacity: 0;
	position: absolute;
	bottom: 6px;
	right: 8px;
	width: 8px;
	height: 8px;
	border-radius: 4px;
	background: rgb(127, 185, 0);

	&.is-active
	{
		opacity: 1;
	}
}

.xfPreview
{
	.m-clearFix();
}

/***** froala.less *****/

/***** variables.less *****/


// Theme Name.
@theme: 'theme';

// Generic.
@white: #FFF;
@light-black: #333333;
@black: #000;
@gray: #CCCCCC;
@dark-grey: #999999;
@font-family: Arial, Helvetica, sans-serif;
@border-radius: 2px;
@transition-timing: 0.2s ease 0s;
@bg-color: #f5f5f5;

// UI colors
@ui-color: #0098f7;
@ui-text: #222222;
@ui-hover-light-color: mix(@white, #999, 90%);
@ui-hover-color: mix(@white, #999, 80%);
@ui-focused-color: mix(@white, #999, 60%);
@ui-disabled-color: mix(@white, #000, 74%);
@ui-active-color: #d6d6d6;
@ui-bg: @white;
@ui-font-size: 14px;
@ui-border-color: @ui-text;
@ui-border-top: 5px solid @ui-border-color;
@ui-border-hover-color:#515151;
@ui-bg-color: #efefef;
@ui-svg-size: 24px;
@ui-box-shadow: 0 3px 1px -2px rgba(0,0,0,.2), 0 2px 2px 0 rgba(0,0,0,.14), 0 1px 5px 0 rgba(0,0,0,.12);
@ui-bg-color-more: @bg-color;

// Separator
@separator-size: 1px;
@separator-color: mix(@white, #999, 80%);
@separator-margin: 8px 4px;

// Toolbar
@toolbar-transition-timing: 0.5s;
@toolbar-newline-margin: 9px;
@toolbar-newline-height: 1px;
@toolbar-newline-color: @ui-bg-color;
@btn-more-open-margin-top: 10px;
@btn-more-open-margin-bottom: -1px;
@btn-size: 36px;

// Logo
@logo-svg-height: 20px;
@logo-svg-width: 47px;
@logo-svg-margin: 7px 0;
@logo-transition-timing: 0.3s;
@logo-span-padding: 11px 5px 10px 15px;
@logo-span-font-size: 12px;
@logo-color: #b1b2b7;

// Screen sizes.
@screen-xs: 480px;
@screen-sm: 768px;
@screen-md: 992px;
@screen-lg: 1200px;
@screen-xs-max: (@screen-sm - 1);
@screen-sm-max: (@screen-md - 1);
@screen-md-max: (@screen-lg - 1);
@screen-lg-max: 'auto';

// Tooltip
@tooltip-bg: @ui-text;
@tooltip-text: @white;
@tooltip-font-size: 11px;
@tooltip-line-height: 22px;

// Editor properties.
@editor-padding: 20px;
@editor-bg: @white;
@editor-font-family: sans-serif;
@editor-font-color: #414141;
@editor-font-size: 14px;
@editor-line-height: 1.6;
@editor-shadow-level: 1;
@editor-border: 1px solid @gray;
@editor-border-radius: 10px;
@editor-align: left;

// Text selection colors.
@selection-bg: rgba(181, 214, 253, 0.8);
@selection-text: #000;

// Placeholder properties.
@placeholder-size: @editor-font-size;
@placeholder-font-family: @editor-font-family;
@placeholder-color: #AAA;

// Button colors.
@btn-text: @light-black;
@btn-hover-text: @light-black;
@btn-hover-bg: #ebebeb;

@btn-active-text: @ui-color;
@btn-active-bg: @ui-active-color;
@btn-active-hover-text: @btn-active-text;

@btn-selected-text: @btn-text;
@btn-selected-bg: @ui-focused-color;

@btn-disabled-color: @ui-disabled-color;
@btn-disabled-opacity: 0.3;

// Button size.
@btn-width: 38px;
@btn-height: 40px;
@btn-margin: 4px;
@btn-font-size: 24px;
@btn-more-toolbar-height: 34px;
@btn-border-radius: 4px;
@btn-dropdown-border-radius: 0 @btn-border-radius @btn-border-radius 0;
@btn-hover-border-radius: @btn-border-radius 0 0 @btn-border-radius;
@btn-svg-size: @ui-svg-size;
@btn-tab-border-radius: 6px 6px 0 0;

// Second toolbar.
@more-toolbar-margin: 0 17px 0 12px;
@more-toolbar-margin-sm: 0 7px 0 6px;
@more-toolbar-btn-height: @btn-height + (@btn-margin * 2);

// Image.
@image-margin: 5px;
@image-padding: 0 1px;

// Image and Video
@handler-size: 12px;
@handler-size-lg: 10px;

// Code View
@code-view-bg: @white;
@code-view-text: @black;

// Table properties.
@table-border: 1px solid #DDD;
@table-resizer: 1px solid @ui-color;

// Insert table grid.
@insert-table-grid: @table-border;

// Quick insert.
@floating-btn-bg: @white;
@floating-btn-text: @light-black;
@floating-btn-hover-bg: @btn-hover-bg;
@floating-btn-hover-text: @floating-btn-text;
@floating-btn-size: 40px;
@floating-btn-font-size: 14px;
@floating-btn-border: none;
@floating-svg-btn-size: @ui-svg-size;
@floating-svg-btn-margin: 8px;
@floating-btn-padding: 6px 10px 10px 10px;
@floating-btn-box-shadow: @ui-box-shadow;

@quick-insert-padding-right: 10px;

// List menu.
@dropdown-arrow-width: 4px;
@dropdown-max-height: 275px;
@dropdown-options-width: 16px;
@dropdown-options-margin-left: -5px;
@dropdown-options-border-left: solid 1px #FAFAFA;
@dropdown-transition-timing: 0.3s;
@dropdown-border-radius: 4px;
@dropdown-list-padding: 8px 0;
@dropdown-list-min-width: 72px;
@dropdown-list-item-font-size: 15px;
@dropdown-menu-box-shadow: @ui-box-shadow;

// Image manager.
@modal-bg: @white;
@modal-overlay-color: @black;
@modal-head-height: 56px;
@modal-head-padding: 0 10px;
@modal-btn-padding: (@floating-btn-size - @floating-svg-btn-size) / 2;
@modal-btn-margin-top: 10px;
@modal-tags-border-radius: 32px;
@modal-tags-padding: 0 20px;
@modal-link-tags-padding: 6px 12px;
@modal-link-tags-margin: 8px 0 8px 8px;
@modal-selected-tag-bg: #EcF5Ff;
@modal-wrapper-border-radius: 10px;
@modal-wrapper-margin-lg: 20px auto;
@modal-wrapper-margin-md: 50px auto;
@modal-wrapper-margin-sm: 30px auto;
@modal-wrapper-box-shadow: 0 3px 5px -1px rgba(0,0,0,.2), 0 6px 10px 0 rgba(0,0,0,.14), 0 1px 18px 0 rgba(0,0,0,.12);
@modal-head-min-height: 42px;
@modal-close-margin: 10px;
@modal-heading-font-size: 20px;
@modal-heading-padding: 19px 10px;
@modal-body-min-width: 150px;
@modal-body-btn-height: @btn-size;
@modal-body-btn-padding: 10px;
@modal-body-padding-bottom: 20px;
@modal-head-line-height: 18px;
@modal-wrapper-min-width: 300px;
@modal-overlay-opacity: 0.5;

// Destroy buttons (delete in image manager).
@modal-destroy-btn-bg: #B8312F;
@modal-destroy-btn-text: @white;
@modal-destroy-btn-hover-bg: mix(contrast(@modal-destroy-btn-bg, @black, @white), @modal-destroy-btn-bg, 10%);
@modal-destroy-btn-hover-text: @white;

// Popups
@popup-layer-width: 260px;
@popup-border-radius: 6px;
@popup-min-width: 276px;
@popup-container-max-height: 200px;
@popup-icon-size: @ui-svg-size;
@popup-tab-button-width: 46px;
@popup-tab-button-height: @btn-height;
@popup-box-shadow: 0 3px 5px -1px rgba(0,0,0,.2), 0 6px 10px 0 rgba(0,0,0,.14), 0 1px 18px 0 rgba(0,0,0,.12);
@popup-action-btn-spacing: 10px;
@popup-margin-top: @popup-action-btn-spacing;
@popup-layer-margin: 20px;
@popup-action-button-font-size: 16px;
@popup-only-btn-padding: 6px 10px;
@popup-btn-svg-size: @ui-svg-size;
@popup-border-margin: 20px;
@popup-border-padding: 20px;
@popup-icon-font-size: 20px;
@popup-padding: 5px;
@popup-icon-padding: 6px;
@popup-emoticon-container-width: 368px;
@popup-sc-container-width: @popup-emoticon-container-width;
@popup-fa-container-width: 506px;
@popup-sm-ie-width: 236px;
@popup-fa-icon-size: 18px;
@popup-fa-icon-padding: 8px;
@popup-fa-icon-margin: 6px;
@popup-fa-icon-font-size: 16px;
@popup-fa-grid-icon-size: 45px;

// Inputs.
@input-border-color: @dark-grey;
@input-label-color: mix(@white, #000, 50%);
@input-line-padding: 15px 0;
@input-border-radius: 2px;
@input-border-width: 1px;
@input-focus-border-width: 2px;
@input-padding-left-right: 12px;
@input-padding-top-bottom: 4px;
@input-padding: @input-padding-top-bottom @input-padding-left-right;
@input-focus-padding: (@input-padding-top-bottom - @input-focus-border-width + @input-border-width) (@input-padding-left-right - @input-focus-border-width + @input-border-width);
@input-height: 46px;
@input-label-font-size: 14px;
@input-label-font-size-after: 11px;
@input-label-top: 29px;
@input-label-top-after: 9px;
@input-label-left: 12px;
@input-label-left-after: 4px;
@input-label-padding: 4px;
@input-margin-bottom: 1px;

// Checkbox
@checkbox-size: 18px;
@checkbox-padding: 10px;
@checkbox-margin: 2px;
@checbox-svg-size: 10px;
@checkbox-line-margin-top: 10px;
@checkbox-line-font-size: 14px;
@checkbox-line-label-margin: 0 5px;
@checkbox-line-height: 1.4px;
@checbox-active-bg: #EcF5Ff;
@checkbox-opacity: 0.8;

// Quote.
@blockquote-level1-color: #5E35B1;
@blockquote-level2-color: #00BCD4;
@blockquote-level3-color: #43A047;

// Char counter.
@char-counter-text-color: @dark-grey;
@char-counter-font-size: 14px;
@char-counter-font-family: sans-serif;
@char-counter-padding: 10px;

@drag-helper-border: solid 1px @ui-color;
@drag-helper-bg: @ui-color;

// Document ready.
@document-ready-padding: 30px;
@document-ready-bg-color: @ui-bg-color;

// Colors
@color-input-line-padding: 15px 0 0;
@color-action-button-padding: 17px 0 0;
@color-span-size: 32px;
@color-remove-svg-margin: 4px;
@color-line-height: 32px;
@color-font-size: 13px;

// Emoticons
@emoticon-tab-padding: 6px;
@emoticon-tab-btn-padding: 0 0 0 14px;

// Image Manager
@image-manager-list-margin: 0 20px;
@image-manager-not-available-padding: 12px 0;

//Special Character
@special-char-btn-padding: 10px 15px;



// ################# CUSTOM OVERRIDES ################
{{ include('editor_override.less') }}

@popup-bg: @xf-nlEditorPopupBg;
@popup-option-color: @xf-nlEditorPopupOption;
@popup-option-hover-color: @xf-nlEditorPopupOptionHover;
@popup-option-hover-bg: @xf-nlEditorPopupOptionHoverBg;
@popup-option-active-color: @xf-nlEditorPopupOptionSelected;
@popup-option-active-bg: @xf-nlEditorPopupOptionSelectedBg;

/***** mixins.less *****/

.resize(@val) {
  resize: @val;
  -moz-resize: @val;
  -webkit-resize: @val;
}

.opacity(@opacity: 0.5) {
	-webkit-opacity: 	@opacity;
	-moz-opacity: 		@opacity;
	opacity: 		@opacity;
  -ms-filter: "progid:DXImageTransform.Microsoft.Alpha(Opacity=0)";
}

.transition(@transition...) {
	-webkit-transition: @transition;
	-moz-transition:    @transition;
	-ms-transition:     @transition;
	-o-transition:      @transition;
}

.transform(@string) {
	-webkit-transform: @string;
	-moz-transform: 	 @string;
	-ms-transform: 		 @string;
	-o-transform: 		 @string;
}

.box-sizing(@type: border-box) {
	-webkit-box-sizing: @type;
	-moz-box-sizing:    @type;
	box-sizing:         @type;
}

.border-radius(@radius: 0) {
  border-radius: @radius;
  -moz-border-radius: @radius;
  -webkit-border-radius: @radius;

  -moz-background-clip:    padding;
	-webkit-background-clip: padding-box;
	background-clip:         padding-box;
}

.user-select(@select) {
  user-select: @select;
  -o-user-select:@select;
  -moz-user-select: @select;
  -khtml-user-select: @select;
  -webkit-user-select: @select;
  -ms-user-select: @select;
}

.box-shadow(@shadow) {
  -webkit-box-shadow: @shadow;
  -moz-box-shadow: @shadow;
  box-shadow: @shadow;
}

.fr-clearfix {
  &::after {
    clear: both;
    display: block;
    content: "";
    height: 0;
  }
}

.fr-clearfix {
  &::after {
    clear: both;
    display: block;
    content: "";
    height: 0;
  }
}

.column-count(@count) {
  column-count: @count;
  -moz-column-count: @count;
  -webkit-column-count: @count;
}

.column-gap(@gap) {
  column-gap: @gap;
  -moz-column-gap: @gap;
  -webkit-column-gap: @gap;
}

.animation(@val) {
	-webkit-animation: @val;
  -moz-animation: @val;
  -o-animation: @val;
  animation: @val;
}

.handler-size(@size) {
  .fr-handler {
    width: @size;
    height: @size;

    &.fr-hnw {
      left: (-@size / 2);
      top: (-@size / 2);
    }

    &.fr-hne {
      right: (-@size / 2);
      top: (-@size / 2);
    }

    &.fr-hsw {
      left: (-@size / 2);
      bottom: (-@size / 2);
    }

    &.fr-hse {
      right: (-@size / 2);
      bottom: (-@size / 2);
    }
  }
}

.font-smoothing() {
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

.fr-hide-by-clipping {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0,0,0,0);
  border: 0;
}

.fr-hide-by-clipping {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0,0,0,0);
  border: 0;
}

.display-inline-flex() {

  display: -webkit-inline-flex;
  display: -ms-inline-flexbox;
  display: inline-flex;
}

.keyframes(@animation-name, @rules) {
  @-webkit-keyframes @animation-name {
    @rules();
  }
  @-moz-keyframes @animation-name {
    @rules();
  }
  @-o-keyframes @animation-name {
    @rules();
  }
  @keyframes @animation-name {
    @rules();
  }
}

/***** core/element.less *****/

.fr-element, .fr-element:focus {
  outline: 0 solid transparent;
}

.fr-view.fr-element-scroll-visible {
  overflow-x: visible !important;
}

.fr-box.fr-basic {
  .border-radius(@editor-border-radius);

  .fr-element {
    font-family: @editor-font-family;
    color: @editor-font-color;
    font-size: @editor-font-size;
    line-height: @editor-line-height;

    padding: @editor-padding;
    .box-sizing(border-box);
    overflow-x: auto;
    min-height: (20px + (2 * @editor-padding));
    text-align: @editor-align;
  }

  &.fr-rtl {
    .fr-element {
      text-align: right;
    }
  }
}

.fr-element {
  background: transparent;
  position: relative;
  z-index: 2;

  // CSS rule for iPad not being able to select sometimes.
  -webkit-user-select: auto;

  // Fix bootstrap select.
  a {
    .user-select(auto);
  }

  &.fr-disabled {
    .user-select(none);
  }

  [contenteditable="true"] {
    outline: 0 solid transparent;
  }
}

.fr-box {
  a.fr-floating-btn {
    .box-shadow(@floating-btn-box-shadow);
    .border-radius(100%);
    height: @floating-btn-size;
    width: @floating-btn-size;
    text-align: center;
    background: @floating-btn-bg;
    color: @floating-btn-text;
    .transition(background @transition-timing, color @transition-timing, transform @transition-timing);
    outline: none;
    left: 0;
    top: 0;
    line-height: (@floating-btn-size);
    .transform(scale(0));
    text-align: center;
    display: block;
    .box-sizing(border-box);
    border: @floating-btn-border;

    svg {
      .transition(transform @transition-timing);
      fill: @floating-btn-text;
    }

    i, svg {
      font-size: @floating-btn-font-size;
      line-height: @floating-btn-size;
    }

    &.fr-btn + .fr-btn {
      margin-left: 10px;
    }

    &:hover {
      background: @floating-btn-hover-bg;
      cursor: pointer;

      svg {
        fill: @floating-btn-hover-text;
      }
    }
  }

  .fr-visible {
    a.fr-floating-btn {
      .transform(scale(1));
    }
  }
}



/***** core/iframe.less *****/

iframe.fr-iframe {
  width: 100%;
  border: none;
  position: relative;
  display: block;
  z-index: 2;
  .box-sizing(border-box);
}

/***** core/wrapper.less *****/


.fr-wrapper {
  position: relative;
  z-index: 1;

  .fr-clearfix();

  .fr-placeholder {
    position: absolute;
    font-size: @placeholder-size;
    color: @placeholder-color;
    font-family: @placeholder-font-family;
    z-index: 1;
    display: none;
    top: 0;
    left: 0;
    right: 0;
    overflow: hidden;
  }

  &.show-placeholder {
    .fr-placeholder {
      display: block;
      white-space: nowrap;
      text-overflow: ellipsis;
    }
  }

  ::-moz-selection {
    background: @selection-bg;
    color: @selection-text;
  }

  ::selection {
    background: @selection-bg;
    color: @selection-text;
  }
}

.fr-box.fr-basic {
  .fr-wrapper {
    background: @editor-bg;
    border: @editor-border;
    border-bottom-color: @ui-bg-color;
    top: 0;
    left: 0;
  }
}

.fr-box.fr-basic {
  &.fr-top .fr-wrapper {
    border-top: 0;
  }

  &.fr-bottom .fr-wrapper {
    border-bottom: 0;
    .border-radius(@editor-border-radius @editor-border-radius 0 0);
  }
}

@media (min-width: @screen-md) {
  .fr-box.fr-document {
    min-width: 21cm;

    .fr-wrapper {
      text-align: left;
      padding: @document-ready-padding;
      min-width: 21cm;
      background: @document-ready-bg-color;

      .fr-element {
        text-align: left;
        background: @white;
        width: 21cm;
        margin: auto;
        min-height: 26cm !important;
        padding: 1cm 2cm;
        overflow: visible;
        z-index: auto;

        hr {
          margin-left: -2cm;
          margin-right: -2cm;
          background: @document-ready-bg-color;
          height: 1cm;
          outline: none;
          border: none;
        }

        img {
          z-index: 1;
        }
      }
    }
  }
}


/***** tooltip.less *****/

.fr-tooltip {
  position: absolute;
  top: 0;
  left: 0;
  padding: 0 8px;
  .border-radius(@border-radius);
  background: @tooltip-bg;
  color: @tooltip-text;
  font-size: @tooltip-font-size;
  line-height: @tooltip-line-height;
  font-family: @font-family;
  .transition(opacity @transition-timing);
  .opacity(0);
  left: -3000px;
  .user-select(none);
  z-index: 2147483647;
  text-rendering: optimizelegibility;
  .font-smoothing();

  &.fr-visible {
    .opacity(1);
  }
}

/***** ui/buttons.less *****/

// Command button.

.fr-toolbar, .fr-popup, .fr-modal {
  .fr-btn-wrap {
    float: left;
    white-space: nowrap;
    position: relative;

    &.fr-hidden {
      display: none;
    }
  }

  .fr-command.fr-btn {
    background: transparent;
    color: @btn-text;
  	-moz-outline: 0;
  	outline: none;
    border: 0;
    line-height: 1;
  	cursor: pointer;
    text-align: left;
    margin: @btn-margin (@btn-margin / 2);
    padding: 0;
    .transition(all @toolbar-transition-timing);
    .border-radius(@btn-border-radius);
    z-index: 2;
    position: relative;
    .box-sizing(border-box);
    text-decoration: none;
    .user-select(none);
    float: left;
    height: @btn-height;

    &.fr-dropdown.fr-options {
      .border-radius(@btn-dropdown-border-radius);
    }

    &.fr-btn-hover {
      .border-radius(@btn-hover-border-radius);
    }

    &::-moz-focus-inner {
      border: 0;
      padding: 0
    }

    &.fr-btn-text {
      width: auto;
    }

    i, svg {
      display: block;
      text-align: center;
      float: none;
      margin: ((@btn-height - @btn-svg-size) / 2) ((@btn-width - @btn-svg-size) / 2);
      width: @btn-svg-size;
    }

    svg.fr-svg {
      height: @btn-svg-size;
    }

    svg path {
      .transition(all @toolbar-transition-timing);
      fill: @btn-text;
    }

    // Used for accessibility instead of aria-label.
    span.fr-sr-only {
      .fr-hide-by-clipping();
    }

    span {
      font-size: @ui-font-size;
      display: block;
      line-height:  (@ui-font-size + 3px);
      min-width: (@btn-width - 2 * @btn-margin);
      float: left;
      text-overflow: ellipsis;
      overflow: hidden;
      white-space: nowrap;
      height: (@ui-font-size + 3px);
      font-weight: bold;
      padding: 0 @btn-margin;
    }

    img {
      margin: ((@btn-height - @btn-font-size) / 2) ((@btn-width - @btn-font-size) / 2);
      width: @btn-font-size;
    }

    &.fr-btn-active-popup {
      background: @btn-active-bg;
    }

    &.fr-dropdown {
      &.fr-selection {

        span {
          font-weight: normal;
        }
      }

      i, span, img, svg {
        margin-left: (((@btn-width - @btn-svg-size) / 2) - @dropdown-arrow-width);
        margin-right: (((@btn-width - @btn-svg-size) / 2) + @dropdown-arrow-width);
      }

      &:after {
        position: absolute;
        width: 0;
        height: 0;
        border-left: @dropdown-arrow-width solid transparent;
        border-right: @dropdown-arrow-width solid transparent;
        border-top: @dropdown-arrow-width solid @btn-text;
        right: ceil((((@btn-width - @btn-svg-size) / 2 - @dropdown-arrow-width) / 2));
        top: ((@btn-height - @dropdown-arrow-width) / 2);
        .transition(all @dropdown-transition-timing);
        content: "";
      }

      // Dropdown is visible.
      &.fr-active {
        fill: @btn-text;
        background: @btn-active-bg;
        .transition(@toolbar-transition-timing ease);

        &:hover {
          background: @btn-hover-bg;
          fill: @btn-selected-text;

          &::after {
            border-top-color: @btn-selected-text;
          }
        }

        &:after {
          border-top: 0;
          border-bottom: 4px solid @ui-text;
        }
      }
    }

    &.fr-disabled {
      color: @btn-disabled-color;
      cursor: default;
      .opacity(@btn-disabled-opacity);

      &::after {
        border-top-color: @btn-disabled-color;
      }
    }

    &.fr-hidden {
      display: none;
    }
  }

  .fr-tabs {
    .fr-command.fr-btn {
      margin: 0;
      width: @popup-tab-button-width;
      height: @popup-tab-button-height;
      .border-radius(0);

      &:not(:hover):not(:focus) {
        &.fr-active, &.fr-active-tab {
          background: @ui-bg;
        }
      }

      span {
        height: (@btn-font-size + 3);
      }

      img, svg {
        margin: ((@popup-tab-button-height - @popup-btn-svg-size) / 2) ((@popup-tab-button-width - @popup-btn-svg-size) / 2);
        width: @popup-btn-svg-size;
        height: @popup-btn-svg-size;
      }
    }
  }

  .fr-btn-grp, .fr-more-toolbar, .fr-buttons:not(.fr-tabs) {
    .fr-command.fr-btn {
      &.fr-active:not(.fr-dropdown) {
        svg path {
          fill: @btn-active-text;
        }
      }
    }
  }

  &.fr-disabled {
    .fr-btn, .fr-btn.fr-active {
      color: @btn-disabled-color;
      .opacity(@btn-disabled-opacity);

      &.fr-dropdown::after {
        border-top-color: @btn-disabled-color;
      }
    }
  }

  &.fr-rtl {
    .fr-btn-grp {
      &.fr-float-left {
        float: right;
      }

      &.fr-float-right {
        float: left;
      }
    }
    .fr-command.fr-btn, .fr-btn-wrap {
      float: right;

      &.fr-dropdown.fr-options {
        .border-radius(@btn-hover-border-radius);
      }

      &.fr-btn-hover {
        .border-radius(@btn-dropdown-border-radius);
      }
    }
  }
}

.fr-toolbar.fr-inline {
  > .fr-command.fr-btn:not(.fr-hidden), > .fr-btn-wrap:not(.fr-hidden) {
    .display-inline-flex();
    float: none;
  }
}

.fr-desktop {
  .fr-command {
    // Hover.
    &:hover, &:focus, &.fr-btn-hover, &.fr-expanded {
      outline: 0;
      color: @btn-hover-text;

      &:not(.fr-table-cell) {
        background: @btn-hover-bg;
      }

      &::after {
        border-top-color: @btn-hover-text;
      }
    }

    // Button is selected.
    &.fr-selected:not(.fr-table-cell), &:active {
      color: @btn-selected-text;
      background: @btn-selected-bg;
    }

    &.fr-active {
      &:hover, &:focus, &.fr-btn-hover, &.fr-expanded {
        background: @btn-hover-bg;
      }

      &:active {
        background: @btn-active-bg;
      }
    }

    &.fr-disabled {
      &:hover, &:focus, &.fr-selected {
        background: transparent;
      }
    }
  }

  &.fr-disabled {
    .fr-command {
      &:hover, &:focus, &.fr-selected {
        background: transparent;
      }
    }
  }
}

.fr-toolbar.fr-mobile, .fr-popup.fr-mobile {
  .fr-command.fr-blink {
    background: @btn-active-bg;
  }
}



/***** ui/dropdown.less *****/

.fr-command.fr-btn {
  &.fr-options {
    width: @dropdown-options-width;
    margin-left: @dropdown-options-margin-left;

    &.fr-btn-hover, &:hover, &:focus {
      border-left: @dropdown-options-border-left;
      .transition(border-left 0s, background-color 0.5s);
    }
  }

  + .fr-dropdown-menu {
    background: @popup-bg;
	color: @popup-option-color;
    display: inline-block;
    position: absolute;
    right: auto;
    bottom: auto;
    height: auto;
    z-index: 4;
    .border-radius(@dropdown-border-radius);
    -webkit-overflow-scrolling: touch;
    overflow: hidden;
    zoom: 1;
    .box-shadow(@dropdown-menu-box-shadow);

    &.test-height {
      .fr-dropdown-wrapper {
        .transition(none);
        height: auto;
        max-height: @dropdown-max-height;
      }
    }

    .fr-dropdown-wrapper {
      padding: 0;
      margin: auto;
      display: inline-block;
      text-align: left;
      position: relative;
      .box-sizing(border-box);
      .transition(height @dropdown-transition-timing);
      margin-top: 0;
      float: left;
      height: 0;
      margin-top: 0 !important;

      .fr-dropdown-content {
        position: relative;

        ul.fr-dropdown-list {
          list-style-type: none;
          margin: 0;
          padding: @dropdown-list-padding;
          min-width: @dropdown-list-min-width;

          li {
            padding: 0;
            margin: 0;
            font-size: @dropdown-list-item-font-size;

            a {
              padding: 0 (((@dropdown-list-min-width - @floating-svg-btn-size) / 2) - @btn-margin);
              line-height: 200%;
              display: flex;
              cursor: pointer;
              white-space: nowrap;
              color: inherit;
              text-decoration: none;
              .border-radius(0);

              svg {
                width: @floating-svg-btn-size;
                height: @floating-svg-btn-size;
                margin: (@btn-margin - 1) @btn-margin;

                path {
                  fill: @btn-text;
                }
              }

			  &:hover {
			    background: @popup-option-hover-bg;
				color: @popup-option-hover-color;
			  }

              &.fr-active {
                background: @popup-option-active-bg;
				color: @popup-option-active-color;
              }

              &.fr-disabled {
                color: @btn-disabled-color;
                cursor: default;
              }

              .fr-shortcut {
                margin-left: 20px;
                font-weight: bold;
                -webkit-opacity: 0.75;
                -moz-opacity: 0.75;
                opacity: 0.75;
              }
            }
          }
        }
      }
    }
  }

  &.fr-active {
    + .fr-dropdown-menu {
      display: inline-block;
      .box-shadow(@dropdown-menu-box-shadow);
    }
  }
}

.fr-bottom > .fr-command.fr-btn {
  + .fr-dropdown-menu {
    .border-radius(@border-radius @border-radius 0 0);
  }
}

.fr-toolbar, .fr-popup {
  &.fr-rtl {
    .fr-dropdown-wrapper {
      text-align: right !important;
    }
  }
}


/***** ui/modal.less *****/

body.fr-prevent-scroll {
  overflow: hidden;

  &.fr-mobile {
    position: fixed;
    -webkit-overflow-scrolling: touch;
  }
}

.fr-modal {
  color: @ui-text;
  font-family: @font-family;
  position: fixed;
  overflow-x: auto;
  overflow-y: scroll;
  top: 0;
  left: 0;
  bottom: 0;
  right: 0;
  width: 100%;
  z-index: 2147483640;
  text-rendering: optimizelegibility;
  .font-smoothing();
  text-align: center;
  line-height: 1.2;

  &.fr-middle {
    .fr-modal-wrapper {
      margin-top: 0;
      margin-bottom: 0;
      margin-left: auto;
      margin-right: auto;
      top: 50%;
      left: 50%;
      .transform(translate(-50%, -50%));
      position: absolute;
    }
  }

  .fr-modal-wrapper {
    .border-radius(@modal-wrapper-border-radius);
    background-clip: padding-box;
    margin: @modal-wrapper-margin-lg;
    display: inline-block;
    background: @modal-bg;
    min-width: @modal-wrapper-min-width;
    .box-shadow(@modal-wrapper-box-shadow);
    border: 0;
    overflow: hidden;
    width: 90%;
    position: relative;

    @media (min-width: @screen-sm) and (max-width: @screen-sm-max) {
      margin: @modal-wrapper-margin-sm;
      width: 70%;
    }

    @media (min-width: @screen-md) {
      margin: @modal-wrapper-margin-md;
      width: 960px;
    }

    .fr-modal-head {
      background: @modal-bg;
      overflow: hidden;
      position: absolute;
      width: 100%;
      min-height: @modal-head-min-height;
      z-index: 3;
      border-bottom: solid @ui-bg-color 1px;
      .transition(all @transition-timing);

      .fr-modal-head-line {
        height: @modal-head-height;
        padding: @modal-head-padding;

      }

      .fr-modal-close {
        margin: @modal-close-margin;
        position: absolute;
        top: 0;
        right: 0;
      }

      h4 {
        font-size: @modal-heading-font-size;
        padding: @modal-heading-padding;
        margin: 0;
        font-weight: 400;
        line-height: @modal-head-line-height;
        display: inline-block;
        float: left;
      }
    }

    div.fr-modal-body {
      height: 100%;
      min-height: @modal-body-min-width;
      overflow-y: auto;
      padding-bottom: @modal-body-padding-bottom;

      &:focus {
        outline: 0;
      }

      button.fr-command {
        height: @modal-body-btn-height;
        line-height: 1;
        color: @ui-color;
        padding: @modal-body-btn-padding;
        cursor: pointer;
        text-decoration: none;
        border: none;
        background: none;
        font-size: 16px;
        outline: none;
        .transition(background @transition-timing);
        .border-radius(@border-radius);

        + button {
          margin-left: 24px;
        }

        &:hover, &:focus {
          background: @btn-hover-bg;
          color: @ui-color;
        }

        &:active {
          background: @btn-active-bg;
          color: @ui-color;
        }
      }

      button::-moz-focus-inner {
        border: 0;
      }
    }
  }
}

.fr-desktop .fr-modal-wrapper {
  .fr-modal-head {
    i:hover {
      background: @ui-hover-color;
    }
  }
}

// Overlay that appears with modal.
.fr-overlay {
  position: fixed;
  top: 0;
  bottom: 0;
  left: 0;
  right: 0;
  background: @modal-overlay-color;
  .opacity(@modal-overlay-opacity);
  z-index: 2147483639;
}
ol.decimal_type { counter-reset: item; }
ol.decimal_type > li{ display: block; }
ol.decimal_type > li:before { content: counters(item, ".") ". "; counter-increment: item; }

/***** ui/popup.less *****/

.fr-popup {
  position: absolute;
  display: none;
  color: @ui-text;
  background: @ui-bg;
  .box-shadow(@popup-box-shadow);
  font-family: @font-family;
  .box-sizing(border-box);
  .user-select(none);
  margin-top: @popup-margin-top;
  z-index: 2147483635;
  text-align: left;
  .border-radius(@popup-border-radius);
  text-rendering: optimizelegibility;
  .font-smoothing();
  line-height: 1.2;

  .fr-icon {
    text-align: center;
    vertical-align: middle;
    font-size: @popup-icon-font-size;
    line-height: 1;
    cursor: pointer;
    font-weight: 400;
    box-sizing: content-box;
    padding: @popup-icon-padding;
  }

  .fr-icon-container {
    padding: @popup-border-padding;
    max-height: @popup-container-max-height;
    overflow: auto;
    .box-sizing(border-box);

    @supports not (-ms-high-contrast: none) { 
      grid-template-columns: repeat(auto-fill, minmax(@btn-size, @btn-size));
      display: grid;
    }

    @media (min-width: @screen-sm) {
      min-width: @popup-min-width; 
    }

    @media screen and (-ms-high-contrast: active), (-ms-high-contrast: none) {
      display: inline-flex;
      -ms-flex-flow: row wrap;
    }

    @media screen and (-ms-high-contrast: active) and (max-width: @screen-sm), (-ms-high-contrast: none) and (max-width: @screen-sm) {
      width: @popup-sm-ie-width;
    }
  }

  .fr-input-focus {
    background: @ui-hover-light-color;
  }

  &.fr-above {
    margin-top: -10px;
    border-top: 0;
  }

  &.fr-active {
    display: block;
  }


  &.fr-hidden {
    display: none !important;
  }

  &.fr-empty {
    display: none !important;
  }

  .fr-hs {
    display: block !important;

    &.fr-hidden {
      display: none !important;
    }
  }

  .fr-input-line {
    position: relative;
    padding: @input-line-padding;

    input[type="text"], input[type="number"], textarea {
      width: 100%;
      margin-bottom: @input-margin-bottom;
      .border-radius(@input-border-radius);
      border: solid @input-border-width @input-border-color;
      color: @ui-text;
      font-size: @input-label-font-size;
      background: @ui-bg;
      position: relative;
      z-index: 2;
      padding: @input-padding;
      .box-sizing(border-box);
      .transition(border @toolbar-transition-timing, padding @toolbar-transition-timing);

      &:hover {
        border: solid @input-border-width @ui-border-hover-color;
      }

      &:focus {
        border: solid @input-focus-border-width @ui-color;
        padding: @input-focus-padding;
      }
    }

    input[type="text"], input[type="number"] {
      height: @input-height;
    }

    input + label, textarea + label {
      position: absolute;
      top: @input-label-top;
      left: @input-label-left;
      font-size: @input-label-font-size;
      color: grey;
      .transition(all @toolbar-transition-timing ease);
      z-index: 3;
      display: block;
      background: @ui-bg;
      padding: 0;
      cursor: text;
    }

    input.fr-not-empty + label, textarea.fr-not-empty + label {
      color: @input-label-color;
      width: auto;
      left: @input-label-left-after;
      padding: 0 @input-label-padding;
      font-size: @input-label-font-size-after;
      top: @input-label-top-after;
    }
  }

  input, textarea {
    .user-select(text);
    .border-radius(0);
    outline: none;
  }

  textarea {
    resize: none,
  }

  .fr-buttons {
    white-space: nowrap;
    line-height: 0;

    .fr-btn {
      margin-left: @btn-margin;
      margin-right: @btn-margin;
      display: inline-block;
      float: none;

      i {
        float: left;
      }
    }

    .fr-separator {
      display: inline-block;
      float: none;
    }

    &.fr-tabs {
      .border-radius(@btn-tab-border-radius);
      background-color: @ui-bg-color-more;
      overflow: hidden;

      &.fr-tabs-scroll {
        @media (max-width: @screen-sm) {
          overflow: scroll;
          overflow-y: hidden;
          width: @popup-min-width;
        }
      }
    }

    &:not(.fr-tabs) {
      padding: @popup-padding;
    }
  }

  .fr-layer {
    .border-radius(@popup-border-radius);
    width: (@popup-layer-width * 0.75);
    @media (min-width: @screen-sm) {
      width: @popup-layer-width;
    }

    .box-sizing(border-box);
    margin: @popup-layer-margin;
    display: none;

    &.fr-active {
      display: inline-block;
    }
  }

  .fr-action-buttons {
    z-index: 7;
    height: @btn-size;
    text-align: right;

    button.fr-command {
      height: @btn-size;
      line-height: 1;
      color: @ui-color;
      padding: @popup-action-btn-spacing;
      cursor: pointer;
      text-decoration: none;
      border: none;
      background: none;
      font-size: @popup-action-button-font-size;
      outline: none;
      .transition(background @transition-timing);
      .border-radius(@border-radius);

      + button {
        margin-left: 24px;
      }

      &:hover, &:focus {
        background: @btn-hover-bg;
        color: @ui-color;
      }

      &:active {
        background: @btn-active-bg;
        color: @ui-color;
      }
    }

    button::-moz-focus-inner {
      border: 0;
    }
  }

  .fr-checkbox {
    position: relative;
    display: inline-block;
    width: @checkbox-size;
    height: @checkbox-size;
    padding: @checkbox-padding;
    border-radius: 100%;
    line-height: 1;
    .box-sizing(content-box);
    vertical-align: middle;

    svg {
      margin-left: @checkbox-margin;
      margin-top: @checkbox-margin;
      display: none;
      width: @checbox-svg-size;
      height: @checbox-svg-size;
    }

    span {
      .border-radius(@border-radius);
      width: @checkbox-size;
      height: @checkbox-size;
      display: inline-block;
      position: relative;
      z-index: 1;
      .box-sizing(border-box);
      .transition(background @transition-timing, border-color @transition-timing);
    }

    input {
      position: absolute;
      z-index: 2;
      .opacity(0);
      border: 0 none;
      cursor: pointer;
      height: @checkbox-size;
      margin: 0;
      padding: 0;
      width: @checkbox-size;
      top: 7px;
      left: 7px;

      &:not(:checked) {

        & + span {
          border: solid 2px @input-border-color;
        }

        &:active + span {
          background-color: @bg-color;
        }

        &:focus + span, &:hover + span {
          border-color: @ui-border-hover-color;
        }
      }

      &:checked {

        & + span {
          background: @ui-color;
          border: solid 2px @ui-color;

          svg {
            display: block;
          }
        }

        &:active + span {
          background-color: @checbox-active-bg;
        }

        &:focus + span, &:hover + span {
          .opacity(@checkbox-opacity);
        }
      }
    }
  }

  .fr-checkbox-line {
    font-size: @checkbox-line-font-size;
    line-height: @checkbox-line-height;
    margin-top: @checkbox-line-margin-top;

    label {
      cursor: pointer;
      margin: @checkbox-line-label-margin;
      vertical-align: middle;
    }
  }

  &.fr-rtl {
    direction: rtl;
    text-align: right;

    .fr-action-buttons {
      text-align: left;
    }

    .fr-input-line {
      input + label, textarea + label {
        left: auto;
        right: 0;
      }
    }

    .fr-buttons .fr-separator.fr-vs {
      float: right;
    }
  }

}


/***** ui/text_edit.less *****/

.fr-text-edit-layer {
  width: 250px;
  .box-sizing(border-box);
  display: block !important;
}


/***** ui/toolbar.less *****/

.fr-toolbar {
  color: @ui-text;
  background: @ui-bg;
  position: relative;
  font-family: @font-family;
  .fr-clearfix();
  .box-sizing(border-box);
  .user-select(none);
  .border-radius(@border-radius);
  text-align: left;
  border: @editor-border;
  text-rendering: optimizelegibility;
  .font-smoothing();
  line-height: 1.2;
  padding-bottom: 0;
  .transition(padding-bottom @toolbar-transition-timing);

  &::after {
    height: 0;
  }

  .fr-newline {
    clear: both;
    display: block;
    content: "";
    margin-left: @toolbar-newline-margin;
    margin-right: @toolbar-newline-margin;
    background: @toolbar-newline-color;
    height: @toolbar-newline-height;
    .transition(height @toolbar-transition-timing);
  }

  &.fr-toolbar-open {
    .fr-newline {
      height: 0;
    }
  }

  .fr-float-right {
    float: right;
  }

  .fr-float-left {
    float: left;
  }

  .fr-more-toolbar {
    float: left;
    .border-radius(0);
    background-color: @ui-bg-color-more;
    .transition(height @toolbar-transition-timing);
    height: 0;
    // 3803 - toolbar hides when track changes toolbar is on or visible 
    // z-index: 2; remove z index for more toolbars so the popover should come over those toolbars
    overflow: hidden;
    .box-sizing(border-box);
    width: 100%;

    &.fr-expanded {
      height: @more-toolbar-btn-height;
    }

    &.fr-overflow-visible {
      overflow: visible;
    }

    & > .fr-command.fr-btn {
      margin-left: @btn-margin;
      margin-right: @btn-margin;
    }
  }

  .fr-btn-grp {
    display: inline-block;
    margin: @more-toolbar-margin;

    @media (max-width: @screen-sm) {
      margin: @more-toolbar-margin-sm;
    }
  }

  .fr-command.fr-btn.fr-open {
    margin-top: @btn-more-open-margin-top;
    margin-bottom: @btn-more-open-margin-bottom;
    .border-radius(@btn-border-radius @btn-border-radius 0 0);

    &:not(:hover):not(:focus):not(:active) {
      background: @ui-bg-color-more;
    }
  }

  &.fr-rtl {
    text-align: right;
  }

  &.fr-inline {
    display: none;
    .box-shadow(@popup-box-shadow);
    border: 0;
    white-space: nowrap;
    position: absolute;
    margin-top: 5px;
    z-index: 2147483630;

    &.fr-above {
      margin-top: -10px;
      border-top: 0;
    }

    .fr-newline {
      height: 0;
    }

    .fr-more-toolbar {
      position: absolute !important;
      &.fr-expanded {
        position: relative !important;
      }
    }
  }

  &.fr-top {
    top: 0;
    border-bottom: 0;
    .border-radius(@editor-border-radius @editor-border-radius 0 0);
  }

  &.fr-bottom {
    bottom: 0;
    border-top: 0;
    padding-bottom: 0;
    .border-radius(0 0 @editor-border-radius @editor-border-radius);

    .fr-newline {
      padding-top: 0;
      .transition(padding-top @toolbar-transition-timing);
    }

    &.fr-toolbar-open .fr-newline {
      padding-top: @more-toolbar-btn-height;
      background: @white;
    }

    .fr-command.fr-btn.fr-open {
      margin-top: @btn-more-open-margin-bottom;
      margin-bottom: @btn-more-open-margin-top;
      .border-radius(0 0 @btn-border-radius @btn-border-radius);
    }
  }

  &.fr-sticky-on {
    .border-radius(0);
  }
}

.fr-separator {
  background: @separator-color;
  display: block;
  vertical-align: top;
  float: left;

  + .fr-separator {
    display: none;
  }

  &.fr-vs {
    height: (@btn-height - 2 * @btn-margin);
    width: @separator-size;
    margin: @separator-margin;
  }

  &.fr-hs {
    clear: both;
    width: calc(~"100% - (2 * @{btn-margin})");
    margin: 0 @btn-margin;
    height: @separator-size;
  }

  &.fr-hidden {
    display: none !important;
  }
}

.fr-rtl .fr-separator {
  float: right;
}
.fr-toolbar.fr-inline .fr-separator.fr-hs {
  float: none;
}

.fr-toolbar.fr-inline .fr-separator.fr-vs {
  float: none;
  display: inline-block;
}

.fr-second-toolbar {
  border: @editor-border;
  border-top: 0;
  background: @editor-bg;
  line-height: 1.4;
  .border-radius(0 0 @editor-border-radius @editor-border-radius);
  .fr-clearfix();
}

.fr-second-toolbar:empty {
  min-height: calc(~"10px");
  position: relative;
  margin-top: calc(~"-1px");
  z-index: 2;
}

#fr-logo {
  float: left;
  outline: none;

  & > span{
    display: inline-block;
    float: left;
    font-family: sans-serif;
    padding: @logo-span-padding;
    font-size: @logo-span-font-size;
    font-weight: 500;
    color: @logo-color;
    .transition(color @logo-transition-timing);
  }

  & > svg {
    height: @logo-svg-height;
    width: @logo-svg-width;
    margin: @logo-svg-margin;
    cursor: pointer;
  }

  & > svg * {
    .transition(fill @logo-transition-timing);
  }

  &:hover, &:focus {
    & > span {
      color: @btn-active-hover-text;
    }

    & > svg .fr-logo {
      fill: @btn-active-hover-text;
    }
  }
}


/***** helpers.less *****/

.fr-visibility-helper {
  display: none;
  margin-left: 0 !important;

  @media (min-width: @screen-sm) {
    margin-left: 1px !important;
  }

  @media (min-width: @screen-md) {
    margin-left: 2px !important;
  }

  @media (min-width: @screen-lg) {
    margin-left: 3px !important;
  }
}

.fr-opacity-0 {
  .opacity(0);
}

.fr-box {
  position: relative;
}

/**
 * Postion sticky hacks.
 */
.fr-sticky {
  position: -webkit-sticky;
	position: -moz-sticky;
	position: -ms-sticky;
	position: -o-sticky;
	position: sticky;
}

.fr-sticky-off {
	position: relative;
}

.fr-sticky-on {
  position: fixed;
  z-index: 10;

  &.fr-sticky-ios {
    position: absolute;
    left: 0;
    right: 0;
    width: auto !important;
  }
}

.fr-sticky-dummy {
	display: none;
}

.fr-sticky-on + .fr-sticky-dummy, .fr-sticky-box > .fr-sticky-dummy {
	display: block;
}

// Used for accessibility instead of aria-label.
span.fr-sr-only {
  .fr-hide-by-clipping();
}

// merged conflict from master, kept both changes
.fr-view .fr-highlight-change, .fr-highlight-change > img, .fr-highlight-change > .fr-video > video,
.fr-highlight-change > .fr-video > embed, .fr-highlight-change > .fr-video > iframe, .fr-highlight-change > .fr-embedly > .embedly-card > .embedly-card-hug > iframe,
.fr-highlight-change > p, .fr-view .fr-highlight-change > span:not(.fr-tracking-deleted) {
  background-color: #f3eec3;
  opacity: 0.5;
}

.fr-highlight-change.fr-highlight-change > table td, .fr-highlight-change.fr-highlight-change > hr {
  border-color: #f3eec3;
}

.fr-tracking-deleted.fr-tracking-deleted > table td, .fr-tracking-deleted.fr-tracking-deleted > hr {
  border-color: #dc3545;
}

.fr-tracking-deleted img, .fr-tracking-deleted > .fr-video > video, .fr-tracking-deleted > .fr-video > iframe, .fr-tracking-deleted > .fr-embedly > .embedly-card > .embedly-card-hug > iframe {
  opacity: 0.5;
  background-color: #dc3545;
}

.fr-view .fr-tracking-deleted {
  background-color: #dc3545;
  text-decoration: line-through;
  pointer-events: none;
  user-select: none;
  opacity: 1;
}

.fr-highlight-change > .fr-video > iframe, .fr-tracking-deleted > .fr-video > iframe, .fr-highlight-change > .fr-video > video,.fr-tracking-deleted > .fr-video > video, .fr-highlight-change > .fr-video > embed, .fr-highlight-change > .fr-embedly > .embedly-card > .embedly-card-hug > iframe, .fr-tracking-deleted > .fr-embedly > .embedly-card > .embedly-card-hug > iframe {
  padding: 10px !important;
}

.fr-tracking-deleted  img, .fr-highlight-change  img{
  border: 2px solid #f3eec3;
}


.fr-highlight-change #isPasted *:not(table):not(tbody):not(tr):not(td){
  opacity: 0.5; 
  background-color: #f3eec3;
}

.fr-highlight-change #isPasted > table td{
  opacity: 0.5; 
  border-color: #f3eec3;
}


.fr-track-hide {
  display: none;
}

.fr-track-hide-mobile {
  width: 0;
  height: 0;
  overflow: hidden;
  position: absolute;
}

.fr-ios-mobile-disable-select {
  -webkit-touch-callout : none;
  -webkit-user-select : none;
  user-select: none;
}

.fr-bottom-extended {
  flex-wrap: wrap;
  display: flex;
  box-sizing: border-box;
}

.position-relative {
  position: relative !important;
}
