			{
			}
			.has-sectionLinks & .p-navEl-splitTrigger
			{
			}
		}

		&:not(.is-selected):not(.is-menuOpen)
		{
			&:hover,
			.p-navEl-link:hover,
			.p-navEl-splitTrigger:hover
