/* core_setup.less */

body
{
	overflow-x: hidden;
}

/* core_avatar.less */

.avatar
{
	.xf-nlAvatar();
}

/* core_blocklink.less */

.blockLink
{
	.xf-blockLinkExtended();

	&.is-selected
	{
		.xf-blockLinkSelected();
		.xf-blockLinkSelectedExtended();
	}

	&:hover
	{
		.xf-nlBlockLinkHover();
	}
}

/* core_blockmessage.less */

.blockMessage
{
	&.blockMessage--none
	{
	}
}

/* core_datalist.less */

.dataList-table
{
	background: @xf-nlStructItemListContainer--background-color;
}
.dataList-row
{
	.xf-nlDataListRow();

	.dataListAltRows &:nth-of-type(even)
	{
		.xf-nlDataListRowAlternate();
	}
	&:hover:not(.dataList-row--noHover):not(.dataList-row--header):not(.is-spHovered),
	.is-spActive &.is-spChecked
	{
		.xf-nlDataListRowHover();
	}

	.is-spActive &.is-spHovered
	{
		.xf-nlDataListRowHover();
	}
}
.dataList-cell {
	&.dataList-cell--alt,
	&.dataList-cell--action {
		.xf-nlDataListActionItem();
	}

	&.dataList-cell--action,
	&.dataList-cell--link {
		cursor: pointer;
		text-decoration: none;

		&.dataList-cell--alt:hover,
		&.dataList-cell--action:hover {
			.xf-nlDataListActionItemHover();
		}
	}
}

/* core_contentrow.less */

.contentRow-lesser
{
	color: @xf-textColorMuted;
}
.contentRow-header,
.contentRow-title {
	// Deprecate and test
	//.xf-nlContentRowTitle();

	a {
		color: inherit;

		&:hover {
			color: @xf-linkHoverColor;
		}
	}
}
.contentRow-extra.contentRow-extra--large {
    font-size: inherit;
    .m-lineHeightDefault();
}

/* core_input.less */

.inputGroup
{
	&.inputGroup--joined
	{
		.inputGroup-text
		{
			.xf-nlButtonLink();

			&:hover,
			&:active,
			&:focus {
				.xf-nlButtonLinkHover();
			}
		}
	}
}

.inputNumber-button
{
	.inputGroup.inputGroup--joined &
	{
		&:hover,
		&:active,
		&:focus
		{
			.xf-nlButtonLinkHover();
		}
	}
}

@_input-elementSpacer: 10px;
@_input-checkBoxSpacer: 1.2em;

.inputChoices
{

	> .inputChoices-choice
	{
		padding-left: @_input-checkBoxSpacer;
		margin-right: @_input-elementSpacer;
	}
}

@controlColor: @xf-nlControlColor;
@controlColor--hover: @xf-nlControlColorActive;

// Don't apply to off-canvas controls
.p-body-main input[type="checkbox"],
.p-body-main input[type="radio"] {
	color: @controlColor;

	~ * {
		transition: .2s color;
	}
	~ span.iconic-label {
		color: @xf-nlControlLabelColor;
	}
	&:checked ~ span.iconic-label {
		color: @xf-nlControlLabelColorActive;
	}
	&:checked + i {
		color: @controlColor--hover;
	}
}
.formRow,
.inputGroup,
.inputChoices,
.block-footer,
.dataList-cell,
.message-cell--extra,
.structItem-extraInfo
{
	.has-pointerControls & .iconic:hover {
		cursor: pointer;
	}
}
.iconic > input[type=checkbox] + i:after {
    font-weight: @xf-nlCheckboxStyle;
}

/* core_pagenav.less */

.pageNav-main
{
	border-spacing: 1px;
}

/* core_labels.less */

.label
{
	&.label--primary
	{
		.m-labelVariation(@xf-labelPrimaryColor, @xf-labelPrimaryBgColor, @xf-labelPrimaryBorderColor);
	}
	/* Deprecate
	&.label--accent
	{
		.xf-nlLabelAccent();
	}
	&.label--subtle
	{
		.xf-nlLabelSubtle();
	}
	*/
}
/* Deprecate
.use-label--accent .label.label--primary
{
		.xf-nlLabelAccent();
}
*/

/* core_menu.less */

@_menu-paddingV: @xf-nlMenuRowPaddingV;
@_menu-paddingH: @xf-nlMenuRowPaddingH;

.menu
{
	.xf-nlMenuOverlayWrapper();

	&.menu--structural
	{
		&.menu--left
		{
			border-top-left-radius: @xf-menuBorderRadius;
		}
		&.menu--right
		{
			border-top-right-radius: @xf-menuBorderRadius;
		}
	}
}
.menu-content
{
	.menu--structural.menu--left &
	{
		border-top-left-radius: @xf-menuBorderRadius;
	}
	.menu--structural.menu--right &
	{
		border-top-right-radius: @xf-menuBorderRadius;
	}
}

.menu-row
{
	.xf-nlMenuRow();

	&.menu-row--alt
	{
		.xf-nlMenuRowAlt();
	}

	&.menu-row--highlighted
	{
		.xf-nlMenuRowHighlighted();
	}

	&.menu-row--clickable:hover
	{
		.xf-nlMenuRowHover();;
	}
	&.menu-row--separated
	{
		+ .menu-row
		{
			border-top: @xf-borderSize solid @xf-nlMenuDividerBorderColor;
		}
	}
}

.menu-linkRow
{
	.xf-menuLinkRowExtended();

	&.is-selected,
	&:hover,
	&:focus
	{
		.xf-menuLinkRowSelectedExtended();

		&.is-selected
		{

		}
	}
}

.menu-tabHeader
{
	.tabs-tab
	{
		&:hover:not(.is-active)
		{
			.xf-nlMenuTabHeaderHover();
		}
	}
}

/* core_offcanvas.less */

.offCanvasMenu-content
{

	& when(@ltr) or 
	{
		.m-dropShadow(2px, 0, 5px, 0, .25);
		.m-transform(translateX(-300px));
	}

	& when(@rtl)
	{
		.m-dropShadow(-2px, 0, 5px, 0, .25);
		.m-transform(translateX(280px));
	}
}


/* core_tab.less */

.tabs--standalone
{

	.tabs-tab
	{
		.xf-standaloneTabTab();

		&:hover:not(.is-active)
		{
			.xf-standaloneTabHover();
		}
	}
}

@media (max-width: @xf-responsiveEdgeSpacerRemoval)
{
	.tabs--standalone
	{
		margin: 0;
	}
}

/* core_blockend.less */

@media (max-width: @xf-responsiveEdgeSpacerRemoval)
{
	.block-container,
	.blockMessage
	{
		margin: 0;
	}
}

/* core_block.less */

.blocks
{
	.block
	{
		.xf-nlBlockWrapper();
	}
}
/* Currently present in customized template
.block-tabHeader
{
	.tabs-tab
	{
		&:hover
		{
			.xf-blockTabHeaderSelected();
		}
	}
}
*/

/* core_button.less */

.button,
a.button // needed for specificity over a:link
{
	&:hover,
	&:active,
	&:focus
	{
		text-decoration: none;
		.xf-nlButtonDefaultHover();
	}

	&.button--primary
	{
		&:hover,
		&:active,
		&:focus
		{
			text-decoration: none;
			.xf-nlButtonPrimaryHover();
		}
	}

	&.button--cta
	{
		&:hover,
		&:active,
		&:focus
		{
			text-decoration: none;
			.xf-nlButtonCtaHover();
		}
	}

	&.button--link
	{
		.xf-nlButtonLink();

		&:hover,
		&:active,
		&:focus
		{
			text-decoration: none;
			background: @xf-contentHighlightBg;
			.xf-nlButtonLinkHover();
		}
	}

	&.button--small, &.button--s
	{
		font-size: @xf-fontSizeSmall;
		padding: 3px 6px;
		.xf-nlButtonSmall();

		&:hover,
		&:active,
		&:focus
		{
			text-decoration: none;
			.xf-nlButtonSmallHover();
		}
	}

	&.button--medium, &.button--m
	{
		.xf-nlButtonMedium();
	}

	&.button--large, &.button--l
	{
		.xf-nlButtonLarge();
	}

	&.button--icon
	{

		.button-icon
		{
		}

		// &--xx          { .m-buttonIcon(@fa-var-plus-square, .79em); }
	}
}

/* core_tooltip.less */

// .tooltip--preview is joined as padding is not offered in style property, whereas preview usually
// has a different padding value than the others
.tooltip-content
{
	.tooltip--preview &
	.tooltip--bookmark &,
	.tooltip--member &,
	.tooltip--share &
	{
		.xf-nlTooltipMenu();

		.block-row + .block-row {
			padding-top: 0;
		}
	}
}

/* Vertical Sliding */

 .slidingVertica l {
     display: inline;
     text-indent: 8px;
}
 .slidingVertical span  {
     animation: topToBottom 12.5s linear infinite 0s;
     color: #00abe9;
     opacity: 0;
     overflow: hidden;
     position: absolute;
}
 .slidingVertical span:nth-child(2) {
     animation-delay: 2.5s;
}
 .slidingVertical span:nth-child(3) {
     animation-delay: 5s;
}
 .slidingVertical span:nth-child(4) {
     animation-delay: 7.5s;
}
 .slidingVertical span:nth-child(5) {
     animation-delay: 10s;
}

/* topToBottom Animation */

 @keyframes topToBottom {
     0%  {
         opacity: 0;
    }
     5%  {
         opacity: 0;
         transform: translateY(-50px);
    }
     10%  {
         opacity: 1;
         transform: translateY(0px);
    }
     25%  {
         opacity: 1;
         transform: translateY(0px);
    }
     30%  {
         opacity: 0;
         transform: translateY(50px);
    }
     80%  {
         opacity: 0;
    }
     100%  {
         opacity: 0;
    }
}

/* Horizontal Sliding */

 .slidingHorizontal {
     display: inline;
     text-indent: 8px;
}
 .slidingHorizontal span {
     animation: leftToRight 12.5s linear infinite 0s;
     color: #00abe9;
     opacity: 0;
     overflow: hidden;
     position: absolute;
}
 .slidingHorizontal span:nth-child(2) {
     animation-delay: 2.5s;
}
 .slidingHorizontal span:nth-child(3) {
     animation-delay: 5s;
}
 .slidingHorizontal span:nth-child(4) {
     animation-delay: 7.5s;
}
 .slidingHorizontal span:nth-child(5) {
     animation-delay: 10s;
}

/* leftToRight Animation */

@keyframes leftToRight {
     0%  {
         opacity: 0;
    }
     5%  {
         opacity: 0;
         transform: translateX(-50px);
    }
     10%  {
         opacity: 1;
         transform: translateX(0px);
    }
     25%  {
         opacity: 1;
         transform: translateX(0px);
    }
     30%  {
         opacity: 0;
         transform: translateX(50px);
    }
     80%  {
         opacity: 0;
    }
     100%  {
         opacity: 0;
    }
}

/* FadeIn */

 .fadeIn {
     display: inline;
     text-indent: 8px;
}
 .fadeIn span {
     animation: fadeEffect 12.5s linear infinite 0s;
     color: #00abe9;
     opacity: 0;
     overflow: hidden;
     position: absolute;
}
 .fadeIn span:nth-child(2) {
     animation-delay: 2.5s;
}
 .fadeIn span:nth-child(3) {
     animation-delay: 5s;
}
 .fadeIn span:nth-child(4) {
     animation-delay: 7.5s;
}
 .fadeIn span:nth-child(5) {
     animation-delay: 10s;
}

/*FadeIn Animation*/

 @keyframes fadeEffect {
     0%  {
         opacity: 0;
    }
     5%  {
         opacity: 0;
         transform: translateY(0px);
    }
     10%  {
         opacity: 1;
         transform: translateY(0px);
    }
     25%  {
         opacity: 1;
         transform: translateY(0px);
    }
     30%  {
         opacity: 0;
         transform: translateY(0px);
    }
     80%  {
         opacity: 0;
    }
     100%  {
         opacity: 0;
    }
}

/* Vertical Flip */

 .verticalFlip {
     display: inline;
     text-indent: 8px;
}
 .verticalFlip span {
     animation: vertical 12.5s linear infinite 0s;
     color: #00abe9;
     opacity: 0;
     overflow: hidden;
     position: absolute;
}
 .verticalFlip span:nth-child(2) {
     animation-delay: 2.5s;
}
 .verticalFlip span:nth-child(3) {
     animation-delay: 5s;
}
 .verticalFlip span:nth-child(4) {
     animation-delay: 7.5s;
}
 .verticalFlip span:nth-child(5) {
     animation-delay: 10s;
}

/* Vertical Flip Animation */

 @keyframes vertical {
     0%  {
         opacity: 0;
    }
     5%  {
         opacity: 0;
         transform: rotateX(180deg);
    }
     10%  {
         opacity: 1;
         transform: translateY(0px);
    }
     25%  {
         opacity: 1;
         transform: translateY(0px);
    }
     30%  {
         opacity: 0;
         transform: translateY(0px);
    }
     80%  {
         opacity: 0;
    }
     100%  {
         opacity: 0;
    }
}

/* Horizontal Flip */

 .horizontalFlip {
     display: inline;
     text-indent: 8px;
}
 .horizontalFlip span {
     animation: horizontal 12.5s linear infinite 0s;
     color: #00abe9;
     opacity: 0;
     overflow: hidden;
     position: absolute;
}
 .horizontalFlip span:nth-child(2) {
     animation-delay: 2.5s;
}
 .horizontalFlip span:nth-child(3) {
     animation-delay: 5s;
}
 .horizontalFlip span:nth-child(4) {
     animation-delay: 7.5s;
}
 .horizontalFlip span:nth-child(5) {
     animation-delay: 10s;
}

/* Horizontal Flip Animation */

 @keyframes horizontal {
     0%  {
         opacity: 0;
    }
     5%  {
         opacity: 0;
         transform: rotateY(180deg);
    }
     10%  {
         opacity: 1;
         transform: translateX(0px);
    }
     25%  {
         opacity: 1;
         transform: translateX(0px);
    }
     30%  {
         opacity: 0;
         transform: translateX(0px);
    }
     80%  {
         opacity: 0;
    }
     100%  {
         opacity: 0;
    }
}

/* AntiClockWise Effect */

 .antiClock {
     display: inline;
     text-indent: 8px;
}
 .antiClock span {
     animation: anti 12.5s linear infinite 0s;
     color: #00abe9;
     opacity: 0;
     overflow: hidden;
     position: absolute;
}
 .antiClock span:nth-child(2) {
     animation-delay: 2.5s;
}
 .antiClock span:nth-child(3) {
     animation-delay: 5s;
}
 .antiClock span:nth-child(4) {
     animation-delay: 7.5s;
}
 .antiClock span:nth-child(5) {
     animation-delay: 10s;
}

/* AntiClockWise Effect Animation */

 @keyframes anti {
     0%  {
         opacity: 0;
    }
     5%  {
         opacity: 0;
         transform: rotate(180deg);
    }
     10%  {
         opacity: 1;
         transform: translateY(0px);
    }
     25%  {
         opacity: 1;
         transform: translateY(0px);
    }
     30%  {
         opacity: 0;
         transform: translateY(0px);
    }
     80%  {
         opacity: 0;
    }
     100%  {
         opacity: 0;
    }
}

/* Pop Effect */

 .popEffect {
     display: inline;
     text-indent: 8px;
}
 .popEffect span {
     animation: pop 12.5s linear infinite 0s;
     color: #00abe9;
     opacity: 0;
     overflow: hidden;
     position: absolute;
}
 .popEffect span:nth-child(2) {
     animation-delay: 2.5s;
}
 .popEffect span:nth-child(3) {
     animation-delay: 5s;
}
 .popEffect span:nth-child(4) {
     animation-delay: 7.5s;
}
 .popEffect span:nth-child(5) {
     animation-delay: 10s;
}

/* Pop Effect Animation */

 @keyframes pop {
     0%  {
         opacity: 0;
    }
     5%  {
         opacity: 0;
         transform: rotate(0deg) scale(0.10) skew(0deg) translate(0px);
    }
     10%  {
         opacity: 1;
         transform: translateY(0px);
    }
     25%  {
         opacity: 1;
         transform: translateY(0px);
    }
     30%  {
         opacity: 0;
         transform: translateY(0px);
    }
     80%  {
         opacity: 0;
    }
     100%  {
         opacity: 0;
    }
}

/* Push Effect */

 .pushEffect {
     display: inline;
     text-indent: 8px;
}
 .pushEffect span {
     animation: push 12.5s linear infinite 0s;
     color: #00abe9;
     opacity: 0;
     overflow: hidden;
     position: absolute;
}
 .pushEffect span:nth-child(2) {
     animation-delay: 2.5s;
}
 .pushEffect span:nth-child(3) {
     animation-delay: 5s;
}
 .pushEffect span:nth-child(4) {
     animation-delay: 7.5s;
}
 .pushEffect span:nth-child(5) {
     animation-delay: 10s;
}

/* Push Effect Animation */

 @keyframes push {
     0%  {
         opacity: 0;
    }
     5%  {
         opacity: 0;
         transform:rotate(0deg) scale(2) skew(0deg) translate(0px);
    }
     10%  {
         opacity: 1;
         transform: translateX(0px);
    }
     25%  {
         opacity: 1;
         transform: translateX(0px);
    }
     30%  {
         opacity: 0;
         transform: translateX(0px);
    }
     80%  {
         opacity: 0;
    }
     100%  {
         opacity: 0;
    }
}

