/* Filter bar - thread grid

.filterBar-triggerGroup {
    background: rgba(0,0,0,0.2);
    border-radius: 4px;
    padding: 4px 6px;
    display: inline;
    margin-right: 0;
    margin-left: auto;

	a {
		color: inherit;
	}
}
*/

.filterBar-listToggle {
	margin-left: 0;
	margin-right: auto;

	&:before {
		.m-faBase();
		content: "\f009";
	}
	&.thread-grid:before {
		content: "\f03a";
	}
}

/* Thread grid */

@itemWidth: (100% / @xf-nlDiscussionGridItemsPerRow);
@itemSpacing: @xf-nlDiscussionGridSpacing;
@itemSpacingOuter: (@itemSpacing / 2);

.structItem.structItem--placeholder {
	margin-top: 0 !important;
	margin-bottom: 0 !important;
	height: 0 !important;
	border: none !important;
	box-shadow: none !important;
}

@media (min-width: @xf-nlDiscussionGridMinWidth) {

	// Setup initial
	.has-js [data-template="forum_view"] #threadList.has-toggle.hide {
		display: none;
	}
	.structItem {
		transition: all 0.2s, width 1ms !important;
	}

	// Grid
	#threadList.thread-grid {
		&.threadGrid-container .structItemContainer {
			.m-clearFix();
			padding: 0 @xf-nlDiscussionGridSpacing @xf-nlDiscussionGridSpacing @xf-nlDiscussionGridSpacing;
			.xf-nlDiscussionGridListContainer();
		}
		&.threadGrid-floating .block-container--threadList,
		&.threadGrid-floating .structItemContainer {
			.m-stripElement();
		}
		.contentShadows &.separateThreads .block-filterBar,
		.contentShadows &.separateThreads .structItem,
		// Nulumia Sticky Threads Separator
		.structItemContainer-header,
		.forum_view-articles-header {
			.m-dropShadow();
		}

		// Nulumia Sticky Threads Separator
		.structItemContainer-header,
		hr.sticky-divider {
			margin: (@xf-nlDiscussionGridSpacing * 1.5) 0 0;
			border-radius: @xf-blockBorderRadius;

			+ .structItemContainer-group {
				margin-top: (@xf-nlDiscussionGridSpacing /2);
			}
		}

		// From structured_lists.less
		.structItem:not(form) .structItem-cell {
			padding: @xf-nlDiscussionGridCellPadding;

			&.structItem-cell--icon {
				width: (@xf-nlStructItemAvatarSize + @_structItemGrid-cellPaddingH);
			}
			&.structItem-cell--iconExpanded {
				width: (@xf-nlStructItemAvatarSizeExpanded + @_structItemGrid-cellPaddingH);
			}
			&.structItem-cell--iconEnd {
				width: (@_structItem-avatarSizeEnd + @_structItemGrid-cellPaddingH);
			}
			&.structItem-cell--iconFixedSmall {
				width: (60px + (@_structItemGrid-cellPaddingH * 2));
			}
		}
		.structItemContainer-group {
			display: flex !important;
			flex-direction: row;
			flex-wrap: wrap;
			margin: @xf-nlDiscussionGridSpacing -(@xf-nlDiscussionGridSpacing / 2) -@xf-nlDiscussionGridSpacing -(@xf-nlDiscussionGridSpacing / 2);
			background: transparent none;
			box-shadow: none;
			border: none;
		}
		.structItem {
			flex: auto;
			margin: @itemSpacingOuter;
			width: ~"calc(@{itemWidth} - @{itemSpacing})";
			min-width: @xf-nlDiscussionGridItemMinWidth;
			display: flex;
			flex-wrap: wrap;
			//height: 100%;
			table-layout: unset;
			position: relative;
			.xf-nlDiscussionGridThread();

			>* {
				display: block;
				flex: 1;
			}
			.structItem-cell {
				width: auto;
			}
			.structItem-cell--icon {
				flex: 0 0 auto;
				//.m-flexAlignCenter();
				.xf-nlDiscussionGridIconBlock();

				&:first-child {
					padding-right: 0;
					padding-bottom: @_structItemGrid-cellPaddingV / 2;
				}
				.structItem-iconContainer {
					// Line-height match
					margin-top: 3px;
				}
			}
			.structItem-iconContainer .structItem-secondaryIcon {
				display: none;
			}
			.structItem-cell--main {
				min-width: 75%;
				padding-bottom: @_structItemGrid-cellPaddingV / 2;
				.xf-nlDiscussionGridMainBlock();
			}
			.structItem-cell--meta {
				flex: 1;
				.m-flexAlignCenter();
				padding-top: @_structItemGrid-cellPaddingV / 2;
				padding-right: @_structItemGrid-cellPaddingH / 2;
				clear: both;
				min-width: 30% !important;
				.xf-nlDiscussionGridStatsBlock();
			}
			.structItem-cell--latest {
				flex: 1;
				.m-flexAlignCenter();
				padding-top: @_structItemGrid-cellPaddingV / 2;
				padding-left: @_structItemGrid-cellPaddingH / 2;
				clear: both;
				max-width: 280px;
				min-width: 30%;
				.xf-nlDiscussionGridLastPost();

				time.structItem-latestDate.u-dt {
					display: block;
					text-align: right;
					.m-overflowEllipsis();
				}
			}
			.structItem-cell--icon.structItem-cell--iconEnd {
				flex: 0 0 auto !important;
				.m-flexAlignCenter();
				padding-left: 0;
				padding-top: @_structItemGrid-cellPaddingV / 2;
				.structItem-iconContainer {
					padding-top: 0;
				}
			}
		}

		&.collapseThreads .structItem {
			border-radius: 0 !important;
		}
		&.fixedThreads .structItem {
			max-width: @xf-nlDiscussionGridItemMaxWidth;
		}
		.structItemContainer-group--sticky .structItem {
			.xf-nlDiscussionGridThreadSticky();
		}

		// Item widths
		&.cols-flex {
			.structItem {
				flex: 1;
			}
		}
		&.items-per-row-2 {
			.structItem {
				width: ~"calc(50% - @{itemSpacing})";
			}
		}
		&.items-per-row-3 {
			.structItem {
				width: ~"calc(33.33% - @{itemSpacing})";
			}
		}
		&.items-per-row-4 {
			.structItem {
				width: ~"calc(25% - @{itemSpacing})";
			}
		}
		&.items-per-row-5 {
			.structItem {
				width: ~"calc(20% - @{itemSpacing})";
			}
		}
		&.items-per-row-6 {
			.structItem {
				width: ~"calc(16.667% - @{itemSpacing})";
			}
		}
		&.items-per-row-7 {
			.structItem {
				width: ~"calc(14.285% - @{itemSpacing})";
			}
		}
		&.items-per-row-8 {
			.structItem {
				width: ~"calc(12.5% - @{itemSpacing})";
			}
		}
		&.stretchThreads .structItemContainer-group.js-threadList .structItem-wrapper {
			max-width: none;
		}
	}
}

// Responsive queries
@media (max-width: @xf-nlDiscussionGridMinWidth)
{
	.filterBar-listToggle {
		display: none;
	}
}
@media (min-width: @xf-nlDiscussionGridMinWidth) and (max-width: 900px)
{
	#threadList.thread-grid[class*=" threadGrid-"] {
		.structItem-wrapper {
			flex: 1 1 33.33%;
			max-width: 33.33%;
		}
	}
}
@media (min-width: @xf-nlDiscussionGridMinWidth) and (max-width: 800px)
{
	#threadList.thread-grid[class*=" threadGrid-"] {
		.structItem-wrapper {
			flex: 1 1 50%;
			max-width: 50%;
		}
	}
}
@media (min-width: @xf-nlDiscussionGridMinWidth) and (max-width: 480px)
{
	//
}

