/* ====================================================================================================================
 * RESETS
 * ====================================================================================================================*/
.flex-container a:hover, .flex-slider a:hover {
	outline: none;
}
.slides, .slides > li, .flex-control-nav, .flex-direction-nav {
	margin: 0;
	padding: 0;
	list-style: none;
}
.flex-pauseplay span {
	text-transform: capitalize;
}
/* ====================================================================================================================
 * BASE STYLES
 * ====================================================================================================================*/
.flexslider {
	margin: 0;
	padding: 0;
    position: relative;
}
.flexslider .slides > li {
	display: none;
	-webkit-backface-visibility: hidden;
}
.flexslider .slides img {
	width: 100%;
	display: block;
}
.flexslider .slides:after {
	content: "\0020";
	display: block;
	clear: both;
	visibility: hidden;
	line-height: 0;
	height: 0;
}
html[xmlns] .flexslider .slides {
	display: block;
}
* html .flexslider .slides {
	height: 1%;
}
.no-js .flexslider .slides > li:first-child {
	display: block;
}
/* ====================================================================================================================
 * DEFAULT THEME
 * ====================================================================================================================*/
.flexslider.flexslider--primary {
	.xf-nlSliderContainer();
}
.flexslider .slides {
	.xf-nlSliderSlidesContainer();
}
.flexslider .slides,
.flexslider .slides > li {
	overflow:hidden;
}
.flexslider .slides img {
	height: auto;
	-moz-user-select: none;
}
.flex-viewport {
	max-height: 2000px;
	transition: all 1s ease;
}
.loading .flex-viewport {
	max-height: 300px;
}

.flex-caption {
	.sliderCaption--bottom &.caption--default,
	&.caption--bottom {
		position: absolute;
		left: 0;
		bottom: 0;
		width: 100%;
		.xf-nlSliderCaptionBoxBottom();
	}
	/* Caption floating */
	.sliderCaption--left &.caption--default,
	&.caption--left {
		position: absolute;
		width: 50%;
		left: @_captionOffset;
		top: 50%;
		transform: translatey(-50%);
		.xf-nlSliderCaptionBoxFloating();

		> * {
			margin: 0 auto @xf-nlSliderCaptionElementSpacer;
		}
	}
	.sliderCaption--right &.caption--default,
	&.caption--right {
		position: absolute;
		width: 50%;
		left: auto;
		right: @_captionOffset;
		top: 50%;
		transform: translatey(-50%);
		text-align: right;
		.xf-nlSliderCaptionBoxFloating();

		> * {
			margin: 0 auto @xf-nlSliderCaptionElementSpacer;
		}
	}
	/* Caption asides */
	.sliderCaption--leftAside &.caption--default,
	&.caption--leftAside {
		flex: 1;

		.xf-nlSliderCaptionBoxAside();

		> * {
			margin: 0 auto @xf-nlSliderCaptionElementSpacer;
		}
	}
	.sliderCaption--rightAside &.caption--default,
	&.caption--rightAside {
		flex: 1 1 30%;

		.xf-nlSliderCaptionBoxAside();

		> * {
			margin: 0 auto @xf-nlSliderCaptionElementSpacer;
		}
	}
	.m-clearFix();

	span.button:first-child {
		float: right;
		margin-top: 6px;
	}
}
.sliderCaption--leftAside,
.sliderCaption--rightAside {
	ul.slides li a {
		display: flex;
		flex-direction: row;
		flex-wrap: wrap;
	}
	ul.slides li img {
		// width: 70%;
		flex: 1 1 70%;
	}
}
.flex-caption h2 {
	line-height: normal;
	margin: 0;

	.sliderCaption--bottom & {
		.xf-nlSliderCaptionBoxBottomTitle();
	}
	.sliderCaption--left &, .sliderCaption--right & {
		.xf-nlSliderCaptionBoxFloatingTitle();
	}
	.sliderCaption--leftAside &, .sliderCaption--rightAside & {
		.xf-nlSliderCaptionBoxAsideTitle();
	}
}
.flex-caption p {
	margin: 0 0 @xf-paddingSmall;
	line-height: 1.4;
}
.flex-caption ul {
	padding: 0;
    list-style: initial;
	.m-clearFix();
}
.flex-caption > *:last-child {
    margin-bottom: 0 !important;
}

.flex-direction-nav {
 *height: 0;
}
.flex-direction-nav a {
	text-decoration: none;
	display: block;
	position: absolute;
	top: 50%;
	transform: translatey(-50%);
	z-index: 10;
	overflow: xhidden;
	opacity: 0;
	cursor: pointer;
	transition: all 0.3s ease-in-out;
	font-size: 0;
}
<xf:if is="property('nlSliderArrowControlType') == 'image'">
.flex-direction-nav a {
	background-repeat: no-repeat;
	background-position: 0 center;
	.xf-nlSliderDirectionalCtrlImg();

	&.flex-next {
		background-position: right center;
	}
	[DIR="RTL"] &.flex-prev {
		background-position: right center;
	}
	[DIR="RTL"] &.flex-next {
		background-position: left center;
	}
}
<xf:elseif is="property('nlSliderArrowControlType') == 'fontawesome'" />
.flex-direction-nav {
	.flex-prev:before {
		content: "\f053";

		[dir="rtl"] & {
			content: "\f054";
		}
	}
	.flex-next:before {
		content: "\f054";

		[dir="rtl"] & {
			content: "\f053";
		}
	}
	a:before {
		.m-faBase('Pro', 900);
		display: inline-block;
		vertical-align: middle;
		text-align: center;
		.xf-nlSliderDirectionalCtrlFa();
	}
	a:hover:before {
		.xf-nlSliderDirectionalCtrlFaHover();
	}
}
</xf:if>

.flex-direction-nav {
	.flex-prev {
		left: @_controlsOffset;
	}
	.flex-next {
		right: @_controlsOffset;
		text-align: right;
	}
	[dir="RTL"] & {
		.flex-prev, .flex-next {
		}
	}
}
.flexslider:hover .flex-direction-nav .flex-prev {
	opacity: 1;
}
.flexslider:hover .flex-direction-nav .flex-prev:hover {
	opacity: 1;
}
.flexslider:hover .flex-direction-nav .flex-next {
	opacity: 1;
}
.flexslider:hover .flex-direction-nav .flex-next:hover {
	opacity: 1;
}
.flex-direction-nav .flex-disabled {
	opacity: 0!important;
	filter: alpha(opacity=0);
	cursor: default;
	z-index: -1;
}
.flex-pauseplay a {
	display: block;
	width: 20px;
	height: 20px;
	position: absolute;
	bottom: 5px;
	left: 10px;
	opacity: 0.8;
	z-index: 10;
	overflow: hidden;
	cursor: pointer;
	color: #000;
}
.flex-pauseplay a:before {
	font-family: fontawesome;
	font-size: 20px;
	display: inline-block;
	content: '\f004';
}
.flex-pauseplay a:hover {
	opacity: 1;
}
.flex-pauseplay a.flex-play:before {
	content: '\f003';
}
.flex-control-wrapper {
	line-height: normal;
	.xf-nlSliderBottomCtrlContainer();
}
.flex-control-nav {
	.xf-nlSliderBottomCtrlInner();
}
.flex-control-nav li {
	display: inline-block;
	zoom: 1;
	vertical-align: middle;
	*display: inline;
}
.flex-control-paging li a {
	display: block;
	cursor: pointer;
	text-indent: -9999px;
	.xf-nlSliderBottomCtrlButton();
}
.flex-control-paging li a:hover, .flex-control-paging li a.flex-active {
	.xf-nlSliderBottomCtrlButtonHover();
}
.flex-control-thumbs {
	margin: 5px 0 0;
	position: static;
	overflow: hidden;
}
.flex-control-thumbs li {
	width: 25%;
	float: left;
	margin: 0;
}
.flex-control-thumbs img {
	width: 100%;
	height: auto;
	display: block;
	opacity: .7;
	cursor: pointer;
	transition: all 1s ease;
}
.flex-control-thumbs img:hover {
	opacity: 1;
}
.flex-control-thumbs .flex-active {
	opacity: 1;
	cursor: default;
}

/* Caption animations */

@keyframes captionSlideIn {
    100% {
    	left: 0;
		right: 0;
		top: 0;
		bottom: 0;
		opacity: 1;
		transform: scale(1);
    }
}
.has-captionAnimation {
	.flex-caption > * {
		animation: captionSlideIn @xf-nlSliderCaptionAnimationLength forwards;
		position:  relative;
		opacity: 0;
		animation-timing-function: @xf-nlSliderCaptionAnimationTiming;
	}
}
.flex-caption ul {
    list-style: none;
}

@_itemDelay: @xf-nlSliderCaptionAnimationDelay;
.item-ratings(5);
.item-ratings(@n, @i: 1) when (@i =< @n) {
	.flex-caption > *:nth-child(@{i}) {
		animation-delay: (@_itemDelay * @i);
	}
	.item-ratings(@n, (@i + 1));
}

/* Top to bottom */
.captionAnimation-slideIn1 .flex-caption > * {
    top: -@_captionSlideOffset;
}

/* Left to right */
.captionAnimation-slideIn2 .flex-caption > * {
    left: -@_captionSlideOffset;
}

/* Bottom to top */
.captionAnimation-slideIn3 .flex-caption > * {
    bottom: -@_captionSlideOffset;
}

/* Right to left */
.captionAnimation-slideIn4 .flex-caption > * {
    right: -@_captionSlideOffset;
}

/* Clockwise */
.captionAnimation-slideIn5 .flex-caption > * {
	&:nth-child(1) {
		top: -@_captionSlideOffset;
	}
	&:nth-child(2) {
		left: -@_captionSlideOffset;
	}
	&:nth-child(3) {
		bottom: -@_captionSlideOffset;
	}
	&:nth-child(4) {
		right: -@_captionSlideOffset;
	}
}

/* Zoom in */
.captionAnimation-slideIn7 .flex-caption > * {
	transform: scale(1.5);
}

