// Extends lightslider.less
// Follows Xenforo extensions

// Default Variables

@arrow-color: white;
@dot-color: black;
@dot-color-active: black;
@prev-character: "\f053";
@next-character: "\f054";
@up-character: "\f077";
@down-character: "\f078";
@dot-character: "\f120";
@dot-size: 6px;
@opacity-default: 1;
@opacity-on-hover: 1;
@opacity-not-active: 0.25;
@arrow-width: @xf-nlDirectionalControlsWidth;
@arrow-height: @xf-nlDirectionalControlsHeight;

.lightSlider--loaded .lightSlider > *,
.lightSlider--loaded .lSGallery li {
	display: block !important;
}

a.lslide,
a.lslide img,
.lSPager.lSGallery li a,
.lSPager.lSGallery li a img {
	display: block;
}

/* Arrow controls */

.lSAction > a
{
	height: auto;
	width: min-content;
    line-height: 0px;
    font-size: 0px;
    cursor: pointer;
    background: transparent;
    color: transparent;
	opacity: 1;
	z-index: 100;
	transition: .2s all;

    &:after
    {
		display: block;
		font-size: 20px;
		width: @arrow-width !important;
		height: @arrow-height;
		line-height: @arrow-height;
		opacity: @opacity-default;
		-webkit-font-smoothing: antialiased;
		-moz-osx-font-smoothing: grayscale;
		z-index: 100;
		transition: .2s all;
		position: relative;
		-webkit-text-fill-color: unset;
		-webkit-text-stroke: unset;
        .xf-nlSlickDirectionalControls();
    }

	&:hover:after
    {
		opacity: @opacity-on-hover;
		.xf-nlSlickDirectionalControlsHover();
    }

	// Vertical
	.lSSlideOuter.vertical & {
		margin: 0;
		transform: translateX(-50%);

		&:after
		{
			width: @arrow-height !important;
			height: @arrow-width;
			line-height: @arrow-width;
		}

		&.lSPrev:after
		{
 			.m-faContent(@fa-var-chevron-up);

		}
		&.lSNext:after
		{
 			.m-faContent(@fa-var-chevron-down);
		}
	}
}

.lSSlideOuter.vertical {
	.m-clearFix();
}

.lSSlideWrapper,
.lSGallery {
	min-height: 10px;
}

.message-cell
{
	&.message-cell--main
	{
		.xf-nlMessageContent();
	}
	.message--userInfo-default &.message-cell--user .message-userExtras {
		.xf-nlMessageUserInfo();
