	{
		.m-stripElement();
	}

	.message,
	.block-row
	{
		.xf-nlMessageWrapper();

		&.is-mod-selected {
			.xf-nlMessageWrapperModSelected();
		}
		+ .message:not(.message--article),
		+ .block-row
		{
			margin-top: @xf-nlMessageSpacer;
		}
	}
}

.message-content a {
	.xf-nlMessageLink();
}
.message-content a:hover {
	.xf-nlMessageLinkHover();
}
.messageButtonLinks .block:not(.block--articles) .actionBar-set--external .actionBar-action {
	.xf-buttonBase();
	<xf:if is="property('nlMessageButtonLinksStyle') == 'buttonPrimary'">
	.xf-buttonPrimary();
	&:hover {
		.xf-nlButtonPrimaryHover();
	}
	<xf:elseif is="property('nlMessageButtonLinksStyle') == 'buttonCta'" />
	.xf-buttonCta();
	&:hover {
		.xf-nlButtonCtaHover();
	}
	<xf:elseif is="property('nlMessageButtonLinksStyle') == 'buttonLink'" />
	.xf-nlButtonLink();
	&:hover {
		.xf-nlButtonLinkHover();
	}
	</xf:if>
	.xf-nlButtonSmall();

	&.has-reaction .reaction-text {
		color: inherit !important;
	}
}

.message-userDetails {
	.xf-nlMessageUserDetails();

	.userTitle {
		.xf-nlUserTitle();
	}
}

.actionBar-action {
	.xf-nlMessageActionLinks();
}
.actionBar-action.actionBar-action--inlineMod label.iconic {
    color: inherit;
}

/* Message banners and buttons */

.message-cell--user {
	a.cxf-button.button--link,
	.offline, .online,
	.userBanner {
		display: block;
		/* width: 100%; */
		margin-top: 4px;
	}
}

/*=============================================
=            Message collapse                 =
=============================================*/

.message-userExtras--collapsible {
	.has-no-js & { display: block; }

	.m-transitionFadeDown();
}

.message--userInfo-default {
	.collapseTrigger {
		width: 100%;
	}
	.collapseTrigger:before {
		width: 100% !important;
		text-align: center;
		float: none !important;
		font-size: 18px;
		margin: 0;
	}
}

@media (min-width: @xf-messageSingleColumnWidth)
{
	// Only show collapseTrigger above responsive column. Change this later to allow expanding the hidden group on mobile
	.message-cell.message-cell--user {
		.collapseTrigger {
			display: block;
		}
		.collapseTrigger:before {
			margin: auto;
		}
	}
	.message--userInfo-above {
		.message-inner {
			flex-direction: column;
		}
		.message-avatar {
			margin-right: @xf-paddingMedium;
		}
		.message-avatar.userInfoAbove-avatar--custom .avatar.avatar--l {
			width: @xf-nlMessageUserInfoAboveAvatarCustomSize;
			max-width: 100%;
			height: @xf-nlMessageUserInfoAboveAvatarCustomSize;

			&.avatar--default.avatar--default--dynamic > span,
			&.avatar--default.avatar--default--text > span {
				line-height: @xf-nlMessageUserInfoAboveAvatarCustomSize;
			}
		}
		// Info top right
		section.message-user.message-user--infoTopRight {
			display: flex;
			flex-flow: row wrap;

			.message-userDetails {
				flex: 1;
			}
			.message-userDetails-wrapper {
				flex: 0 0 auto;
			}
		}
		section.message-user.message-user--infoCompact {
			.message-avatar {
				float: left;
			}
			.collapseTrigger {
				float: left;
				margin: 3px @xf-paddingSmall 0 0;
			}
			.message-userExtras {
				width: auto;

				&.is-active {
					display: inline-block;
				}
			}

			dl.pairs.pairs--justified {
				display: inline-block;
				margin-right: 6px;
			}
		}
		.message-cell.message-cell--user {
			flex: 1;
			border-radius: 0;
			border-top-left-radius: @block-borderRadius-inner;
			border-top-right-radius: @block-borderRadius-inner;
			border-right: none;
			.xf-nlMessageUserBlockAbove();
		}
		.message-userDetails {

		}
		.message-userDetails > .message-name {
			display: block;
			width: 100%;
			padding: 0;
		}
		.message-userDetails > * {
			display: inline-block;
			text-align: left;
			margin: 0;
		}
		.message-userArrow
		{
			position: absolute;
			top: auto;
			right: auto;
			left: (@xf-messagePadding) * 2;
			bottom: -1px;

			.m-triangleUp(xf-default(@xf-nlMessageUserBlockAbove--border-bottom-color, transparent), @xf-messagePadding);

			&:after
			{
				position: absolute;
				top: auto;
				right: auto;
				left: -(@xf-messagePadding - 1px);
				bottom: -@xf-messagePadding;
				content: "";

				.m-triangleUp(@xf-contentBg, @xf-messagePadding - 1px);
			}
		}
	}
}

.avatar-block--compact .message-cell.message-cell--user {
    flex: 0 0 auto;
}

/*=============================================
=            Message view                     =
=============================================*/

.message-avatar
{
	.avatar.avatar--l {
		width: @xf-messageUserBlockWidth;
		max-width: 100%;
		height: @xf-messageUserBlockWidth;

		&.avatar--default.avatar--default--dynamic > span,
		&.avatar--default.avatar--default--text > span {
			line-height: @xf-messageUserBlockWidth;
		}
	}
	&.userInfoAside-avatar--custom .avatar.avatar--l {
		width: @xf-nlMessageAvatarWidth;
		max-width: 100%;
		height: @xf-nlMessageAvatarWidth;

		&.avatar--default.avatar--default--dynamic > span,
		&.avatar--default.avatar--default--text > span {
			line-height: @xf-nlMessageAvatarWidth;
		}
	}
}

/* MrJinx Profile Fields Popup */

.message-cell--user {
	.message-userExtras-popup {
		.m-clearFix();
	}
	.profilefieldspopup_link	{
		color: inherit;
	}
	.profilefieldspopup_link:hover {
		color: inherit;
		opacity: 0.8;
	}
}

.scOnOffMobile {
    position: relative; // Fix arrow zindex issue
}

/* XFMG Fix */

/* XFMG - ADDONCOMPAT */

<xf:if is="!property('nulumia_xfmgiNulumiaAddonCompat')">
.has-touchevents .itemList-itemOverlay,
.itemList-item:hover .itemList-itemOverlay {
    height: auto;
}

[data-type="xfmg_media"] {

	.block-container {
		.m-stripElement();
	}
	.itemList {
		margin: 0 -(@xf-nlXFMGItemSpacing / 2);
	}
	.itemList-item {
		flex: 1 0 25%;
		max-width: none;
		margin: (@xf-nlXFMGItemSpacing / 2);
	}
	.media-gridItems-2 & .itemList-item {
		flex: 0 0 ~"calc(50% - @xf-nlXFMGItemSpacing)";
	}
	.media-gridItems-3 & .itemList-item {
		flex: 0 0 ~"calc(33.3% - @xf-nlXFMGItemSpacing)";
	}
	.media-gridItems-4 & .itemList-item {
		flex: 0 0 ~"calc(25% - @xf-nlXFMGItemSpacing)";
	}
	.media-gridItems-5 & .itemList-item {
		flex: 0 0 ~"calc(20% - @xf-nlXFMGItemSpacing)";
	}
	.media-gridItems-6 & .itemList-item {
		flex: 0 0 ~"calc(16.667% - @xf-nlXFMGItemSpacing)";
	}

	<xf:if is="property('nlXFMGItemHideAuthorDate') == true">
	.itemInfoRow-main .itemInfoRow-status:nth-of-type(1) {
		display: none;
	}
	</xf:if>
	<xf:if is="property('nlXFMGItemHideLikesComments') == true">
	.itemInfoRow-main .itemInfoRow-status:nth-of-type(2) {
		display: none;
	}
	</xf:if>
	.media-itemDesc-below & {
		.itemList-item {
			.xf-contentBase();
			.xf-blockBorder();
			border-radius: @xf-blockBorderRadius;
		}
		.itemList-itemOverlay {
			position: relative;
			background: transparent;
			color: @xf-textColorMuted;
			top: auto;
			bottom: auto;
			height: auto;
			.xf-nlXFMGItemDescBelowContent();
		}
		.itemList-itemOverlay * {
			color: inherit;
			font-size: inherit;
			text-shadow: none;
		}
		.itemInfoRow-title {
			margin-bottom: @xf-paddingSmall;
			overflow: visible;
			white-space: inherit;
			word-wrap: inherit;
			text-overflow: inherit;
			.xf-nlXFMGItemDescBelowTitle();
		}
	}
	.media-itemDesc-fade & {
		.itemList-itemOverlay {
			color: @xf-textColorMuted;
		  top: 0;
		  bottom: auto;
		  height: 100%;
		  width: 100%;
		  display: flex;
		  text-align: center;
		  align-items: center;
			opacity: 0;
			transition: .2s opacity;
			pointer-events: none;
		}
		.itemList-item:hover .itemList-itemOverlay {
			opacity: 1;
		}
		<xf:if is="property('nlXFMGZoomThumbHover') == true">			
		.itemInfoRow-main {
			transition: .2s transform;
			backface-visibility: hidden;
			transform: scale(0.8);
		}
		.itemList-item:hover .itemInfoRow-main {
			transform: scale(1);
		}
		</xf:if>
		.itemList-itemOverlay * {
			color: inherit;
			font-size: inherit;
			text-shadow: none;
			margin: auto;
		}
		.itemInfoRow-title {
		  margin-bottom: 6px;
		  color: #fff;
		  font-size: @xf-fontSizeLarge;
		}
	}
}
@media (max-width: @xf-responsiveMedium)
{
	.itemList-item {
		width: auto;
		flex: 1 1 ~"calc(50% - @xf-nlXFMGItemSpacing)" !important;
	}
}
@media (max-width: @xf-responsiveNarrow)
{
	.itemList-item {
		flex: 1 1 ~"calc(100% - @xf-nlXFMGItemSpacing)" !important;
	}
}
<xf:if is="property('nlXFMGZoomThumbHover') == true">
[data-type="xfmg_media"] {

	.xfmgThumbnail {
		overflow: hidden;

		img {
			transition: .2s transform;
		}
	}
	.itemList-item:hover .xfmgThumbnail img {
		transform: scale(@xf-nlXFMGZoomThumbAmount);
	}
}
</xf:if>

.itemList-itemOverlay
{
	height: 35%;
	bottom: -35%;

	.has-touchevents &,
	.itemList-item:hover &
	{
		height: auto;
	}
}

a.media-button {
	display: block;
	width: auto;
	height: auto;
	.xf-nlXFMGMediaControls();

	.media-button-icon {
