}

/* Siropu Chat */

#siropuChatOptions {
	margin-top: 0;
}

// From siropu_chat_widget.less
.siropuChatWidgetRooms > ul
{
	> li
	{
		border: none;
		.xf-blockLink();
		.xf-blockLinkExtended();

		&:first-child
		{
			border: none;
		}
		&:hover
		{
			border: none;
			.xf-blockLink();
			.xf-blockLinkExtended();
			.xf-nlBlockLinkHover();
		}
		&.siropuChatActiveRoom > span
		{
			color: green;
		}
