/* DBTech Ecommerce */

.productList-product-grid.node .node-title {
	margin-bottom: @xf-paddingSmall;
}

.p-body {
	.productList-grid {
		.block-footer {
			.m-stripElement();
		}
	}
	.productList-product-grid.node {
		.productList-product-grid--updateInfo {
			.xf-blockFooter();
		}
	}
	/* Standard price in widgets */
	.price {
		.xf-nlDBTechEcommWidgetPrice();
	}
	/* Set strikethrough price styles */
	.productList-product-grid--clearfix .price,
	.productList-product-grid--priceCartInfo .price {
		span {
			line-height: normal;
		}
		.old-price {
			text-decoration: line-through;
			color: @xf-textColorMuted;
		}
		.sale-price {

		}
	}
	.productList-product-grid--clearfix .price {
		span {
			display: block;
		}
	}
}

.productList-product-grid--priceCartInfo {
	display: flex;

	.addToCart, .costs {
		padding: @xf-paddingSmall;
		flex: 1;
		.m-lineHeightDefault();
	}
	.addToCart {
		flex: 0 0 auto;
	}
	.costs {
		text-align: right;
	}
}

/* Product icons */

.productList-product-grid.node .productList-product-grid--icon {
	.xf-nlDBTechEcommThumbWrapper();
}

/* Product pages */

// Product images
.productHeader {

	.productHeader-imageList {
		.xf-nlDBTechEcommProductPageSlider();
	}
	.lSSlideOuter .lSPager.lSGallery li {
		.xf-nlDBTechEcommProductPageSliderAttachments();

		img {
			width: auto;
			max-height: 150px;
			margin: auto;
		}
	}
	.lSSlideOuter.vertical .lSAction > a:after {
		.xf-nlDBTechEcommProductPageSliderDirectionalControls();
	}
	@media (min-width: @xf-responsiveNarrow)
	{
		.lslide img {
			display: block;
			max-height: @xf-nlDBTechEcommProductSlideMaxHeight;
			margin: auto;
		}
		&.productHeader--scroller-side  .lSSlideOuter.vertical {

			.lslide img {
				height: 100%;
			}
			.lSPager.lSGallery li a {
				height: inherit;

				img {
					object-fit: cover;
					object-position: center;
					height: 100%;
					width: 100%;
				}
			}
			.lSGallery {
				width: 120px !important;
			}
		}
		&.productHeader--scroller-side.productHeader--scroller-left .lSSlideOuter.vertical {
				padding-left: (120px + (@xf-elementSpacer / 2));
				padding-right: 0 !important;

				.lSGallery {
					right: auto;
					left: 0;
					margin-right: (@xf-elementSpacer / 2);
					margin-left: 0 !important;
				}
		}
	}
	&.productHeader--scroller-below {

	}
	@media (max-width: @xf-responsiveNarrow)
	{
		.productHeader-imageList {
			padding-bottom: 0 !important;
		}
	}
}

@media (min-width: @xf-responsiveWide)
{
	.template-dbtech_ecommerce_product_view .p-body-sidebar {
		width: @xf-nlDBTechEcommSidebarWidth;
