/* TH Node grid */

.thNodes__nodeList {
	.block-container .block-body {
		margin-top: @xf-th_nodeGutter;

		@media (max-width: @xf-responsiveEdgeSpacerRemoval) {
			margin-left: -@xf-th_nodeGutter;
