}
ul.nav-horizontal li.is-active ul {
    opacity: 1;
}
.p-body-horizontalNav > ul > li.subcategorySpacer {
    padding-bottom: (@xf-nlHorizontalCategoryListSublinkHeight + (@xf-paddingMedium * 2)) !important;
    display: block !important;
    clear: both;
    width: 100%;
}

