/*=============================================
=            Forum list                       =
=============================================*/

.node + .node {
    border-top: inherit;
}
.node-body {
	min-height: 70px;
	.xf-nlNodeRow();
}
.alternateNodes .block-body > .node:nth-of-type(even) .node-body {
	.xf-nlNodeRowAlternate();
}
.hoverNodes:not(.nodeImgBehind) {
	.node:not(.th_nodes) .node-body:hover,
	.block-body > .node:nth-of-type(even):not(.th_nodes) .node-body:hover {
		.xf-nlNodeRowHover();
	}
}
.node-body > div,
.node-body > span {
	.xf-nlNodeCell();
}

.node {
	// Needs specificity for TH Nodes
	.node-body .node-icon,
	.node-body .no-icon { // cv6 nodes
		padding: @xf-nlNodePaddingV 0 @xf-nlNodePaddingV @xf-nlNodePaddingH;
		width: @xf-nlNodeIconBlockWidth;
		.xf-nlNodeIconBlock();

		i {
			line-height: 1;
			// .xf-nlNodeIconReadWrapper();

			&:before {
				display: inline-block;
				font-weight: @xf-nlNodeIconStyle;
				color: @xf-nodeIconReadColor;
				text-shadow: 1px 1px 0.5px fade(@xf-nlBoxShadowColor, (@xf-nlBoxShadowAlpha * 100));
				width: @xf-nlNodeIconSize;
				height: @xf-nlNodeIconSize;
				line-height: @xf-nlNodeIconSize;
				.xf-nlNodeIcon();

				.node--unread& {
					opacity: 1;
					color: @xf-nodeIconUnreadColor;
					text-shadow: 1px 1px 0.5px fade(@xf-nlBoxShadowColor, (@xf-nlBoxShadowAlpha * 100));
					.xf-nlNodeIconUnread();
				}
			}
		}
	}
}

.node-main
{
	padding: @xf-nlNodePaddingV @xf-nlNodePaddingH;
	width: 100%;
	.xf-nlNodeMainBlock(); 
}
.node-stats
{
	padding: @xf-nlNodePaddingV 0;
	.xf-nlNodeStatsBlock();

	> dl.pairs.pairs--rows
	{
		.xf-nlNodeStatsLabelPair();
	}
	&.node-stats--iconify > dl.pairs dt {
		display: inline-block;
		width: 1em;
		padding-right: .3em;
		text-decoration: none;
		color: inherit;
		color: @xf-nlStatsSubforumsIconColor;
		/* text-shadow: 1px 1px 0 fade(@xf-nlBoxShadowColor, (@xf-nlBoxShadowAlpha * 100)); */
	}
}
.node-extra a:hover,
.node-extra-user a.username:hover,
.structItem-title a:hover {
	color: @xf-linkHoverColor;
}
.node-extra
{
	width: @xf-nlNodelastPostBlockWidth;
	padding: @xf-nlNodePaddingV @xf-nlNodePaddingH;
	.xf-nlNodeLastPost();
	.m-clearFix();

	.node-extra-inner {
		.xf-nlNodeLastPostInner();
	}
}
.node-extra-row .node-extra-date {
	color: inherit;
}
.node-extra-date {
}
.node-extra .node-extra-row .listInline--bullet {
    .m-overflowEllipsis();
}

a.node-extra-title {
	color: @xf-nlNodeLastPostTitleColor;
	.xf-nlNodeLastPostTitle();
}
.node-extra-user a.username {
	color: @xf-nlNodeLastPostAuthorColor;
	.xf-nlNodeLastPostAuthor();
}

h3.node-title
{
	<xf:if is="property('nlNodeTitleOverflow') =='ellipsis'">
	.m-overflowEllipsis();
	</xf:if>
	color: @xf-nlNodeTitleColor;
	.xf-nlNodeTitle();

	a {
		color: inherit;
	}
	a:hover {
		.xf-nlNodeTitleHover();
	}
	.node--unread &
	{
		/* font-weight: @xf-fontWeightHeavy; */
	}
}

.node-statsMeta
{
	i {
		color: @xf-nlStatsSubforumsIconColor;
	}
}

@media (max-width: @xf-responsiveMedium)
{
.node-extra
	{
		.xf-nlNodeLastPostResponsive();
	}
}

.subNodeLink
{
	&:before
	{
		color: @xf-nlStatsSubforumsIconColor;
		/* text-shadow: 1px 1px 0 @xf-nlBoxShadowColor; */
	}
	&.subNodeLink--unread
	{
		&:before
		{
			/* text-shadow: 1px 1px 0 @xf-nlBoxShadowColor; */
		}
	}
	/* Deprecate
	&.subNodeLink--forum:before,
	&.subNodeLink--category:before
	{
		.m-faContent(@fa-var-folder);
	}
	*/
}

.nodeList .block-body > .node:last-of-type .node-body {
    margin-bottom: 0;
}
.nodeList {
	width: 100%;
	.xf-nlNodeListWrapper();

	.block.block--nodes {
		.xf-nlNodeGroupContainer();
	}

	.block.block--nodes .block-container {
		.xf-nlNodeCategoryContainer();
	}
	.block.block--nodes .block-body {
		.xf-nlNodeCategoryListContainer();

		& > .node:last-of-type .node-body {
			margin-bottom: 0;
		}
	}
	.block.block--nodes h2.block-header {
		margin: 0;
		padding: 0;
		.xf-nlCategoryStrip();

		a {
			.xf-nlCategoryStripTitle();
		}
		a:hover {
			.xf-nlCategoryStripTitleHover();
		}
		.block-desc {
			.xf-nlCategoryStripDescription();
		}
		+ .block-desc {
			.xf-nlCategoryDescSeparate();
		}
	}
}
.node-description {
	margin: (@xf-paddingSmall / 2) 0;
	.xf-nlNodeDescription();
}
/* Hard set line height, gives tighter appearance. Reconsider for later */
.node-description, .node-extra-row, .node-title, .structItem-cell {
    .m-lineHeightDefault();
}
.subNodeLink {
	color: inherit;
}

/* Replicate popup menus */
.menu .subNodeMenu
{
	.subNodeLink
	{
		.xf-menuLinkRow();
		.xf-menuLinkRowExtended();

		&:hover {
			.xf-menuLinkRowSelected();
		}
	}
}

.hideIcon .node-icon {
	display: none !important;
}
.hideStatsBlock .node-stats {
	display: none !important;
}
.hideLastPost .node-extra {
	display: none !important;
}
.node-iconStats .pairs.pairs--inline {
	margin-right: 10px;

	> dt:after {
		display: none;
	}
}
.node-main .node-stats {

	font-size: @xf-fontSizeSmall;
	color: @xf-textColorDimmed;

	padding: 6px 0;
	flex: none;
	text-align:  left;
	background: transparent none;
	display: block;
	width: 100%;

	dl.pairs > *,
	dl.pairs {
		display: inline-block !important;
		margin-right: 2px;
	}
	&.node-stats--iconify .pairs > dt:after {
		content: "";
	}
	&.node-stats--iconify .pairs > dd {
		display: inline-block;
	}
}
.node-body .node-stats.node-stats--iconify {

	> dl.pairs dt {
		width: auto;
	}
	.pairs.pairs--rows > dd {
		display: inline;
	}
}
.nodeStats-belowDesc .node-statsMeta {
    display: inline-block;
}

/* Layout */

.collapseNodes {

}
.gridNodes.separateNodes {
	.block--category .block-container,
	> .block-container,
	.block-container--subforums {
		.m-stripElement();
	}
}

/* Node grid */

@itemWidth: (100% / @xf-nlNodeGridNodePerRow);
@itemSpacing: @xf-nlGridNodeSpacing;
@itemSpacingOuter: (@itemSpacing / 2);

#nodeList.gridNodes,
#subForumsList.gridSubForums {
    .block--nodes .block-body {
        display: flex !important;
		flex-direction: row;
        flex-wrap: wrap;
        margin: @itemSpacingOuter -@itemSpacingOuter -@itemSpacingOuter;
        background: transparent none;
        box-shadow: none;
        border: none;
    }
	.block--nodes .block-body:first-child {
        margin-top: 0;
    }
    .node {
		flex: auto;
		margin: @itemSpacingOuter;
		width: ~"calc(@{itemWidth} - @{itemSpacing})";
		min-width: @xf-nlNodeGridNodeMinWidth;
    }
	&.fixedNodes .node {
		max-width: @xf-nlNodeGridNodeMaxWidth;
	}
	.node.node--placeholder {
		margin-top: 0;
		margin-bottom: 0;
		height: 0;
		border: none;
		box-shadow: none;
	}
    .node-body {
        display: flex;
        flex-flow: row wrap;
        height: 100%;
        table-layout: unset;
        position: relative;
        .xf-nlGridNode();

		.collapseNodes& {
			border-radius: 0 !important;
		}
        > * {
            display: block;
            flex: 1;
        }
        .node-icon,
		.no-icon { // cv6 nodes
			padding: @xf-nlGridNodePaddingV 0 @xf-nlGridNodePaddingV @xf-nlGridNodePaddingH;
            flex: 0 1 @xf-nlNodeIconBlockWidth;
            .xf-nlGridNodeIconBlock();
        }
        .node-main {
			padding: @xf-nlGridNodePaddingV @xf-nlGridNodePaddingH;
            .xf-nlGridNodeMainBlock();
        }
        h3.node-title a {
            <xf:if is="property('nlImgNodeTitleOverflow') =='ellipsis'">
			.m-overflowEllipsis();
            </xf:if>;
        }
        .node-stats {
            flex: 1 0 100%;
            clear: both;
            width: auto;
			padding: @xf-nlGridNodePaddingV 0;
            .xf-nlGridNodeStatsBlock();
        }
        .node-extra {
            flex: 1 0 100%;
            clear: both;
            min-width: 0;
			//width: auto;
			padding: @xf-nlGridNodePaddingV @xf-nlGridNodePaddingH;
            .xf-nlGridNodeLastPost();
        }
    }
	 > .block-container .block-body {
        margin-top: 0;
    }

	// Border radius
	&.separateNodes.imgNodes.nodeImgAbove {
		.node {
			border-radius: @xf-nlGridNode--border-radius;
			overflow: hidden;
		}
		.node-body {
			border-top-left-radius: 0;
			border-top-right-radius: 0;
		}
	}
}

@media (min-width: @xf-nlNodeGridMinWidth) {
	#nodeList.gridNodes,
	#subForumsList.gridSubForums {

		// Item widths
		&.cols-flex {
			.node {
				flex: 1;
			}
		}
		&.items-per-row-2 {
			.node {
				width: ~"calc(50% - @{itemSpacing})";
			}
		}
		&.items-per-row-3 {
			.node {
				width: ~"calc(33.33% - @{itemSpacing})";
			}
		}
		&.items-per-row-4 {
			.node {
				width: ~"calc(25% - @{itemSpacing})";
			}
		}
		&.items-per-row-5 {
			.node {
				width: ~"calc(20% - @{itemSpacing})";
			}
		}
		&.items-per-row-6 {
			.node {
				width: ~"calc(16.667% - @{itemSpacing})";
			}
		}
		&.items-per-row-7 {
			.node {
				width: ~"calc(14.285% - @{itemSpacing})";
			}
		}
		&.items-per-row-8 {
			.node {
				width: ~"calc(12.5% - @{itemSpacing})";
			}
		}
	}
}
@media (max-width: @xf-nlNodeGridMinWidth) {
	@_nodeSpacingResponsive: (@xf-nlGridNodeSpacing / 2);

	#nodeList.gridNodes,
	#subForumsList.gridSubForums {
		.block--nodes .block-body {
			margin: 0;
		}
		.node {
			flex: 1 1 100%;
			margin: 0 auto @_nodeSpacingResponsive;
			min-width: auto;
			max-width: none;
		}
		.node:nth-of-type(1) {
			margin-top: @_nodeSpacingResponsive;
		}
		.block-container > .block-body:only-child {
			margin-top: 0;
		}
		.node:last-of-type {
			margin-bottom: 0;
		}
	}
}

/* Image nodes */

#nodeList.imgNodes,
#subForumsList.imgNodes {
	.nodeImgPreview {
		position: relative;
		background-repeat: no-repeat;
		background-position: @xf-nlImgNodeBgOrigin;
		background-size: cover;

		&.has-overlay:before {
			content: " ";
			display: inline-block;
			position: absolute;
			width: 100%;
			height: 100%;
			left: 0;
			top: 0;
			right: 0;
			bottom: 0;
			transition: .3s all;
			opacity: 1;
			.xf-nlImgNodeOverlay();
		}
		&.has-overlay > * {
			position: relative;
		}
	}
	&.nodeImgAbove .nodeImgPreview.has-overlay:before {
		.xf-nlImgNodeOverlayAbove();
	}
	&.nodeImgAbove .node:hover .nodeImgPreview.has-overlay:before {
		.xf-nlImgNodeOverlayAboveHover();
	}
	&.nodeImgBehind .nodeImgPreview.has-overlay:before {
		.xf-nlImgNodeOverlayBehind();
	}
	&.nodeImgBehind .node:hover .nodeImgPreview.has-overlay:before {
		.xf-nlImgNodeOverlayBehindHover();
	}
	&.nodeImgBehind {
		h3.node-title {
			.xf-nlImgNodeTitle();

			a {
				color: inherit;
			}
		}
		.node-main a, .node-extra a, .node-stats a {
			.xf-nlImgNodeLink();
		}
		.node-icon {
			.xf-nlImgNodeIconBlock();

			i {
				// .xf-nlImgNodeIconWrapper();

				&:before {
					.xf-nlImgNodeIcon();
				}
			}
		}
		.node--unread .node-icon i:before {
			.xf-nlImgNodeIconUnread();
		}
		.node-main {
			.xf-nlImgNodeMainBlock();

			.pairs > dt, .node-description, .subNodeLink:before, i {
				color: inherit;
			}
		}
		.node-stats {
			.xf-nlImgNodeStatsBlock();

			.pairs > dt, dl.pairs, dl.pairs i {
				color: inherit;
			}
		}
		.node-extra {
			.xf-nlImgNodeLastPost();

			.node-extra-row {
				color: @xf-nlImgNodeLastPost--color;
			}
		}
	}
	&.nodeImgAbove {
		.node {
			display: flex;
			flex-flow: column wrap;
		}
		.nodeImgPreview {
			min-height: @xf-nlNodeImgMinHeight;
			z-index: 50;
			display: block;
		}
		.node-body {
			flex: 1;
		}
	}
}
#subForumsList:not(.gridSubForums).imgNodes.nodeImgAbove .nodeImgPreview {
	display: none !important;
}

<xf:if is="property('nlUseImgNodes')">
{{ include('nl_node_backgrounds.less') }}
</xf:if>

/* Responsive styling */

@media (max-width: @xf-responsiveMedium)
{
	#nodeList.gridNodes .node-extra {
		width: 280px;
	}
	#nodeList.imgNodes,
	#subForumsList.imgNodes {
		&.nodeImgBehind .node-body {
			table-layout: auto;
		}
	}
}

.p-page-header,
.headerFixed .p-page-header {
	position: relative;
	width: 100%;
	margin: auto;
	z-index: @zIndex-1;
	overflow: hidden;
	.xf-nlPageHeader();
}

.p-page-header {
	.p-page-header-inner {
		position: relative;
		max-width: @xf-pageWidthMax;
		width: 100%;
		margin: auto;
		display: flex;
		flex-direction: row;
		flex-wrap: wrap;
		align-items: center;
		z-index: @zIndex-3;
	}
	.p-title {
		flex-direction: column;
		align-items: flex-start;

		.u-muted {
			color: inherit;
			opacity: 0.8;
			font-weight: normal;
			font-size: 70%;
		}
	}
	.p-title-value {
		.xf-nlPageHeaderTitle();
	}
	.p-description {
		.xf-nlPageHeaderDescription();

		.p-description {
			margin: 0;
		}
	}
	.p-description a {
		.xf-nlPageHeaderLink();

		&.tagItem {
			color: inherit;
			background: transparent;
			border-color: @xf-nlPageHeader--color;
			border-color: @xf-nlPageHeaderDescription--color;
		}
	}
	.p-body-header.block-container {
		background: transparent none !important;
	}
	.p-page-header-inner > * {
		flex: 1;
		margin-bottom: 0;
	}
	.p-breadcrumbs,
	.p-breadcrumbs li {
		text-align: right;
		background: transparent none;
		border: none;
		box-shadow: none !important;
	}
	.p-breadcrumbs {
		flex: 1;
		display: block;
		color: inherit;

		> li, > li a {
			color: inherit;
			padding: 0;
		}
		> li {
			float: none;
			display: inline-block;
			vertical-align: top;
			.m-stripElement();

			&:hover {
				color: inherit;
				background: none;
			}
			a {
				position: relative;
			}
			&:after {
				color: inherit;
			}
		}

		> li a {
			.xf-nlPageHeaderBcrumbItem();

			&:hover {
				.xf-nlPageHeaderBcrumbItemHover();
			}
		}
		span.arrow {
			display: none;
		}
	}
	.contentRow {
		.xf-nlPageHeaderContentRow();
	}
	.porta-listInline-right {
		float: left;
		margin-left: @xf-paddingSmall;
	}
	.hide-pageMeta & .p-description ul {
		display: none;
	}
	.hide-pageDescription & .p-description .p-description {
		display: none;
	}
}
.p-page-header,
.headerFixed .p-page-header {
	background-position: center @xf-nlPageHeaderBgAttachment;
}
.p-page-header.parallax-window2 {
	background-image: none;
}

/* Introduce */

.inner-grid-3 {
	.porta-masonry .porta-article-item {
		width: ~"calc(100% / 3)";
	}
}
.inner-grid-4 {
	.porta-masonry .porta-article-item {
		width: 25%;
	}
}
.inner-grid-5 {
	.porta-masonry .porta-article-item {
		width: 20%;
	}
}
.inner-grid-6 {
	.porta-masonry .porta-article-item {
		width: ~"calc(100% / 6)";
	}
}
.color-dimmed {
	color: @xf-textColorDimmed;
}
.color-muted {
	color: @xf-textColorMuted;
}

/* General */

.p-body {
	h1, h2, h3, h4, h5 {
		&.h-300 {
			font-weight: 300;
		}
		&.h-400 {
			font-weight: 400;
		}
		&.h-700 {
			font-weight: 700;
		}
		&.h-800 {
			font-weight: 800;
		}
		&.h-900 {
			font-weight: 900;
		}
		&.h-dimmed {
			color: @xf-textColorDimmed;
		}
		&.h-muted {
			color: @xf-textColorMuted;
		}
		&.h-accented {
			position: relative;
		}
		&.h-large {
			font-size: 2.4em;
			line-height: normal;
		}
	}
}

/* Set ratings */

.generate-min-height(800);

.generate-min-height(@n, @i: 100) when (@i =< @n) {
  .min-height-@{i} {
    min-height: (1px * @i);
  }
  .generate-min-height(@n, (@i + 100));
}


/* Section rows */

.p-row {
	margin: 0 0 @xf-elementSpacer;
    clear: both;

	.m-clearFix();

	.generate-width(100);

	.generate-width(@n, @i: 20) when (@i =< @n) {
		.width-@{i} {
			width: (1% * @i);
			max-width: (1% * @i);
		}
		.generate-width(@n, (@i + 5));
	}

	&.spacer-s > *:not(.p-row-inner):not(:last-child), .p-xrow-inner > *:not(:last-child) {
		margin-bottom: 10px;
	}
	&.spacer-m > *:not(.p-row-inner):not(:last-child), .p-xrow-inner > *:not(:last-child) {
		margin-bottom: 20px;
	}
	&.spacer-l > *:not(.p-row-inner):not(:last-child), .p-xrow-inner > *:not(:last-child) {
		margin-bottom: 30px;
	}

	&.padding-s,
	.padding-s {
		padding: 10px 0;
	}
	&.padding-m,
	.padding-m {
		padding: 20px 0;
	}
	&.padding-l,
	.padding-l {
		padding: 30px 0;
	}

	.floatingContent &.wide {
		margin-left: -50vw;
		position: relative;
		left: 50%;
		width: 100vw;
		box-sizing: border-box;
		clear: both;
		/* z-index: 1; */
	}
	&.parallax-window {
		/* min-height: 300px; */
		background: transparent;
	}
	&.matte,
	.matte {
		background: #f5f5f5;
	}
	&.inline,
	.inline {
		margin-top: 0;
		margin-bottom: 0;
	}
	&.matte-dark,
	.matte-dark {
		background: #333;

		.block-container {
			border: none;
		}
	}
	&.dark *,
	.dark * {
		color: #fff;
	}
	&.img-bg {
		background-repeat: no-repeat;
		background-position: center center;
		background-size: cover;
	}
	&.img-align-top {
		background-position-y: top !important;
	}
	&.img-align-bottom {
		background-position-y: bottom !important;
	}
	&.img-align-left {
		background-position-x: left !important;
	}
	&.img-align-right {
		background-position-x: right !important;
	}
	&.f-v-stretch {

		/*
		.p-row-inner {
			flex: 1;
			display: flex;
			justify-content: center;
		}
		*/
	}
	&.f-align-right .p-row-inner {
		align-items: flex-end;
	}

	.float-caption {
		position: absolute;
		padding:  20px;
	}

	.float-caption.top-right {
		top: 0;
		right: 0;
	}

}
.p-row-inner {
		max-width: @xf-pageWidthMax;
		width: 100%;
		margin: auto;
		position: relative;
	}
.t-align-center {
	text-align: center;
}
.t-align-right {
	text-align: right;
}
.flex.f-v-stretch {
    align-items: center;
}
.f-v-stretch > * {

}
.inline-list,
.list-inline {
	padding: 0;
	margin: 0;
	list-style: none;
}

/* Flex layouts */

.flex {
    display: flex;
    flex-wrap: wrap;
    flex-direction: row;
}
.flex > * {
	flex: 1;

	@media (max-width: @xf-responsiveNarrow)
	{
		flex: 1 1 100% !important;
	}
}

.flex-dir-column {
    flex-direction: column;
    flex-wrap: wrap;
}

.col-has-gutter {

	&:not(.flex-dir-column) {
		margin-left: -(@xf-elementSpacer * .5);
		margin-right: -(@xf-elementSpacer * .5);

		> .flex-col {
			padding: 0 (@xf-elementSpacer * .5);
		}
	}
	.flex-dir-column& > .flex-col {
		padding: (@xf-elementSpacer * .5) 0;
	}
}
.col-has-gutter.gutter-s {

	&:not(.flex-dir-column) {
		margin-left: -(@xf-elementSpacer * .25);
		margin-right: -(@xf-elementSpacer * .25);

		> .flex-col {
			padding: 0 (@xf-elementSpacer * .25);
		}
	}
	.flex-dir-column& > .flex-col {
		padding: (@xf-elementSpacer * .25) 0;
	}
}
.col-has-gutter.gutter-m {

	&:not(.flex-dir-column) {
		margin-left: -(@xf-elementSpacer * .75);
		margin-right: -(@xf-elementSpacer * .75);

		> .flex-col {
			padding: 0 (@xf-elementSpacer * .75);
		}
	}
	.flex-dir-column& > .flex-col {
		padding: (@xf-elementSpacer * .75) 0;
	}
}
.col-has-gutter.gutter-l {

	&:not(.flex-dir-column) {
		margin-left: -@xf-elementSpacer;
		margin-right: -@xf-elementSpacer;

		> .flex-col {
			padding: 0 @xf-elementSpacer;
		}
	}
	.flex-dir-column& > .flex-col {
		padding: (@xf-elementSpacer) 0;
	}
}
.flex-dir-column > .flex-col:first-child {
    padding-top: 0 !important;
}
.flex-dir-column > .flex-col:last-child {
    padding-bottom: 0 !Important;
}

.col-1 {
    flex: 1 0 100%;
}
.col-2 {
    flex: 1 0 50%;
}
.col-3 {
	flex: 1 0 33%;
}
.col-4 {
	flex: 1 0 25%;
}
.col-5 {
	flex: 1 0 20%;
}
.col-6 {
	flex: 1 0 16%;
}

.flex .block {
    height: 100%;
    display: flex;
    margin-bottom: 0;
}
.flex .block-container {
	width: 100%;
}

/* Misc */

.img-preview img {
