/*=============================================
=            Pricing Tables                   =
=============================================*/

.pricing-tables {
    display: flex;
    flex-direction: row;
    flex-wrap: wrap;
	.m-clearFix();

	&.has--primary {

		&:before, &:after {
			width: 100%;
			height: @xf-elementSpacer;
		}
	}
}

.pricing-table {
    flex: 1;

	> * {
		/* flex: 1 !important; */
		/* align-items: center; */
		/* align-content: center; */
	}
}

.pricing-table {
    background: @xf-contentBg;
}

.p-table-header {
    background: @xf-element1;
    display: block;
    padding: 18px;
    text-align: center;
    text-transform: uppercase;
    font-weight: @xf-fontWeightHeavy;
    color: #fff;
    line-height: normal;
    font-size: 18px;
}
.p-table-description {
    display: block;
    font-size: @xf-fontSizeSmall;
    text-transform: initial;
    opacity: 0.7;
    font-weight: normal;
    margin-top: 6px;
}
.p-table-price {
    display: block;
    text-align: center;
    padding: 30px;
    font-size: 36px;
    font-weight: @xf-fontWeightHeavy;
    line-height: normal;
}
.p-table-header h3 {
    margin: 0;
}

/* Border setup */
.p-table-price,
.pricing-tables ul,
.p-table-footer {
	border-left: 1px solid @xf-borderColor;
    border-right: 1px solid @xf-borderColor;
}
.pricing-tables ul,
.p-table-footer {
	border-bottom: 1px solid @xf-borderColor;
}

.pricing-tables ul {
    list-style: none;
    margin: 0;
    padding: 0;
}

.pricing-table li {
    display: block;
    padding: 8px @xf-contentPadding;
    color: #888;
}

.pricing-table li:nth-of-type(odd) {
    background: rgba(0,0,0,0.02);
}

.p-table-footer {
    padding: @xf-contentPadding;
    text-align: center;
}

.pricing-table.primary {
    z-index: 99;
    margin: -@xf-contentPadding 0;
	.m-dropShadow();

	.p-table-header {
		padding: 25px @xf-contentPadding !important;
	}
	.p-table-footer {
		padding: 30px;
	}
}

