/*=============================================
=            Node collapse                    =
=============================================*/

.block--category.collapsible--nodes {

	.block-header {
		display: flex;
		position: relative;
		align-items: center;
	}
	.block-header--collapse-left {
		margin-right: auto;
		max-width: 100%;
	}
	.block-header--collapse-right {
		margin-left: auto;
		display: flex;
		align-items: center;
	}
	.collapseTrigger {
		margin: 0;
		position: relative;
		.xf-nlCategoryStripCollapseToggle();

		&:before {
			margin: 0;
			width: auto;
			.xf-nlCategoryStripCollapseToggleIcon();
        }
        &.is-active:before {
			.xf-nlCategoryStripCollapseToggleIconActive();
        }
    }
}

