/*=============================================
=            Compact header                   =
=============================================*/

@media (min-width: @xf-publicNavCollapseWidth)
{
	.compactHeader {
		.p-header {
			display: none;
		}
		// Apply nav styling to traditional element
		.p-navController:not(.p-navController--combined) {
			.p-nav {
				.xf-nlCompactHeaderNavStrip();
			}
			.p-navSticky.is-sticky .p-nav {
				.xf-nlCompactHeaderSticky();
			}
		}
		// Apply nav styling to the navController
		.p-navController.p-navController--combined {
			.xf-nlCompactHeaderNavStrip();

			&.p-navSticky.is-sticky {
				.xf-nlCompactHeaderSticky();
			}
		}
		.p-nav-inner {
			display: flex;
			flex-wrap: wrap;
			flex-direction: row;
			align-items: center;

			> * {
				flex: 0 0 auto;
			}
			.p-nav-scroller {
				flex: 1;
				text-align: right;
			}
		}
		.p-nav .p-nav-list .p-navEl,
		.p-nav .p-navgroup-link {
			.xf-nlCompactHeaderNavTab();

			&:hover:not(.is-selected):not(.is-menuOpen) {
				.xf-nlCompactHeaderNavTabHover();
			}
			&.is-selected {
				.xf-nlCompactHeaderNavTabSelected();
			}
			&.is-menuOpen {
				.xf-nlCompactHeaderNavTabMenuOpen();
			}
		}
		.p-nav-smallLogo {
			display: block;
			.xf-nlCompactLogo();
		}
		.p-sectionLinks {
			.xf-nlCompactHeaderSubNav();

			.p-sectionLinks-list .p-navEl {
				.xf-nlCompactHeaderSubNavLink();
			}
			.p-sectionLinks-list .p-navEl:hover {
				.xf-nlCompactHeaderSubNavLinkHover();
			}
		}
		// Sub-navigation
		&.compactHeader-subnav--center {
			.p-sectionLinks {
				.p-sectionLinks-list {
					text-align: center;
				}
			}
		}
		&.compactHeader-subnav--right {
			.p-sectionLinks {
				.p-sectionLinks-list {
					text-align: right;
				}
			}
		}
	}
}

