/* Dark background text adjust */

.floatingTextAdjust {
	.carousel-footer a,
	.p-body-content .p-body-header:not(.box-container) .p-title-value,
	.p-body-content .p-body-header:not(.box-container) .p-description
	<xf:if is="property('nlFloatingTextDarkClasses') != null">,
	{{ property('nlFloatingTextDarkClasses') }}</xf:if> {
		color: @xf-nlFloatingTextColor;
	}
}

/*=============================================
=            Hover transitions                =
=============================================*/

.hoverTransitions {
	// extend nlbase
	.p-header-topbar a,
	.hoverNodes .node-body,
	.structItem,
	ul.social_icons li a,
	.flex-direction-nav a:before,	
	.slick-prev:before, .slick-next:before,
	.flex-item ul.footer-list li a
	{
		transition: {{ property ('nlHoverTransitionSpeed') }}s all;
	}

	.hover-fx {
		position: relative;
		overflow: hidden;

		&.h-float-down, &.h-float-up {
			transition: {{ property ('nlHoverTransitionSpeed') }}s margin;
		}
		&.h-float-up:hover {
			margin-top: -10px;
			margin-bottom: 10px;
		}
		&.h-float-down:hover {
			margin-bottom: -10px;
			margin-top: 10px;
		}
		a& {
			display: block;
		}
		> img {
			display: block;
		}
	}
}

/* Circle */

.h-circle {
	position: relative;
}
.h-circle:before {
	position: absolute;
	top: 50%;
	left: 50%;
	z-index: 2;
	display: block;
	content: '';
	width: 0;
	height: 0;
	background: rgba(255,255,255,.2);
	border-radius: 100%;
	-webkit-transform: translate(-50%, -50%);
	transform: translate(-50%, -50%);
	opacity: 0;
}
.h-circle:hover:before {
	-webkit-animation: circle .75s;
	animation: circle .75s;
}
@-webkit-keyframes circle {
	0% {
		opacity: 1;
	}
	40% {
		opacity: 1;
	}
	100% {
		width: 200%;
		height: 200%;
		opacity: 0;
	}
}
@keyframes circle {
	0% {
		opacity: 1;
	}
	40% {
		opacity: 1;
	}
	100% {
		width: 200%;
		height: 200%;
		opacity: 0;
	}
}

/* Image zoom */

.hover-fx.h-img-zoom {
    position: relative;
    overflow: hidden;
}

.hover-fx.h-img-zoom > img {
    transition: .2s all;
    display: block;
}

.hover-fx.h-img-zoom:hover > img {
    transform: scale(1.1) rotate(1deg);
}

/*=============================================
=            Notices                          =
=============================================*/

.notice.has-icon {
	display: flex;
	flex-direction: row;
	flex-wrap: nowrap;

	.notice-icon,
	.notice-image {
		flex: 0 0 auto;
	}
	.notice-content {
		flex: 1;
