	}
	&.notice--primary .notice-icon {
		.xf-nlNoticePrimaryIconColumn();
	}
	&.notice--accent .notice-icon {
		.xf-nlNoticeAccentIconColumn();
	}
	&.notice--dark .notice-icon {
		.xf-nlNoticeDarkIconColumn();
	}
	&.notice--light .notice-icon {
		.xf-nlNoticeLightIconColumn();
	}
}
