	}
	> input[type="radio"] {
	  position: absolute;
	  left: -200vw;
	}
	> label {
	  position: relative;
	  padding: 14px;
	  border-bottom: 0;
	  cursor: pointer;
	  font-weight: 600;
	  float: left;
		.xf-nlBlockTabHeaderTab();
	}
	> label:hover,
	> input:focus + label,
	> input:checked + label {
		background: @xf-element1;
		color: @xf-element3;
	}
	.tab-panel {
	  display: none;
	}
	> input:first-child:checked ~ .panels > .tab-panel:first-child,
	> input:nth-child(3):checked ~ .panels > .tab-panel:nth-child(2),
	> input:nth-child(5):checked ~ .panels > .tab-panel:nth-child(3),
	> input:nth-child(7):checked ~ .panels > .tab-panel:nth-child(4),
	> input:nth-child(9):checked ~ .panels > .tab-panel:nth-child(5),
	> input:nth-child(11):checked ~ .panels > .tab-panel:nth-child(6) {
	  display: block;
	}
	.panels {
		clear: both;
	}
	.tab-panel {
	}
}

/* Ticker CSS */

// Base setup

.ticker_container {
    overflow: hidden;
    position: relative;
	-webkit-mask-image: linear-gradient(to right, transparent, #000 3%, #000 97%, transparent 100%);
	mask-image: linear-gradient(to right, transparent, #000 3%, #000 97%, transparent 100%);
}
.ticker_container * {
	box-sizing: unset;
}
.ticker_wrap {
  width: 100%;
  padding-left: 100%;
}
.ticker {
  display: inline-block;
  white-space: nowrap;
  padding-right: 100%;
}
.ticker.animate:hover {
    animation-play-state: paused;
}
.ticker_item {
	display: inline-block;
}
.ticker_item:after {
	content: "\f0da";
	font-family: 'Font Awesome 5 Pro';
	font-style: normal;
	font-weight: 900;
	text-rendering: auto;
	-webkit-font-smoothing: antialiased;
	display: inline-block;
	margin: 0 4px;
}
.ticker_item:last-child:after {
    display: none;
}

@-webkit-keyframes ticker {
  0% {
    -webkit-transform: translate3d(0, 0, 0);
    transform: translate3d(0, 0, 0);
    visibility: visible;
  }

  100% {
    -webkit-transform: translate3d(-100%, 0, 0);
    transform: translate3d(-100%, 0, 0);
  }
}

@keyframes ticker {
  0% {
    -webkit-transform: translate3d(0, 0, 0);
    transform: translate3d(0, 0, 0);
    visibility: visible;
  }

  100% {
    -webkit-transform: translate3d(-100%, 0, 0);
    transform: translate3d(-100%, 0, 0);
  }
}

.animate {
  -webkit-animation-iteration-count: infinite; 
          animation-iteration-count: infinite;
  -webkit-animation-timing-function: linear;
          animation-timing-function: linear;
 -webkit-animation-name: ticker;
         animation-name: ticker;
	-webkit-animation-duration: {{ property('nlCSSTickerSpeed') }};
          animation-duration: {{ property('nlCSSTickerSpeed') }};
}

// Top bar
.p-header-topbar {

	.ticker_container {
		.xf-nlTickerContainer();
	}
	.ticker_item {
		color: inherit;
		height: @xf-nlTopBarElementHeight;
		line-height: @xf-nlTopBarElementHeight;
		.xf-nlTickerItem();
	}
	.ticker_item:after {
		.xf-nlTickerItemSeparator();
	}
	.ticker_item a {
		.xf-nlTickerLink();
	}
}

// Body

@_tickerBodyHeight: 34px;
.p-body .block-ticker {

	.ticker_container {
		.xf-nlTickerContainerBody();
	}
	.block-row {
		display: flex;
	}
	.ticker-title--left {
		.block-row {
			flex-direction: row;
			align-items: center;
		}
		.ticker-title {
			flex: 0 0 auto;
		}
		h1, h2, h3, h4, h5, p {
			margin: 0;
		}
	}
	.ticker-title--above {
		.block-row {
			flex-direction: column;
		}
		h1, h2, h3, h4, h5, p {
			margin: 0 auto @xf-paddingMedium;
		}
	}
	.ticker-title {
		line-height: @_tickerBodyHeight;
		.xf-nlTickerTitle();
	}
	.ticker_item {
		height: @_tickerBodyHeight;
		line-height: @_tickerBodyHeight;
		.xf-nlTickerItemBody();
	}
	.ticker_item:after {
		.xf-nlTickerItemSeparatorBody();
	}
	.ticker_item a {
		.xf-nlTickerLinkBody();
	}
}

