@_topbarItemSpacer: 14px;

.p-header-topbar {
	position: relative;
	z-index: 200;
	line-height: @xf-nlTopBarElementHeight;
	.xf-nlTopBar();

	&:after {
		clear: both;
		display: block;
		width: 100%;
		content: " ";
	}

	.p-topBar-inner {
		display: flex;
		flex-direction: row;
		flex-wrap: wrap;
		.m-clearFix();

		> * {
			display: flex;
			align-items: center;
			.m-clearFix();
		}
	}

	ul, ol {
		margin: 0;
		padding: 0;
	}
	li {
		list-style: none;
		display: inline-block;
	}
	.p-topBar-left,
	.p-topBar-right {
		flex: 0 0 auto;
	}
	.p-topBar-left {
		padding-right: @_topbarItemSpacer;
		margin-right: auto;
	}
	.p-topBar-right {
		padding-left: @_topbarItemSpacer;
		margin-left: auto;
	}
	.p-topBar-center {
		flex: 1;
		overflow: hidden;
		min-width: 200px;
	}
	.p-topbar-group {
		display: inline-block;
		float: left;
		margin-right: @_topbarItemSpacer;
		.xf-nlTopbarGroup();

		&:last-child {
			margin-right: 0;
		}
		&.group--ticker {
			overflow: hidden;
		}
		&:not(.visitorLinks) > * {
			height: inherit;
			line-height: inherit;
			color: inherit;
			font-weight: inherit;
			.xf-nlTopbarItem();
		}
		a {
			height: inherit;
			line-height: inherit;
		}
		&:not(.visitorLinks) a {
			.xf-nlTopBarLinks();
		}
		&:not(.visitorLinks) a:hover {
			.xf-nlTopBarLinksHover();
		}
		&.group--html {
			li:not(:last-of-type) {
				margin-right: (@_topbarItemSpacer * .5);
			}
		}
	}

	@_topbarAvatarSizeWithLabel: (@xf-nlTopBarElementHeight - 8);
	.p-navgroup-link.p-navgroup-link--user .avatar {
		height: @_topbarAvatarSizeWithLabel;
		line-height: @_topbarAvatarSizeWithLabel;
		width: @_topbarAvatarSizeWithLabel;
	}
	.p-navgroup-link.badgeContainer:after {
		.xf-nlVisitorTabsTopbarBadge();
	}
}
.p-header-topbar .p-topbar-group.visitorLinks {
	.xf-nlVisitorTabsTopbarBlock();

	.p-nav-opposite {
		.m-clearFix();

		.p-navgroup-link {
			.xf-nlVisitorTabsTopbarTab();
		}
		.p-navgroup-link:hover {
			.xf-nlVisitorTabsTopbarTabHover();
		}
	}
	[data-logged-in="true"].hide-loggedVtabLabels & {
		.p-navgroup-link.p-navgroup-link--user {
			background: transparent none;
			border: none;
			margin-right: 4px;
			.xf-nlVisitorTabsTopbarAvatarTab();

			&:hover {
				.xf-nlVisitorTabsTopbarAvatarTabHover();
			}
			@_topbarAvatarSizeNoLabel: (@xf-nlTopBarElementHeight - 4);
			.avatar {
				height: @_topbarAvatarSizeNoLabel;
				line-height: @_topbarAvatarSizeNoLabel;
				width: @_topbarAvatarSizeNoLabel;
				margin: 2px 0;
			}
		}
	}
}

@_nodeList-statsCellBreakpoint: 1000px;

.node
{
	& + .node
	{
		border-top: @xf-borderSize solid @xf-borderColorFaint;
	}
}

.node-body
{
	display: table;
	table-layout: fixed;
	width: 100%;
}

.node-icon
{
	display: table-cell;
	vertical-align: middle;
	text-align: center;
	width: 46px;
	padding: @xf-paddingLarge 0 @xf-paddingLarge @xf-paddingLarge;

	i
	{
		display: block;
		line-height: 1.125;
		font-size: 32px;

		&:before
		{
			.m-faBase();

			color: @xf-nodeIconReadColor;

			.node--unread &
			{
				opacity: 1;
				color: @xf-nodeIconUnreadColor;
			}
		}

		.th_nodes .node--forum &:before,
		.th_nodes .node--category &:before
		{
			.m-faContent(@fa-var-comments);
		}

		.th_nodes .node--search &::before
		{
			.m-faContent(@fa-var-search);
		}
		.th_nodes .node--page &:before
		{
			.m-faContent(@fa-var-file-alt);
		}

		.th_nodes .node--link &:before
		{
			.m-faContent(@fa-var-link);
		}

		<xf:if is="property('nlUseImgNodeIcons') == 'default'">
		.node--forum &:before,
		.node--category &:before
		{
			.m-faContent(@fa-var-comments);
		}

		.node--search &::before
		{
			.m-faContent(@fa-var-search);
		}
		.node--page &:before
		{
			.m-faContent(@fa-var-file-alt);
		}

		.node--link &:before
		{
			.m-faContent(@fa-var-link);
		}
		</xf:if>
	}
}

.node-main
{
	display: table-cell;
	vertical-align: middle;
	padding: @xf-paddingLarge;
}

.node-stats
{
	display: table-cell;
	width: 140px;
	vertical-align: middle;
	text-align: center;
	padding: @xf-paddingLarge 0;

	> dl.pairs.pairs--rows
	{
		width: 50%;
		float: left;
		margin: 0;
		padding: 0 @xf-paddingMedium/2;

		&:first-child
		{
			padding-left: 0;
		}

		&:last-child
		{
			padding-right: 0;
		}
	}

	&.node-stats--single
	{
		width: 100px;

		> dl.pairs.pairs--rows
		{
			width: 100%;
			float: none;
		}
	}

	&.node-stats--triple
	{
		width: 240px;

		> dl.pairs.pairs--rows
		{
			width: 33.333%;
		}
	}

	@media (max-width: @_nodeList-statsCellBreakpoint)
	{
		display: none;
	}
}

@_nodeExtra-avatarSize: 36px;

.node-extra
{
	display: table-cell;
	vertical-align: middle;
	width: 280px;
	padding: @xf-paddingLarge;

	font-size: @xf-fontSizeSmall;
}

.node-extra-row
{
	.m-overflowEllipsis();
	color: @xf-textColorMuted;
}

.node-extra-icon
{
	padding-right: @xf-paddingMedium;
	float: left;

	.avatar
	{
		// .m-avatarSize(@_nodeExtra-avatarSize);
	}
}

.node-title
{
	margin: 0;
	padding: 0;
	font-size: @xf-fontSizeLarge;
	font-weight: @xf-fontWeightNormal;

	.node--unread &
	{
		font-weight: @xf-fontWeightHeavy;
	}
}

.node-description
{
	font-size: @xf-fontSizeSmall;
	color: @xf-textColorDimmed;

	&.node-description--tooltip
	{
		.has-js:not(.has-touchevents) &
		{
			display: none;
		}
	}
}

.node-meta
{
	font-size: @xf-fontSizeSmall;
}

.node-statsMeta
{
	display: none;

	@media (max-width: @_nodeList-statsCellBreakpoint)
	{
		display: inline;
	}
}

.node-bonus
{
	font-size: @xf-fontSizeSmall;
	color: @xf-textColorMuted;
	text-align: right;
}

.node-subNodesFlat
{
	font-size: @xf-fontSizeSmall;
	margin-top: .3em;

	.node-subNodesLabel
	{
		display: none;
	}
}

.node-subNodeMenu
{
	display: inline;

	.menuTrigger
	{
		color: @xf-textColorMuted;
	}
}

@media (max-width: @xf-responsiveMedium)
{
	.node-main
	{
		display: block;
		width: auto;

		.node--link &,
		.node--page &
		{
			// #168882: we only display the title for these types
			// so keep these as table-cells for vertical alignment
			display: table-cell;
		}
	}

	.node-extra
	{
		display: block;
		width: auto;
		// this gives an equivalent of medium padding between main and extra, with main still having large
		margin-top: (@xf-paddingMedium - @xf-paddingLarge);
		padding-top: 0;
	}

	.node-extra-row
	{
		display: inline-block;
		vertical-align: top;
		max-width: 100%;
	}

	.node-extra-icon
	{
		display: none;
	}

	.node-description,
	.node-stats,
	.node-subNodesFlat
	{
		display: none;
	}
}

@media (max-width: @xf-responsiveNarrow)
{
	.node-subNodeMenu
	{
		display: none;
	}
}

.subNodeLink
{
	&:before,
	.subNodeLink-icon
	{
		display: inline-block;
		width: 1.28571429em;
		margin-right: .3em;
		text-decoration: none;
		text-align: center;

		color: @xf-nodeIconReadColor;
	}

	&:before
	{
		.m-faBase();
	}

	&:hover:before
	{
		&:before,
		.subNodeLink-icon
		{
			text-decoration: none;
		}
	}

	&.subNodeLink--unread
	{
		font-weight: @xf-fontWeightHeavy;

		&:before,
		.subNodeLink-icon
		{
			color: @xf-nodeIconUnreadColor;
		}
	}

	&.subNodeLink--category:before
	{
		.m-faContent(@fa-var-comments);
	}

	&.subNodeLink--page:before
	{
		.m-faContent(@fa-var-file-alt);
	}

	&.subNodeLink--link:before
	{
		.m-faContent(@fa-var-link);
	}

	&.subNodeLink--search::before
	{
		.m-faContent(@fa-var-search);
	}
}

.node-subNodeFlatList
{
	.m-listPlain();
	.m-clearFix();

	> li
	{
		display: inline-block;
		margin-right: 1em;

		&:last-child
		{
			margin-right: 0;
		}
	}

	ol,
	ul,
	.node-subNodes
	{
		display: none;
	}
}

.subNodeMenu
{
	.m-listPlain();

	ol,
	ul
	{
		.m-listPlain();
	}

	.subNodeLink
	{
		display: block;
		padding: @xf-blockPaddingV @xf-blockPaddingH;
		text-decoration: none;
		cursor: pointer;

		&:hover
		{
			text-decoration: none;
			background: @xf-contentHighlightBg;
		}
	}

	li li .subNodeLink { padding-left: 1.5em; }
	li li li .subNodeLink { padding-left: 3em; }
	li li li li .subNodeLink { padding-left: 4.5em; }
	li li li li li .subNodeLink { padding-left: 6em; }
	li li li li li li .subNodeLink { padding-left: 7.5em; }
}

