		</xf:if>
	}
	.page-section-xfrm & {
		<xf:if is="property('nlBreadcrumbResourcesBot') == 'off'">
			.m-bcrumbHide();
		<xf:elseif is="property('nlBreadcrumbResourcesBot') == 'on'" />
			.m-bcrumbShow();
		</xf:if>
	}
	.page-section-EWRporta & {
		<xf:if is="property('nlBreadcrumbArticlesBot') == 'off'">
			.m-bcrumbHide();
		<xf:elseif is="property('nlBreadcrumbArticlesBot') == 'on'" />
			.m-bcrumbShow();
		</xf:if>
	}
	.page-section-dbtechEcommerce & {
		<xf:if is="property('nlBreadcrumbEcommerceBot') == 'off'">
			.m-bcrumbHide();
		<xf:elseif is="property('nlBreadcrumbEcommerceBot') == 'on'" />
			.m-bcrumbShow();
		</xf:if>
	}
	.page-section-siropuChat,
	.page-section-siropuShoutbox & {
		<xf:if is="property('nlBreadcrumbChatBot') == 'off'">
			.m-bcrumbHide();
		<xf:elseif is="property('nlBreadcrumbChatBot') == 'on'" />
			.m-bcrumbShow();
		</xf:if>
	}
}

// This should be used for additional LESS setup code (that does not output anything).
// setup.less customizations should be avoided when possible.

.m-dotControls()
{
	.xf-nlDotControl();
}
.m-dotControlsHover()
{
	.xf-nlDotControlHover();
}
.m-stripElement()
{
	background: transparent none !important;
	padding: 0;
	border: none !important;
	box-shadow: none !important;
}
.m-buttonReset()
{
    .m-stripElement();
    color: inherit;
    text-transform: capitalize;
    font-weight: normal;
    padding: 0;
    display: inline;
}
.m-lineHeight(@lineHeight: 1.4)
{
	line-height: @lineHeight;
}
.m-lineHeightNormal()
{
	line-height: normal;
}
.m-lineHeightDefault()
{
	line-height: 1.4;
}
.m-flexAlignCenter()
{
	display: flex;
	align-items: center;
}

.m-fullTriangleLeft(@color; @size; @offset: 50%) {
	position: relative;

	&:before {
		content: "";
		position: absolute;
		left: -@size;
		top: @offset;
		transform: translateY(-50%);
	}
	&:before {
		.m-triangleLeft(@color, @size)
	}
}
.m-fullTriangleUp(@color; @size; @offset: 50%) {
	position: relative;

	&:before {
		content: "";
		position: absolute;
		top: -@size;
		margin: 0 auto;
		left: @offset;
		transform: translateX(-50%);
	}
	&:before {
		.m-triangleUp(@color, @size)
	}
}
.m-fullTriangleRight(@color; @size; @offset: 50%) {
	position: relative;

	&:after {
		content: "";
		position: absolute;
		right: -@size;
		top: @offset;
		transform: translateY(-50%);
	}
	&:after {
		.m-triangleRight(@color, @size)
	}
}
.m-fullTriangleDown(@color; @size; @offset: 50%) {
	position: relative;

	&:before {
		content: "";
		position: absolute;
		bottom: -@size;
		margin: 0 auto;
		left: @offset;
		transform: translateX(-50%);
	}
	&:before {
		.m-triangleDown(@color, @size)
	}
}

.m-dropShadow(@x: @xf-nlBoxShadowX; @y: @xf-nlBoxShadowY; @blur: @xf-nlBoxShadowBlur; @spread: @xf-nlBoxShadowSpread; @alpha: @xf-nlBoxShadowAlpha)
{
	box-shadow: @x @y @blur @spread fade(@xf-nlBoxShadowColor, (@alpha * 100));
}

.m-popupDropShadow(@x: @xf-nlPopupBoxShadowX; @y: @xf-nlPopupBoxShadowY; @blur: @xf-nlPopupBoxShadowBlur; @spread: @xf-nlPopupBoxShadowSpread; @alpha: @xf-nlPopupBoxShadowAlpha)
{
	box-shadow: @x @y @blur @spread fade(@xf-nlPopupBoxShadowColor, (@alpha * 100));
}

.m-primaryGradient(@direction: to bottom; @startColor: @xf-gradientTop; @stopColor: @xf-gradientBottom;) {
	background: linear-gradient(@direction, @startColor, @stopColor);
}
.m-secondaryGradient(@direction: to bottom; @startColor: @xf-secondaryGradientTop; @stopColor: @xf-secondaryGradientBottom;) {
	background: linear-gradient(@direction, @startColor, @stopColor);
}
.m-lightGradient(@direction: to bottom; @startColor: @xf-lightGradientTop; @stopColor: @xf-lightGradientBottom;) {
	background: linear-gradient(@direction, @startColor, @stopColor);
}
.m-darkGradient(@direction: to bottom; @startColor: @xf-darkGradientTop; @stopColor: @xf-darkGradientBottom;) {
	background: linear-gradient(@direction, @startColor, @stopColor);
}

/* Palette Colors */

@_blend-mode: xf-intensify;
@_blend-amount: 10%; 

@_palette--blue: #0096de;
@_palette--indigo: #1f44d1;
@_palette--navy: #1f44d1;
@_palette--sky-blue: #43c2fb;
@_palette--aqua: #00BCD4;
@_palette--sea-green: #009688;
@_palette--forest: #0c790c;
@_palette--green: #62a51b;
@_palette--lime: #a9c516;
@_palette--yellow: #efd80f;
@_palette--saffron: #F4C430;
@_palette--orange: #ff9800;
@_palette--burnt-orange: #a25203;
@_palette--brown: #965d2a;
@_palette--red: #e00f00;
@_palette--magenta: #9e0621;
@_palette--brick: #795548;
@_palette--purple: #673AB7;
@_palette--pink: #e45683;
@_palette--neon-pink: #E91E63;
@_palette--pear: #CDDC39;
@_palette--coffee: #a96c36;
@_palette--slate: #607D8B;
@_palette--gray: #9E9E9E;
@_palette--blue-gray: #9E9E9E;
@_palette--teal: #00c9d4;
@_palette--teal-gray: #5c898c;
@_palette--silver: #9E9E9E;
@_palette--gold: #d6a921;
@_palette--charcoal: #464646;
@_palette--black: #1b1b1b;
@_palette--periwinkle: #637dbb;
@_palette--violet: #9C27B0;
@_palette--cherry-red: #ce0e00;
@_palette--plum: #893F62;
@_palette--navy: #1f78d1;
@_palette--yoga-green: #818E6D;

@_structItem-avatarSize: @xf-nlStructItemAvatarSize;
@_structItem-avatarSizeExpanded: @xf-nlStructItemAvatarSizeExpanded;
@_structItem-avatarSizeEnd: @avatar-xxs;
@_structItem-cellPaddingH: @xf-nlStructItemPaddingH;
@_structItem-cellPaddingV: @xf-nlStructItemPaddingV;
@_structItem-avatarVAlign: @xf-nlStructItemVerticalAlign;

@_structItemGrid-cellPaddingH: @xf-nlDiscussionGridCellPadding;
@_structItemGrid-cellPaddingV: @xf-nlDiscussionGridCellPadding;

.structItemContainer
{
	border-collapse: collapse;
	list-style: none;
	margin: 0;
	padding: 0;
	width: 100%;
	.xf-nlStructItemListContainer();

	.alternateRows & .structItem:not(form):hover,
	.alternateRows & .structItem-wrapper:nth-of-type(even) .structItem {
		.xf-nlStructItemAlternate();
	}
	.hoverRows & .structItem:not(form):hover,
	.hoverRows & .structItem-wrapper:nth-of-type(even) .structItem:hover {
		.xf-nlStructItemHover();
	}
}

.structItemContainer-group
{
}

.structItemContainer > .structItem:first-child,
.structItemContainer > .structItemContainer-group:first-child > .structItem:first-child
{
	border-top: none;
}

.structItem
{
	display: table;
	table-layout: fixed;
	border-collapse: collapse;
	list-style: none;
	margin: 0;
	padding: 0;
	width: 100%;
	.xf-nlStructItem();

	&.is-highlighted,
	&.is-moderated
	{
		background: @xf-contentHighlightBg !important;
	}

	&.is-deleted
	{
		opacity: .7;

		.structItem-title > *
		{
			text-decoration: line-through;
		}
	}

	&.is-mod-selected
	{
		background: @xf-inlineModHighlightColor !important;
		opacity: 1;
	}
}

.structItem-cell
{
	display: table-cell;
	vertical-align: @xf-nlStructItemVerticalAlign;
	padding: @_structItem-cellPaddingV @_structItem-cellPaddingH;
	.xf-nlStructItemCell();

	.structItem--middle &
	{
		vertical-align: middle;
	}

	&.structItem-cell--vote
	{
		width: (40px + (@_structItem-cellPaddingH) * 2);
	}

	&.structItem-cell--icon
	{

		width: ((@_structItem-avatarSize) + (@_structItem-cellPaddingH) * 2);
		position: relative;
		.xf-nlStructItemCellIcon();

		&.structItem-cell--iconExpanded
		{
			width: ((@_structItem-avatarSizeExpanded) + (@_structItem-cellPaddingH) * 2);
		}

		&.structItem-cell--iconEnd
		{
			width: ((@_structItem-avatarSizeEnd) + (@_structItem-cellPaddingH) + (@_structItem-cellPaddingH / 2));
			padding-left: @_structItem-cellPaddingH / 2;
			.xf-nlStructItemCellIconEnd();

			.structItem-iconContainer
			{
				& when (@_structItem-avatarVAlign = top) {
					padding-top: @xf-paddingSmall;
				}
			}
		}

		&.structItem-cell--iconFixedSmall
		{
			width: (60px + (@_structItem-cellPaddingH) * 2);
		}

		&.structItem-cell--iconFixedSmallest
		{
			width: ((@_structItem-avatarSizeEnd) + (@_structItem-cellPaddingH) * 2);
		}

		.solutionIcon
		{
			padding-left: 0;
			padding-right: 0;
		}
	}
	&.structItem-cell--main
	{
		.xf-nlStructItemCellMain();
	}
	&.structItem-cell--meta
	{
		width: 135px;
		.xf-nlStructItemCellMeta();
	}

	&.structItem-cell--latest
	{
		width: 190px;
		text-align: right;
		width: @xf-nlStructItemLastPostCellWidth;
		.xf-nlStructItemCellLatest();
	}
}

.structItem-iconContainer
{
	position: relative;

	img
	{
		display: block;
		width: 100%;
	}

	.avatar
	{
		.m-avatarSize(@_structItem-avatarSize);

		&.avatar--xxs
		{
			.m-avatarSize(@_structItem-avatarSizeEnd);
		}
	}

	.structItem-secondaryIcon
	{
		position: absolute;
		right: -5px;
		bottom: -5px;

		.m-avatarSize(@_structItem-avatarSize / 2  + 2px);
	}

	.structItem-cell--iconExpanded &
	{
		.avatar
		{
			.m-avatarSize(@_structItem-avatarSizeExpanded);
		}

		.structItem-secondaryIcon
		{
			.m-avatarSize(@_structItem-avatarSizeExpanded / 2 - 2px);
		}
	}
}

.structItem-title
{
	font-size: @xf-fontSizeLarge;
	font-weight: @xf-fontWeightNormal;
	margin: 0;
	padding: 0;
	.xf-nlStructItemTitle();

	a {
		color: inherit;
	}

	.label
	{
		font-weight: @xf-fontWeightNormal;
	}

	.is-unread &
	{
		//font-weight: @xf-fontWeightHeavy;
		.xf-nlStructItemTitleUnread();
	}
}

.structItem-minor
{
	font-size: @xf-fontSizeSmaller;
	color: @xf-textColorMuted;

	.m-hiddenLinks();
}

.structItem-parts
{
	.m-listPlain();
	display: inline;

	> li
	{
		display: inline;
		margin: 0;
		padding: 0;

		&:nth-child(even)
		{
			color: @xf-textColorDimmed;
		}

		&:before
		{
			content: "\00B7\20";
		}

		&:first-child:before
		{
			content: "";
			display: none;
		}
	}
}

.structItem-pageJump
{
	margin-left: 8px;
	font-size: @xf-fontSizeSmallest;

	a
	{
		.xf-chip();
		text-decoration: none;
		border-radius: @xf-borderRadiusSmall;
		padding: 0 3px;
		opacity: .5;
		.m-transition();

		.structItem:hover &,
		.has-touchevents &
		{
			opacity: 1;
		}

		&:hover
		{
			text-decoration: none;
			.xf-chipHover();
		}
	}
}

.structItem-statuses,
.structItem-extraInfo
{
	.m-listPlain();
	float: right;

	> li
	{
		float: left;
		margin-left: 8px;
	}

	input[type=checkbox]
	{
		.m-checkboxAligner();
	}
}

.structItem-statuses .reactionSummary
{
	vertical-align: -2px;
}

.structItem-extraInfo .reactionSummary
{
	vertical-align: middle;
}

.structItem-status
{
	&::before
	{
		.m-faBase();
		display: inline-block;
		font-size: 90%;
		color: @xf-textColorMuted;
	}

	&--deleted::before { .m-faContent(@fa-var-trash-alt, .875em); }
	&--locked::before { .m-faContent(@fa-var-lock, .875em); }
	&--moderated::before { .m-faContent(@fa-var-shield, 1em); color: @xf-textColorAttention; }
	&--redirect::before { .m-faContent(@fa-var-external-link, 1em); }
	&--starred::before { .m-faContent(@fa-var-star, 1.125em); color: @xf-starFullColor; }
	&--sticky::before { .m-faContent(@fa-var-thumbtack, .75em); }
	&--watched::before { .m-faContent(@fa-var-bell, .875em); }

	&--solved::before { .m-faContent(@fa-var-check-circle, 1em); color: @xf-votePositiveColor; }
	&--attention::before { .m-faContent(@fa-var-bullhorn, 1.125em); color: @xf-textColorAttention; }
	&--upvoted::before { .m-faContent(@fa-var-thumbs-up, 1em); }
	&--downvoted::before { .m-faContent(@fa-var-thumbs-down, 1em); }
}

.structItem.structItem--note
{
	.xf-contentBase();

	.structItem-cell
	{
		padding-top: @_structItem-cellPaddingV / 2;
		padding-bottom: @_structItem-cellPaddingV / 2;
		font-size: @xf-fontSizeSmaller;
		text-align: center;
	}
}

@media (max-width: @xf-responsiveWide)
{
	.structItem-cell
	{
		vertical-align: top;

		&.structItem-cell--meta
		{
			width: 115px;
			font-size: @xf-fontSizeSmaller;
		}

		&.structItem-cell--latest
		{
			width: 140px;
			font-size: @xf-fontSizeSmaller;
		}
	}
}

@media (max-width: @xf-responsiveMedium)
{
	.structItem-cell
	{
		padding: (@_structItem-cellPaddingV) / 2 @_structItem-cellPaddingH;
		background: transparent none !important;

		&.structItem-cell--icon
		{
			.structItem-cell + &
			{
				padding-left: 0;
				width: ((@_structItem-avatarSize) + (@_structItem-cellPaddingH));
			}
		}

		&.structItem-cell--main,
		&.structItem-cell--newThread
		{
			display: block;
			padding-bottom: .2em;

			.structItem-cell + &
			{
				padding-left: 0;
			}
		}

		&.structItem-cell--meta
		{
			display: block;
			width: auto;
			float: left;
			padding-top: 0;
			padding-left: 0;
			padding-right: 0;
			color: @xf-textColorMuted;

			.structItem-minor
			{
				display: none;
			}

			.pairs
			{
				> dt,
				> dd
				{
					display: inline;
					float: none;
					margin: 0;
				}
			}
		}

		&.structItem-cell--latest
		{
			display: block;
			width: auto;
			float: left;
			padding-top: 0;
			padding-left: 0;

			&:before
			{
				content: "\00A0\00B7\20";
				color: @xf-textColorMuted;
			}

			a
			{
				color: @xf-textColorMuted;
			}

			.structItem-minor
			{
				display: none;
			}
		}

		&.structItem-cell--iconEnd
		{
			display: none;
		}
	}

	.structItem-pageJump,
	.structItem-extraInfoMinor
	{
		display: none;
	}

	.is-unread .structItem-latestDate
	{
		font-weight: @xf-fontWeightNormal;
	}
}

@media (max-width: @xf-responsiveNarrow)
{
	.structItem-parts
	{
		.structItem-startDate
		{
			display: none;
		}
	}

	.structItem.structItem--quickCreate
	{
		.structItem-cell--icon,
		.structItem-cell--vote
		{
			display: none;
		}

		.structItem-cell--newThread
		{
			padding-left: @_structItem-cellPaddingH;
			padding-bottom: @_structItem-cellPaddingH;
		}
	}
}

